import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import type EnhancedThreeViewer from '@/platforms/dt-robot/lib/EnhancedThreeViewer';

interface Props {
    viewer: EnhancedThreeViewer | null;
    initialOptions?: any;
}

const LightControlPanel: React.FC<Props> = ({ viewer, initialOptions }) => {
    const { t } = useTranslation('dt-robot');
    const [isCollapsed, setIsCollapsed] = useState(true);
    const [light, setLight] = useState({
        isOn: true,
        intensity: 1.5,
        color: '#ffffff',
        position: { x: 10, y: 10, z: 10 }
    });

    useEffect(() => {
        if (initialOptions) {
            setLight(prev => ({
                ...prev,
                ...initialOptions,
                position: initialOptions.position ? { ...initialOptions.position } : prev.position
            }));
        }
    }, [initialOptions]);

    const handleUpdate = (updates: any) => {
        const next = { ...light, ...updates };
        setLight(next);

        if (viewer) {
            if (updates.intensity !== undefined) {
                viewer.setDirectionalLightIntensity(next.isOn ? updates.intensity : 0);
            }
            if (updates.color !== undefined) {
                viewer.setDirectionalLightColor(updates.color);
            }
            if (updates.position !== undefined) {
                viewer.setDirectionalLightPosition({ x: next.position.x, y: next.position.y, z: next.position.z });
            }
        }
    };

    const togglePower = () => {
        const nextIsOn = !light.isOn;
        handleUpdate({ isOn: nextIsOn, intensity: nextIsOn ? 1.5 : 0 });
    };

    const reset = () => {
        const defaultLight = {
            isOn: true,
            intensity: 1.5,
            color: '#ffffff',
            position: { x: 10, y: 10, z: 10 }
        };
        handleUpdate(defaultLight);
    };

    return (
        <div className="control-section">
            <div className="section-title" onClick={() => setIsCollapsed(!isCollapsed)}>
                <span>{t('panels.light.title')}</span>
                <span>{isCollapsed ? '▼' : '▲'}</span>
            </div>

            {!isCollapsed && (
                <div className="control-body">
                    <div className="control-item">
                        <label className="control-label">{t('panels.light.power_brightness')}</label>
                        <div className="control-row">
                            <input
                                type="checkbox"
                                checked={light.isOn}
                                onChange={togglePower}
                                className="dt-switch"
                            />
                            <input
                                type="range"
                                min="0" max="5" step="0.1"
                                value={light.intensity}
                                onChange={(e) => handleUpdate({ intensity: parseFloat(e.target.value) })}
                                className="dt-slider"
                                disabled={!light.isOn}
                            />
                            <span style={{ fontSize: 12, minWidth: 25 }}>{light.intensity}</span>
                        </div>
                    </div>

                    <div className="control-item">
                        <label className="control-label">{t('panels.light.color')}</label>
                        <div className="control-row">
                            <input
                                type="color"
                                value={light.color}
                                onChange={(e) => handleUpdate({ color: e.target.value })}
                                className="dt-input"
                                style={{ height: 30, padding: 2, cursor: 'pointer' }}
                            />
                            <input
                                type="text"
                                value={light.color}
                                onChange={(e) => handleUpdate({ color: e.target.value })}
                                className="dt-input"
                                style={{ width: 80 }}
                            />
                        </div>
                    </div>

                    <div className="control-item">
                        <label className="control-label">{t('panels.light.position')}</label>
                        <div className="control-row">
                            <input
                                type="number"
                                value={light.position.x}
                                onChange={(e) => handleUpdate({ position: { ...light.position, x: parseFloat(e.target.value) } })}
                                className="dt-input"
                            />
                            <input
                                type="number"
                                value={light.position.y}
                                onChange={(e) => handleUpdate({ position: { ...light.position, y: parseFloat(e.target.value) } })}
                                className="dt-input"
                            />
                            <input
                                type="number"
                                value={light.position.z}
                                onChange={(e) => handleUpdate({ position: { ...light.position, z: parseFloat(e.target.value) } })}
                                className="dt-input"
                            />
                        </div>
                    </div>

                    <button onClick={reset} className="reset-btn">{t('panels.light.reset')}</button>
                </div>
            )}

            {isCollapsed && <div className="status-info">{t('panels.light.description')}</div>}
        </div>
    );
};

export default LightControlPanel;
