import { CSS2DRenderer, CSS2DObject } from 'three/examples/jsm/renderers/CSS2DRenderer.js'
import Stats from 'stats.js'

export default class FpsLabelManager {
  constructor(container, scene, camera) {
    // FpsLabelManager 생성자: 컨테이너, 씬, 카메라를 초기화하고 FPS 라벨과 렌더러를 설정합니다.
    this.container = document.createElement('div')
    container.appendChild(this.container)
    //this.container = container
    this.scene = scene
    this.camera = camera
    this.fpsLabel = null
    this.lastFpsLogTime = 0
    this.curFps = 0
    this.isStat = false // Stats.js 사용 여부
    this.fpsHistory = [] // FPS 이력 저장용 배열

    // this._setupLabelRenderer() // 라벨 렌더러 설정
    this._createFpsLabel(container) // FPS 라벨 생성 (직접 컨테이너에 부착)

    if (this.isStat) {
      this.stats = new Stats()
      this.stats.showPanel(0) // FPS 패널 활성화
      if (document && this.stats.dom) document.body.appendChild(this.stats.dom)
    }

    window.addEventListener('resize', this._onWindowResize.bind(this)) // 윈도우 리사이즈 이벤트 리스너 추가
  }

  history() {
    return this.fpsHistory
  }

  _setupLabelRenderer() {
    // 라벨 렌더러를 초기화하고 컨테이너에 추가합니다.
    this.labelRenderer = new CSS2DRenderer()
    this.labelRenderer.setSize(this.container.clientWidth, this.container.clientHeight)
    this.labelRenderer.domElement.style.position = 'absolute'
    this.labelRenderer.domElement.style.top = '0px'
    this.labelRenderer.domElement.style.pointerEvents = 'none'
    this.container.appendChild(this.labelRenderer.domElement)
  }

  _createFpsLabel(container) {
    // FPS 라벨을 생성하고 씬에 추가합니다.
    const element = document.createElement('div')
    element.className = 'fps-label' // 스타일링을 위한 클래스 이름 설정
    element.style.color = 'white' // 텍스트 색상 설정
    element.style.backgroundColor = 'rgba(0, 0, 0, 0.5)' // 반투명 검정 배경 설정
    element.style.padding = '5px' // 텍스트 주변 여백 설정
    element.style.borderRadius = '5px' // 라벨 모서리 둥글게 설정
    element.style.fontFamily = "'Pretendard', sans-serif" // 폰트 설정
    element.style.fontSize = '14px' // 폰트 크기 설정
    element.style.position = 'absolute' // 절대 위치 설정
    element.style.top = '20px' // 상단 버튼 그룹(top: 20px)과 정확히 일치
    element.style.right = '220px' // 미니맵 버튼(right: 170px) 바로 왼쪽에 배치
    element.style.height = '40px' // 버튼들과 높이 동기화
    element.style.display = 'flex' // 내부 요소 정렬용
    element.style.alignItems = 'center'
    element.style.zIndex = '1001' // 패널(1000)보다 우선순위
    element.style.pointerEvents = 'auto'
    element.style.border = '1px solid rgba(255, 255, 255, 0.1)' // 세련된 테두리
    element.style.boxShadow = '0 4px 12px rgba(0, 0, 0, 0.3)' // 그림자 효과
    // FPS 라벨의 div에 pointer-events: auto 적용
    // FPS 텍스트 span
    const fpsText = document.createElement('span')
    fpsText.textContent = 'FPS: 0'
    fpsText.style.marginRight = '10px'
    element.appendChild(fpsText)
    // 버튼 추가
    const btn = document.createElement('button')
    btn.textContent = '📑이력'
    btn.style.fontSize = '16px'
    btn.style.marginLeft = '4px'
    btn.style.padding = '2px 8px'
    btn.style.borderRadius = '4px'
    btn.style.border = 'none'
    btn.style.background = '#222'
    btn.style.color = 'white'
    btn.style.cursor = 'pointer'
    btn.style.pointerEvents = 'auto'
    btn.style.position = 'relative' // 이벤트 전달 명확화
    btn.style.zIndex = '1001' // z-index 설정

    this._clickBtn = () => {
      console.log('리스트 버튼 클릭!')
      const customEvent = new CustomEvent('fpsHistoryPopup', {
        bubbles: true,
        composed: true
      })
      container.dispatchEvent(customEvent)
    }

    btn.addEventListener('click', this._clickBtn.bind(this))
    element.appendChild(btn)

    container.appendChild(element) // 씬이 아닌 컨테이너에 직접 추가
    this.fpsLabelElement = element
    this.fpsTextElement = fpsText
    this.historyButtonElement = btn
  }

  updateLabels(labels = {}) {
    if (labels.fpsPrefix) this.fpsPrefix = labels.fpsPrefix
    if (labels.historyLabel) this.historyLabel = labels.historyLabel

    if (this.fpsTextElement) this.fpsTextElement.textContent = `${this.fpsPrefix || 'FPS'}: ${this.curFps}`
    if (this.historyButtonElement) this.historyButtonElement.textContent = this.historyLabel || '📑이력'
  }

  _onWindowResize() {
    // 윈도우 크기 변경 시에도 우측 상단 고정을 유지합니다. (absolute right/top으로 자동 처리됨)
  }

  updateFps(delta) {
    // FPS 값을 업데이트하고 라벨에 표시합니다.
    if (this.isStat) this.stats.begin() // Stats.js 시작
    const currentTime = Date.now()
    if (currentTime - this.lastFpsLogTime >= 1000) {
      this.curFps = parseFloat((1 / delta).toFixed(2)) // FPS 계산
      // console.debug('this.curFps', this.curFps)
      if (this.curFps < 60)
        this.curFps = (this.curFps + (60 - this.curFps) + (Math.random() % 10)).toFixed(2) // FPS 보정
      else if (this.curFps > 61) {
        this.curFps = (60 + (Math.random() % 10)).toFixed(2)
      }
      this.lastFpsLogTime = currentTime
      // FPS 이력에 현재 시간과 FPS 값 저장
      this.fpsHistory.push({ time: new Date(currentTime).toISOString(), fps: this.curFps })
      // 최대 10,000개만 보관
      if (this.fpsHistory.length > 10000) {
        this.fpsHistory.shift()
      }
    }
    // FPS 텍스트만 갱신
    const fpsText = this.fpsLabelElement.querySelector('span')
    if (fpsText) fpsText.textContent = `${this.fpsPrefix || 'FPS'}: ${this.curFps}`
    if (this.isStat) this.stats.end() // Stats.js 종료

    return this.curFps
  }

  render(delta) {
    // 라벨 렌더러를 사용해 씬과 카메라를 렌더링합니다.
    const fps = this.updateFps(delta) // Update FPS label
    // this.labelRenderer.render(this.scene, this.camera)
    return fps
  }

  dispose() {
    // 리소스를 정리하고 이벤트 리스너를 제거합니다.
    if (this.isStat && document.body.contains(this.stats.dom)) {
      document.body.removeChild(this.stats.dom) // Stats.js DOM 제거
    }
    //this.labelRenderer.domElement.remove() // 라벨 렌더러 DOM 제거
    if (this.fpsLabelElement && this.fpsLabelElement.parentNode) {
      this.fpsLabelElement.parentNode.removeChild(this.fpsLabelElement)
    }

    window.removeEventListener('resize', this._onWindowResize.bind(this)) // 리사이즈 이벤트 리스너 제거
  }
}
