import * as THREE from 'three'
import { FBXLoader } from 'three/examples/jsm/loaders/FBXLoader.js'
import ModelLoadingStrategy from './ModelLoadingStrategy.js'

// 전역 loader 선언 (재사용 목적)
let fbxLoader = null

export default class FBXLoadingStrategy extends ModelLoadingStrategy {
  constructor() {
    super()
    this.supportedExtensions = ['fbx']

    // 전역 loader 초기화 (한 번만 생성)
    if (!fbxLoader) fbxLoader = new FBXLoader()
  }

  async loadModelInstance(viewer, modelData) {
    const modelPath = `${viewer.options.modelFolder}${modelData.path}`

    return new Promise((resolve, reject) => {
      fbxLoader.setPath('./')
      fbxLoader.load(
        modelPath,
        (model) => {
          viewer.scene.add(model)

          const animations = model.animations
          const mixer = animations?.length > 0 ? new THREE.AnimationMixer(model) : null

          // 추가 정보와 함께 반환
          resolve({ model, mixer, animations })
        },
        (xhr) => {
          /* 로딩 진행률 처리 */
        },
        (error) => {
          console.error(`FBX 로딩 실패: ${modelPath}`, error)
          reject(new Error(`FBX 로딩 실패: ${modelPath}`))
        },
      )
    })
  }

  disposeModel({ model, mixer }) {
    // 1. 모델 전체 순회
    model.traverse((child) => {
      if (child.isMesh) {
        // Geometry 해제
        if (child.geometry) {
          child.geometry.dispose()
          child.geometry = null
        }

        // Material 및 텍스처 해제
        if (child.material) {
          this.disposeMaterial(child.material)
          child.material = null
        }

        // Skeleton 처리 (FBX 캐릭터 애니메이션)
        if (child.skeleton?.boneInverses) {
          child.skeleton.dispose()
          child.skeleton = null
        }
      }
    })

    // 2. 씬 계층 구조에서 제거
    model.removeFromParent()

    // 3. 애니메이션 리소스 정리
    if (mixer) {
      mixer.stopAllAction()
      mixer.uncacheRoot(model)
      mixer = null
    }

    // 4. 참조 제거
    model.children = []
    model = null
  }

  disposeMaterial(material) {
    if (Array.isArray(material)) {
      material.forEach((m) => this.disposeSingleMaterial(m))
    } else {
      this.disposeSingleMaterial(material)
    }
  }

  disposeSingleMaterial(material) {
    // 텍스처 해제 (FBX는 주로 map, normalMap 사용)
    const textureKeys = ['map', 'normalMap', 'specularMap', 'alphaMap']
    textureKeys.forEach((key) => {
      const texture = material[key]
      if (texture?.isTexture) {
        texture.dispose()
        material[key] = null
      }
    })

    material.dispose()
  }
}
