// src/strategies/ModelInteractionStrategy.js

/**
 * 모델 상호작용 전략의 추상 기본 클래스입니다.
 * 모든 구체적인 상호작용 전략은 이 클래스를 상속받아 정의된 메서드를 구현해야 합니다.
 */
export default class ModelInteractionStrategy {
  constructor() {
    if (new.target === ModelInteractionStrategy) {
      throw new TypeError(
        'ModelInteractionStrategy는 직접 인스턴스화할 수 없습니다. 상속받아 사용하세요.',
      )
    }
  }

  /**
   * 모델 클릭 이벤트를 처리하고, 선택 로직을 수행합니다.
   * @param {EnhancedThreeViewer} viewer 뷰어 인스턴스
   * @param {Array<THREE.Intersection>} intersects Raycaster가 감지한 교차 객체 배열
   * @returns {void}
   * @abstract
   */
  handleModelClick(viewer, intersects) {
    throw new Error('handleModelClick() 메서드를 구현해야 합니다.')
  }

  /**
   * 특정 모델을 선택했을 때 적용되는 시각적/기능적 효과를 정의합니다.
   * @param {EnhancedThreeViewer} viewer 뷰어 인스턴스
   * @param {THREE.Object3D} obj 선택된 모델 객체
   * @returns {void}
   * @abstract
   */
  selectModel(viewer, obj) {
    throw new Error('selectModel() 메서드를 구현해야 합니다.')
  }

  /**
   * 특정 모델의 선택을 해제했을 때 적용되는 시각적/기능적 효과를 정의합니다.
   * @param {EnhancedThreeViewer} viewer 뷰어 인스턴스
   * @returns {void}
   * @abstract
   */
  unselectModel(viewer) {
    throw new Error('unselectModel() 메서드를 구현해야 합니다.')
  }

  /**
   * 매 프레임마다 상호작용 로직을 업데이트합니다.
   * (예: 선택된 모델의 애니메이션)
   * @param {EnhancedThreeViewer} viewer 뷰어 인스턴스
   * @param {number} delta 마지막 업데이트 이후 경과 시간 (초)
   * @returns {void}
   * @abstract
   */
  update(viewer, delta) {
    // 필요한 경우 하위 클래스에서 오버라이드하여 상호작용 애니메이션 로직을 추가
  }

  /**
   * 상호작용 전략에 필요한 모든 리소스를 해제합니다.
   * @returns {void}
   * @abstract
   */
  dispose() {
    // 필요한 경우 하위 클래스에서 오버라이드하여 리소스 해제 로직을 추가
  }
}
