import * as THREE from 'three'

/**
 * 개별 모델을 위한 효과 매니저
 * 각 모델 인스턴스마다 하나씩 생성되어 해당 모델의 효과를 관리합니다.
 */
export default class ModelEffectManager {
  constructor(scene, model, camera = null) {
    this.scene = scene
    this.model = model
    this.camera = camera
    this.modelId = model.userData.id
    this.activeEffects = new Map() // effectId -> { effectObjects, updateFn, config }
    this.timer = new THREE.Timer()

    // 효과별 기본 설정
    this._effectConfigs = {
      fire: {
        type: 'particle',
        baseCount: 120,
        baseSpreadFactor: 0.8,
        baseHeightFactor: 4.0,
        baseSpeed: 0.12,
        baseLifetime: 2.5,
        baseSize: 1.5,
        baseSizeEnd: 3.5,
        colorStart: 0xff4400, // 진한 주황/빨강
        colorEnd: 0xffaa00, // 밝은 주황
        opacityStart: 0.8,
        opacityEnd: 0,
        direction: new THREE.Vector3(0, 1, 0),
        material: null,
      },
      smoke: {
        type: 'particle',
        baseCount: 100,
        baseSpreadFactor: 1.2,
        baseHeightFactor: 3.0,
        baseSpeed: 0.05,
        baseLifetime: 4.0,
        baseSize: 0.8,
        baseSizeEnd: 4.0,
        colorStart: 0x666666,
        colorEnd: 0xaaaaaa,
        opacityStart: 0.5,
        opacityEnd: 0,
        direction: new THREE.Vector3(0, 1, 0),
        material: null,
      },
      water: {
        type: 'particle',
        baseCount: 150,
        baseSpreadFactor: 0.4,
        baseHeightFactor: 1.5,
        baseSpeed: 0.15,
        baseLifetime: 1.5,
        baseSize: 0.5,
        baseSizeEnd: 1.2,
        colorStart: 0x4444ff, // 파란색
        colorEnd: 0xaaaaff, // 연한 파란색/흰색
        opacityStart: 0.7,
        opacityEnd: 0,
        direction: new THREE.Vector3(0, -1, 0), // 아래로 쏟아짐
        material: null,
      },
      laser: {
        type: 'line',
        baseLength: 5.0,
        baseWidth: 3.0,
        colorStart: 0xff0000,
        colorEnd: 0xff4444,
        opacityStart: 1.0,
        opacityEnd: 0.3,
        direction: new THREE.Vector3(0, -1, 0),
        animated: true,
        pulseSpeed: 10.0,
        material: null,
      },
      welding_spark: {
        type: 'particle',
        baseCount: 50,
        baseSpreadFactor: 0.5,
        baseHeightFactor: 2.0,
        baseSpeed: 0.1,
        baseLifetime: 2.0,
        baseSize: 1.0,
        baseSizeEnd: 2.5,
        colorStart: 0xffaa00,
        colorEnd: 0xff4400,
        opacityStart: 1.0,
        opacityEnd: 0,
        direction: new THREE.Vector3(0, 1, 0),
        material: null,
      },
      cutting_spark: {
        type: 'particle',
        baseCount: 80,
        baseSpreadFactor: 1.0,
        baseHeightFactor: 1.5,
        baseSpeed: 0.15,
        baseLifetime: 1.5,
        baseSize: 0.8,
        baseSizeEnd: 2.0,
        colorStart: 0xffffff,
        colorEnd: 0xffaa44,
        opacityStart: 1.0,
        opacityEnd: 0,
        direction: new THREE.Vector3(0, 0.5, 0),
        material: null,
      },
      plasma_flame: {
        type: 'particle',
        baseCount: 30,
        baseSpreadFactor: 0.3,
        baseHeightFactor: 4.0,
        baseSpeed: 0.08,
        baseLifetime: 3.0,
        baseSize: 1.0,
        baseSizeEnd: 2.0,
        colorStart: 0x4444ff,
        colorEnd: 0x8888ff,
        opacityStart: 0.9,
        opacityEnd: 0,
        direction: new THREE.Vector3(0, 1, 0),
        material: null,
      },
      smoke_emission: {
        type: 'particle',
        baseCount: 100,
        baseSpreadFactor: 1.0,
        baseHeightFactor: 3.0,
        baseSpeed: 0.05,
        baseLifetime: 4.0,
        baseSize: 0.8,
        baseSizeEnd: 3.0,
        colorStart: 0x666666,
        colorEnd: 0xaaaaaa,
        opacityStart: 0.5,
        opacityEnd: 0,
        direction: new THREE.Vector3(0, 1, 0),
        material: null,
      },
    }

    this.textures = {
      spark: this._createSparkTexture(),
      smoke: this._createSmokeTexture(),
    }

    this._initializeMaterials()
  }

  /** 스파크용 텍스처 생성 */
  _createSparkTexture() {
    const canvas = document.createElement('canvas')
    canvas.width = 32
    canvas.height = 32
    const context = canvas.getContext('2d')
    const gradient = context.createRadialGradient(16, 16, 0, 16, 16, 16)
    gradient.addColorStop(0, 'rgba(255,255,255,1)')
    gradient.addColorStop(0.3, 'rgba(255,200,100,0.8)')
    gradient.addColorStop(0.7, 'rgba(255,100,50,0.4)')
    gradient.addColorStop(1, 'rgba(0,0,0,0)')
    context.fillStyle = gradient
    context.fillRect(0, 0, 32, 32)
    return new THREE.CanvasTexture(canvas)
  }

  /** 연기용 텍스처 생성 */
  _createSmokeTexture() {
    const canvas = document.createElement('canvas')
    canvas.width = 32
    canvas.height = 32
    const context = canvas.getContext('2d')
    const gradient = context.createRadialGradient(16, 16, 0, 16, 16, 16)
    gradient.addColorStop(0, 'rgba(255,255,255,0.6)')
    gradient.addColorStop(0.5, 'rgba(128,128,128,0.4)')
    gradient.addColorStop(1, 'rgba(64,64,64,0)')
    context.fillStyle = gradient
    context.fillRect(0, 0, 32, 32)
    return new THREE.CanvasTexture(canvas)
  }

  /** 효과별 재료 초기화 */
  _initializeMaterials() {
    for (const type in this._effectConfigs) {
      const config = this._effectConfigs[type]
      if (config.colorStart !== undefined) {
        if (config.type === 'line') {
          config.material = new THREE.LineBasicMaterial({
            color: new THREE.Color(config.colorStart),
            transparent: true,
            opacity: config.opacityStart,
            linewidth: config.baseWidth || 1,
            depthTest: true, // 깊이 테스트 활성화로 적절한 가려짐 처리
            depthWrite: false, // 투명 효과를 위해 깊이 쓰기는 비활성화
          })
        } else if (config.type === 'particle') {
          config.material = new THREE.PointsMaterial({
            color: new THREE.Color(config.colorStart),
            size: config.baseSize || 1.0,
            sizeAttenuation: true, // 거리에 따른 크기 조절 활성화
            transparent: true,
            blending: THREE.AdditiveBlending,
            depthWrite: false, // 투명 효과를 위해 깊이 쓰기는 비활성화
            depthTest: true, // 깊이 테스트 활성화로 적절한 가려짐 처리
            map: this.textures.spark,
            vertexColors: true, // 정점 색상 활성화
            opacity: config.opacityStart,
            alphaTest: 0.1, // 알파 테스트 추가
          })
        }
      }
    }
  }

  /**
   * 효과를 추가합니다.
   * @param {string} effectType 효과 타입
   * @param {string} [objectName] 특정 오브젝트 이름 (선택사항)
   * @param {Object} [options] 추가 옵션
   * @param {number} [options.size] 파티클 크기 배수 (1.0이 기본값)
   * @param {number} [options.width] 라인 두께 배수 (1.0이 기본값)
   * @param {number} [options.length] 라인 길이 배수 (1.0이 기본값)
   * @param {number} [options.count] 파티클 개수 배수 (1.0이 기본값)
   * @param {number} [options.speed] 효과 속도 배수 (1.0이 기본값)
   * @param {number} [options.spread] 파티클 퍼짐 정도 배수 (1.0이 기본값)
   * @param {number} [options.lifetime] 파티클 생존시간 배수 (1.0이 기본값)
   * @param {number} [options.opacity] 투명도 배수 (1.0이 기본값, 0.0-1.0)
   * @param {number} [options.alphaTest] 알파 테스트 값 (0.0-1.0, 기본값은 효과별 설정)
   * @param {boolean} [options.depthTest] 깊이 테스트 활성화 여부 (기본값은 효과별 설정)
   * @param {boolean} [options.depthWrite] 깊이 쓰기 활성화 여부 (기본값은 효과별 설정)
   * @param {number} [options.renderOrder] 렌더링 순서 (낮을수록 먼저, 높을수록 나중에 렌더링, 기본값: 10)
   * @returns {string} 효과 ID
   */
  addEffect(effectType, objectName = null, options = {}) {
    const effectId = `${effectType}_${objectName || 'model'}_${Date.now()}`

    const baseConfig = this._effectConfigs[effectType]
    if (!baseConfig) {
      console.warn(`정의되지 않은 효과 타입: ${effectType}`)
      return null
    }

    let targetObject = null
    let worldPosition = new THREE.Vector3()

    if (objectName) {
      // 특정 오브젝트에 효과 적용
      targetObject = this._findObjectByName(this.model, objectName)
      if (!targetObject) {
        console.warn(`오브젝트 '${objectName}'을 모델 '${this.modelId}'에서 찾을 수 없습니다.`)
        return null
      }
      targetObject.getWorldPosition(worldPosition)
    } else if (options.position) {
      // 직접 위치 지정
      worldPosition.copy(options.position)
    } else {
      // 모델의 중심 위치 사용
      this.model.getWorldPosition(worldPosition)
    }

    // 효과 설정 계산 (크기, 두께, 길이 등의 배수 적용)
    const config = {
      ...baseConfig,
      effectType: effectType,
      effectId: effectId,
      worldPosition: worldPosition,
      targetObject: targetObject,
      direction: options.direction || baseConfig.direction.clone(),
      intensity: options.intensity || 1.0,
      // 크기 및 두께 관련 옵션들
      sizeMultiplier: options.size || 1.0,
      widthMultiplier: options.width || 1.0,
      lengthMultiplier: options.length || 1.0,
      countMultiplier: options.count || 1.0,
      speedMultiplier: options.speed || 1.0,
      spreadMultiplier: options.spread || 1.0,
      lifetimeMultiplier: options.lifetime || 1.0,
      // 투명도 및 depth 관련 옵션들
      opacityMultiplier: options.opacity || 1.0,
      customAlphaTest: options.alphaTest !== undefined ? options.alphaTest : null,
      customDepthTest: options.depthTest !== undefined ? options.depthTest : null,
      customDepthWrite: options.depthWrite !== undefined ? options.depthWrite : null,
      customRenderOrder: options.renderOrder !== undefined ? options.renderOrder : 10,
      ...options,
    }

    const effectObjects = []
    let updateFn = null

    if (config.type === 'line') {
      const lineSystem = this._createLineEffect(config)
      effectObjects.push(lineSystem.line)
      updateFn = lineSystem.update
      this.scene.add(lineSystem.line)
    } else if (config.type === 'particle') {
      const particleSystem = this._createParticleSystem(config)
      effectObjects.push(particleSystem.points)
      updateFn = particleSystem.update
      this.scene.add(particleSystem.points)
    }

    this.activeEffects.set(effectId, { effectObjects, updateFn, config })
    return effectId
  }

  /**
   * 효과를 제거합니다.
   * @param {string} effectId 효과 ID
   */
  removeEffect(effectId) {
    if (this.activeEffects.has(effectId)) {
      const { effectObjects } = this.activeEffects.get(effectId)
      effectObjects.forEach((obj) => {
        if (obj instanceof THREE.Points || obj instanceof THREE.Line) {
          obj.geometry.dispose()
          if (obj.material) {
            obj.material.dispose()
          }
        }
        this.scene.remove(obj)
      })
      this.activeEffects.delete(effectId)
    }
  }

  /**
   * 모든 효과를 제거합니다.
   */
  removeAllEffects() {
    for (const effectId of this.activeEffects.keys()) {
      this.removeEffect(effectId)
    }
  }

  /**
   * 효과의 위치를 업데이트합니다.
   * @param {string} effectId 효과 ID
   * @param {THREE.Vector3} position 새로운 위치
   */
  updateEffectPosition(effectId, position) {
    if (this.activeEffects.has(effectId)) {
      const { config } = this.activeEffects.get(effectId)
      config.worldPosition.copy(position)
    }
  }

  /**
   * 효과의 방향을 업데이트합니다.
   * @param {string} effectId 효과 ID
   * @param {THREE.Vector3} direction 새로운 방향
   */
  updateEffectDirection(effectId, direction) {
    if (this.activeEffects.has(effectId)) {
      const { config } = this.activeEffects.get(effectId)
      config.direction.copy(direction)
    }
  }

  /**
   * 모델에서 이름으로 오브젝트 찾기
   * @param {THREE.Object3D} model
   * @param {string} objectName
   * @returns {THREE.Object3D|null}
   */
  _findObjectByName(model, objectName) {
    let foundObject = null
    model.traverse((child) => {
      if (child.name === objectName && !foundObject) {
        foundObject = child
      }
    })
    return foundObject
  }

  /**
   * 라인 효과 생성 (레이저 등)
   * @param {Object} config 효과 설정
   */
  _createLineEffect(config) {
    const points = []
    const startPoint = config.worldPosition.clone()
    const effectiveLength = config.baseLength * config.intensity * config.lengthMultiplier
    const endPoint = config.worldPosition
      .clone()
      .add(config.direction.clone().multiplyScalar(effectiveLength))

    points.push(startPoint, endPoint)

    const geometry = new THREE.BufferGeometry().setFromPoints(points)

    // 재료 복제 및 설정 적용
    const material = config.material.clone()
    material.linewidth = config.baseWidth * config.widthMultiplier

    // 투명도 설정
    if (config.opacityMultiplier !== 1.0) {
      material.opacity = config.opacityStart * config.opacityMultiplier
    }

    // 깊이 테스트 및 쓰기 설정
    if (config.customDepthTest !== null) {
      material.depthTest = config.customDepthTest
    }
    if (config.customDepthWrite !== null) {
      material.depthWrite = config.customDepthWrite
    }

    const line = new THREE.Line(geometry, material)
    line.name = `effect_line_${config.effectType}`

    // 렌더링 순서 설정
    line.renderOrder = config.customRenderOrder

    // 좌절 컬링 비활성화 (카메라 시야 밖에서도 렌더링)
    line.frustumCulled = false

    // 라인 업데이트 함수
    const update = (deltaTime) => {
      if (!line.geometry || !config.targetObject) return

      // 오브젝트의 현재 월드 위치로 업데이트
      const currentWorldPos = new THREE.Vector3()
      if (config.targetObject) {
        config.targetObject.getWorldPosition(currentWorldPos)
      } else {
        currentWorldPos.copy(config.worldPosition)
      }

      const effectiveLength = config.baseLength * config.intensity * config.lengthMultiplier
      const newEndPoint = currentWorldPos
        .clone()
        .add(config.direction.clone().multiplyScalar(effectiveLength))

      const positions = line.geometry.attributes.position.array
      positions[0] = currentWorldPos.x
      positions[1] = currentWorldPos.y
      positions[2] = currentWorldPos.z
      positions[3] = newEndPoint.x
      positions[4] = newEndPoint.y
      positions[5] = newEndPoint.z

      line.geometry.attributes.position.needsUpdate = true

      // 애니메이션 효과 (펄스)
      if (config.animated) {
        const time = this.timer.getElapsed()
        const pulse = Math.sin(time * config.pulseSpeed) * 0.3 + 0.7
        line.material.opacity = config.opacityStart * pulse
      }
    }

    return { line, update }
  }

  /**
   * 파티클 시스템 생성
   * @param {Object} config 효과 설정
   */
  _createParticleSystem(config) {
    const effectiveCount = Math.round(config.baseCount * config.countMultiplier)
    const positions = new Float32Array(effectiveCount * 3)
    const sizes = new Float32Array(effectiveCount)
    const colors = new Float32Array(effectiveCount * 3)
    const initialTimes = new Float32Array(effectiveCount)
    const lifetimes = new Float32Array(effectiveCount)
    const velocities = new Float32Array(effectiveCount * 3)

    const colorStart = new THREE.Color(config.colorStart)
    const colorEnd = new THREE.Color(config.colorEnd)

    for (let i = 0; i < effectiveCount; i++) {
      const i3 = i * 3

      // 초기 위치 설정
      positions[i3 + 0] = config.worldPosition.x
      positions[i3 + 1] = config.worldPosition.y
      positions[i3 + 2] = config.worldPosition.z

      // 크기 설정 (크기 배수 적용)
      sizes[i] = config.baseSize * config.sizeMultiplier

      // 색상 설정
      colors[i3 + 0] = colorStart.r
      colors[i3 + 1] = colorStart.g
      colors[i3 + 2] = colorStart.b

      // 시간 설정 (생존시간 배수 적용)
      const effectiveLifetime = config.baseLifetime * config.lifetimeMultiplier
      initialTimes[i] = this.timer.getElapsed() + Math.random() * effectiveLifetime
      lifetimes[i] = effectiveLifetime * (0.8 + Math.random() * 0.4)

      // 속도 설정 (속도 및 퍼짐 배수 적용)
      const velocity = config.direction.clone()
      const effectiveSpread = config.baseSpreadFactor * config.spreadMultiplier
      velocity.x += (Math.random() - 0.5) * effectiveSpread
      velocity.y += (Math.random() - 0.5) * effectiveSpread
      velocity.z += (Math.random() - 0.5) * effectiveSpread
      velocity.multiplyScalar(config.baseSpeed * config.intensity * config.speedMultiplier)

      velocities[i3 + 0] = velocity.x
      velocities[i3 + 1] = velocity.y
      velocities[i3 + 2] = velocity.z
    }

    const geometry = new THREE.BufferGeometry()
    geometry.setAttribute('position', new THREE.BufferAttribute(positions, 3))
    geometry.setAttribute('size', new THREE.BufferAttribute(sizes, 1))
    geometry.setAttribute('color', new THREE.BufferAttribute(colors, 3))
    geometry.setAttribute('initialTime', new THREE.BufferAttribute(initialTimes, 1))
    geometry.setAttribute('lifetime', new THREE.BufferAttribute(lifetimes, 1))
    geometry.setAttribute('velocity', new THREE.BufferAttribute(velocities, 3))

    // 재료 복제 및 설정 적용
    const material = config.material.clone()
    material.size = config.baseSize * config.sizeMultiplier

    // 투명도 설정
    if (config.opacityMultiplier !== 1.0) {
      material.opacity = config.opacityStart * config.opacityMultiplier
    }

    // 알파 테스트 설정
    if (config.customAlphaTest !== null) {
      material.alphaTest = config.customAlphaTest
    }

    // 깊이 테스트 및 쓰기 설정
    if (config.customDepthTest !== null) {
      material.depthTest = config.customDepthTest
    }
    if (config.customDepthWrite !== null) {
      material.depthWrite = config.customDepthWrite
    }

    const points = new THREE.Points(geometry, material)
    points.name = `effect_particles_${config.effectType}`

    // 렌더링 순서 설정
    points.renderOrder = config.customRenderOrder

    // 좌절 컬링 비활성화 (카메라 시야 밖에서도 렌더링)
    points.frustumCulled = false

    // 파티클 업데이트 함수
    const update = (deltaTime) => {
      if (!points.geometry || (!config.targetObject && !config.worldPosition)) return

      // 현재 위치 계산
      const currentWorldPos = new THREE.Vector3()
      if (config.targetObject) {
        config.targetObject.getWorldPosition(currentWorldPos)
      } else {
        currentWorldPos.copy(config.worldPosition)
      }

      const positions = points.geometry.attributes.position.array
      const sizes = points.geometry.attributes.size.array
      const colors = points.geometry.attributes.color.array
      const initialTimes = points.geometry.attributes.initialTime.array
      const lifetimes = points.geometry.attributes.lifetime.array
      const velocities = points.geometry.attributes.velocity.array
      const currentTime = this.timer.getElapsed()

      for (let i = 0; i < effectiveCount; i++) {
        const i3 = i * 3
        const i1 = i

        let elapsed = (currentTime - initialTimes[i1]) % lifetimes[i1]
        if (elapsed < 0) elapsed += lifetimes[i1]

        const progress = elapsed / lifetimes[i1]

        // 파티클 재시작
        if (progress >= 1.0) {
          initialTimes[i1] = currentTime
          elapsed = 0

          // 새로운 속도 계산 (배수들 다시 적용)
          const newVelocity = config.direction.clone()
          const effectiveSpread = config.baseSpreadFactor * config.spreadMultiplier
          newVelocity.x += (Math.random() - 0.5) * effectiveSpread
          newVelocity.y += (Math.random() - 0.5) * effectiveSpread
          newVelocity.z += (Math.random() - 0.5) * effectiveSpread
          newVelocity.multiplyScalar(config.baseSpeed * config.intensity * config.speedMultiplier)

          velocities[i3 + 0] = newVelocity.x
          velocities[i3 + 1] = newVelocity.y
          velocities[i3 + 2] = newVelocity.z
        }

        // 위치 업데이트 (현재 오브젝트 위치 + 속도 * 시간)
        positions[i3 + 0] = currentWorldPos.x + velocities[i3 + 0] * elapsed
        positions[i3 + 1] = currentWorldPos.y + velocities[i3 + 1] * elapsed
        positions[i3 + 2] = currentWorldPos.z + velocities[i3 + 2] * elapsed

        // 크기 업데이트 (크기 배수 적용)
        const effectiveSizeEnd = config.baseSizeEnd * config.sizeMultiplier
        let baseSize = THREE.MathUtils.lerp(
          config.baseSize * config.sizeMultiplier,
          effectiveSizeEnd,
          progress,
        )

        // 카메라 거리에 따른 크기 조절
        if (this.camera) {
          const distance = this.camera.position.distanceTo(currentWorldPos)
          const scaleFactor = Math.max(0.5, Math.min(3.0, distance / 10.0)) // 거리에 따른 스케일 팩터
          baseSize *= scaleFactor
        }

        sizes[i1] = baseSize

        // 색상 업데이트
        const colorStart = new THREE.Color(config.colorStart)
        const colorEnd = new THREE.Color(config.colorEnd)
        const currentColor = colorStart.clone().lerp(colorEnd, progress)
        colors[i3 + 0] = currentColor.r
        colors[i3 + 1] = currentColor.g
        colors[i3 + 2] = currentColor.b
      }

      points.geometry.attributes.position.needsUpdate = true
      points.geometry.attributes.size.needsUpdate = true
      points.geometry.attributes.color.needsUpdate = true
      points.geometry.attributes.velocity.needsUpdate = true
    }

    return { points, update }
  }

  /**
   * 효과 업데이트 (애니메이션 루프에서 호출)
   * @param {number} deltaTime
   */
  update(deltaTime) {
    this.timer.update()
    for (const { updateFn } of this.activeEffects.values()) {
      if (updateFn) {
        updateFn(deltaTime)
      }
    }
  }

  /**
   * 리소스 정리
   */
  dispose() {
    this.removeAllEffects()

    // 텍스처 정리
    Object.values(this.textures).forEach((texture) => {
      texture.dispose()
    })

    // 재료 정리
    Object.values(this._effectConfigs).forEach((config) => {
      if (config.material) {
        config.material.dispose()
      }
    })

    this.activeEffects.clear()
  }
}
