import * as THREE from 'three'

export default class MoveManager {
  constructor(
    instances,
    onModelPositionUpdate,
    collisionDetectionEnabled = true,
    ignoreCollisionModels = new Set(),
  ) {
    this.instances = instances
    this.onModelPositionUpdate = onModelPositionUpdate
    this.movingModels = new Map()
    this.moveSpeed = 0
    this.collisionDetectionEnabled = collisionDetectionEnabled
    this.ignoreCollisionModels = ignoreCollisionModels
  }

  startContinuousMove(modelId, direction, moveSpeed = 5) {
    const model = this.instances.get(modelId)
    if (!model) {
      console.warn(
        `[MoveManager] 모델 '${modelId}'를 찾을 수 없습니다. 연속 이동을 시작할 수 없습니다.`,
      )
      return
    }

    this.moveSpeed = moveSpeed

    let duration = 1
    let moveVector = { x: 0, y: 0, z: 0 }

    switch (direction) {
      case 'left':
        moveVector.x = -1 * duration
        break
      case 'right':
        moveVector.x = duration
        break
      case 'forward':
        moveVector.z = -1 * duration
        break
      case 'backward':
        moveVector.z = duration
        break
      case 'up':
        moveVector.y = duration
        break
      case 'down':
        moveVector.y = -1 * duration
        break
      case 'forward-left':
        moveVector.x = -1 * duration
        moveVector.z = -1 * duration
        break
      case 'forward-right':
        moveVector.x = duration
        moveVector.z = -1 * duration
        break
      case 'backward-left':
        moveVector.x = -1 * duration
        moveVector.z = duration
        break
      case 'backward-right':
        moveVector.x = duration
        moveVector.z = duration
        break
      case 'stop':
        this.stopContinuousMove(modelId)
        return
      default:
        console.warn(`[MoveManager] 알 수 없는 방향: ${direction}`)
        return
    }

    const vectorLength = Math.sqrt(moveVector.x ** 2 + moveVector.y ** 2 + moveVector.z ** 2)
    if (vectorLength > 0 && vectorLength !== 1) {
      moveVector.x /= vectorLength
      moveVector.y /= vectorLength
      moveVector.z /= vectorLength
    }

    this.movingModels.set(modelId, moveVector)
  }

  stopContinuousMove(modelId) {
    if (this.movingModels.has(modelId)) this.movingModels.set(modelId, { x: 0, y: 0, z: 0 }) // 해당 모델의 이동 벡터를 0으로 설정하여 멈춤

    const chkStopModel = Array.from(this.movingModels.values()).every(
      (vec) => vec.x === 0 && vec.y === 0 && vec.z === 0,
    )
    if (chkStopModel) this.moveSpeed = 0 // 모든 모델이 멈췄는지 확인하여 moveSpeed를 0으로 설정
    return chkStopModel
  }

  update(delta) {
    // moveSpeed가 0보다 클 때만 이동 로직 실행
    if (this.moveSpeed > 0) {
      this.movingModels.forEach((dir, modelId) => {
        // 이동 방향 벡터가 (0,0,0)이 아닌 경우에만 처리
        if (dir.x !== 0 || dir.y !== 0 || dir.z !== 0) {
          const model = this.instances.get(modelId)
          if (!model) {
            console.warn(
              `[MoveManager] 업데이트 중 인스턴스에서 모델 ${modelId}를 찾을 수 없습니다.`,
            )
            // 모델을 찾을 수 없으면 movingModels 맵에서 제거 (선택 사항)
            this.movingModels.delete(modelId)
            return
          }

          const originalPosition = model.position.clone()

          const newPosition = new THREE.Vector3(
            model.position.x + dir.x * this.moveSpeed * delta,
            model.position.y + dir.y * this.moveSpeed * delta,
            model.position.z + dir.z * this.moveSpeed * delta,
          )

          model.position.copy(newPosition)

          let collisionDetected = false
          const currentMoveDirection = new THREE.Vector3(dir.x, dir.y, dir.z).normalize()

          if (this.collisionDetectionEnabled && !this.ignoreCollisionModels.has(modelId)) {
            // const AXIAL_TOLERANCE = 0.99
            // collisionDetected = this._checkCollisions(model, modelId,currentMoveDirection,  AXIAL_TOLERANCE )
            collisionDetected = this._checkMeshCollision(
              model,
              modelId,
              currentMoveDirection,
              this.moveSpeed * delta, // 이동 거리
            )
          }

          if (collisionDetected) {
            // 1. 충돌이 감지되면 일단 이전 위치로 되돌립니다.
            model.position.copy(originalPosition)

            // 2. 모델의 바운딩 박스 크기를 얻습니다.
            const bbox = new THREE.Box3().setFromObject(model)
            const size = new THREE.Vector3()
            bbox.getSize(size) // size.x, size.y, size.z 에 모델의 너비, 높이, 깊이가 저장됩니다.

            // 3. 튕겨 나갈 거리를 모델 크기(가장 큰 축의 길이)의 일부로 설정합니다.
            // 여기서는 0.5를 곱하여 모델 크기의 절반만큼 튕겨 나가도록 했습니다.
            // 이 값은 모델의 종류와 원하는 효과에 따라 조정할 수 있습니다.
            const pushBackDistance = Math.max(size.x, size.y, size.z) * 0.5 // 모델 크기의 절반

            // 4. 충돌 방향의 반대 방향으로 밀어냅니다.
            const pushBackVector = currentMoveDirection.negate().multiplyScalar(pushBackDistance)
            model.position.add(pushBackVector)

            // 5. 이동을 멈춥니다. (연속 이동의 경우)
            this.stopContinuousMove(modelId)
          }
          // 6. 모델의 새로운 위치를 업데이트 알림 (밀어낸 후의 위치)
          this.onModelPositionUpdate(modelId, model.position.toArray())
        }
      })
    }
    // moveSpeed가 0이거나, 모든 모델의 이동 방향이 (0,0,0)이면 아무것도 하지 않으므로 불필요한 로그가 출력되지 않음
  }

  /**
   * 특정 모델이 다른 모델과 충돌하는지 확인합니다.
   * @param {THREE.Object3D} movingModel 현재 이동 중인 모델
   * @param {string} movingModelId 현재 이동 중인 모델의 ID
   * @param {THREE.Vector3} direction 현재 이동하려는 방향 벡터 (정규화된 상태)
   * @param {number} tolerance 축별 겹침 허용 오차
   * @returns {boolean} 충돌이 감지되면 true, 그렇지 않으면 false
   */
  _checkCollisions(movingModel, movingModelId, direction, tolerance) {
    // console.log('_checkCollisions', movingModelId, direction)
    const movingModelBBox = new THREE.Box3().setFromObject(movingModel)

    let collision = false
    this.instances.forEach((otherModel, otherModelId) => {
      if (movingModelId === otherModelId || this.ignoreCollisionModels.has(otherModelId)) return

      const otherModelBBox = new THREE.Box3().setFromObject(otherModel)

      if (movingModelBBox.intersectsBox(otherModelBBox)) {
        const intersection = new THREE.Box3().copy(movingModelBBox).intersect(otherModelBBox)
        const intersectionSize = new THREE.Vector3()
        intersection.getSize(intersectionSize)

        let isCollidingInMoveDirection = false

        // X축 방향으로 이동하려는 경향이 강한 경우
        if (
          Math.abs(direction.x) > Math.abs(direction.y) &&
          Math.abs(direction.x) > Math.abs(direction.z)
        ) {
          isCollidingInMoveDirection = intersectionSize.x > tolerance * 2
        }
        // Y축 방향으로 이동하려는 경향이 강한 경우
        else if (
          Math.abs(direction.y) > Math.abs(direction.x) &&
          Math.abs(direction.y) > Math.abs(direction.z)
        ) {
          isCollidingInMoveDirection = intersectionSize.y > tolerance
        }
        // Z축 방향으로 이동하려는 경향이 강하거나, 모든 방향으로 이동 의지가 비슷하거나 없는 경우
        else {
          isCollidingInMoveDirection = intersectionSize.z > tolerance
        }

        if (isCollidingInMoveDirection) {
          collision = true
          return
        }
      }
    })
    return collision
  }

  /**
   * 특정 모델이 이동 방향으로 Raycasting을 사용하여 다른 모델과 충돌하는지 확인합니다.
   * 이 함수는 Mesh의 실제 기하학을 기반으로 충돌을 감지합니다.
   * @param {THREE.Object3D} movingModel 현재 이동 중인 모델
   * @param {string} movingModelId 현재 이동 중인 모델의 ID
   * @param {THREE.Vector3} direction 현재 이동하려는 방향 벡터 (정규화된 상태)
   * @param {number} distance 이동 거리 (delta * moveSpeed)
   * @returns {boolean} 충돌이 감지되면 true, 그렇지 않으면 false
   */
  _checkMeshCollision(movingModel, movingModelId, direction, distance) {
    // console.log('_checkMeshCollision (Raycasting)', movingModelId, direction, distance)
    let collision = false
    const raycaster = new THREE.Raycaster()
    const origin = movingModel.position.clone() // 모델의 현재 위치에서 광선 발사

    // 모델의 바운딩 박스를 사용하여 광선 발사 지점 조정 (선택 사항, 더 정확한 시작점을 위해)
    const bbox = new THREE.Box3().setFromObject(movingModel)
    const center = bbox.getCenter(new THREE.Vector3())
    origin.copy(center) // 모델의 중심에서 광선 발사

    raycaster.set(origin, direction)
    raycaster.far = distance + 0.1 // 이동하려는 거리 + 약간의 여유

    const objectsToCheck = []
    this.instances.forEach((otherModel, otherModelId) => {
      if (movingModelId !== otherModelId && !this.ignoreCollisionModels.has(otherModelId)) {
        // 다른 모델의 모든 메시 자식을 검사 대상에 추가
        otherModel.traverse((child) => {
          if (child.isMesh) {
            objectsToCheck.push(child)
          }
        })
      }
    })

    if (objectsToCheck.length > 0) {
      const intersects = raycaster.intersectObjects(objectsToCheck, true)
      if (intersects.length > 0) {
        // 가장 가까운 교차점을 확인하여 충돌로 간주
        const firstIntersect = intersects[0]
        if (firstIntersect.distance < distance + 0.01) {
          // 이동 거리 내에서 충돌했는지 확인
          collision = true
          console.log(
            `[MoveManager] 메시 충돌 감지! ${movingModelId}와 ${firstIntersect.object.parent.name || firstIntersect.object.name} 간의 충돌`,
          )
        }
      }
    }
    return collision
  }

  moveTo(modelId, newPosition) {
    const model = this.instances.get(modelId)
    if (!model) {
      console.warn(`[MoveManager] 모델 '${modelId}'를 찾을 수 없습니다.`)
      return
    }
    model.position.set(...newPosition)
    this.onModelPositionUpdate(modelId, newPosition)
  }

  rotateModel(modelId, axis, angleDeg) {
    const model = this.instances.get(modelId)
    if (!model) {
      console.warn(`[MoveManager] 모델 '${modelId}'를 찾을 수 없습니다. 회전할 수 없습니다.`)
      return
    }

    const angleRad = THREE.MathUtils.degToRad(angleDeg)
    const currentPosition = model.position.clone()
    const bbox = new THREE.Box3().setFromObject(model)
    const center = bbox.getCenter(new THREE.Vector3())
    model.position.sub(center)

    switch (axis) {
      case 'x':
        model.rotateX(angleRad)
        break
      case 'y':
        model.rotateY(angleRad)
        break
      case 'z':
        model.rotateZ(angleRad)
        break
      default:
        console.warn(
          `[MoveManager] 회전을 위한 유효하지 않은 축: ${axis}. 'x', 'y', 또는 'z'를 사용하세요.`,
        )
        model.position.copy(currentPosition)
        return
    }
    model.position.add(center)
  }

  rotateModelByEuler(modelId, xDeg, yDeg, zDeg, order = 'XYZ', isAdditive = true) {
    const model = this.instances.get(modelId)
    if (!model) {
      console.warn(`[MoveManager] 모델 '${modelId}'를 찾을 수 없습니다. 오일러 회전할 수 없습니다.`)
      return
    }

    const xRad = THREE.MathUtils.degToRad(xDeg)
    const yRad = THREE.MathUtils.degToRad(yDeg)
    const zRad = THREE.MathUtils.degToRad(zDeg)

    const currentPosition = model.position.clone()
    const bbox = new THREE.Box3().setFromObject(model)
    const center = bbox.getCenter(new THREE.Vector3())
    model.position.sub(center)

    if (isAdditive) {
      model.rotateX(xRad)
      model.rotateY(yRad)
      model.rotateZ(zRad)
    } else {
      const newEuler = new THREE.Euler(xRad, yRad, zRad, order)
      model.rotation.copy(newEuler)
    }
    model.position.add(center)
  }

  dispose() {
    this.movingModels.clear()
    this.moveSpeed = 0
  }
}
