import React, { useState, useEffect, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import type EnhancedThreeViewer from '@/platforms/dt-robot/lib/EnhancedThreeViewer';
import type { AnalyzedModelData, AnalyzedObject } from '@/platforms/dt-robot/lib/EnhancedThreeViewer';

interface Props {
    viewer: EnhancedThreeViewer | null;
    modelId: string;
    onUpdate: (property: string, value: any) => void;
}

const ModelObjectControlPanel: React.FC<Props> = ({ viewer, modelId, onUpdate }) => {
    const { t } = useTranslation('dt-robot');
    const [isCollapsed, setIsCollapsed] = useState(true);
    const [selectedObjectName, setSelectedObjectName] = useState('');
    const [position, setPosition] = useState({ x: 0, y: 0, z: 0 });
    const [rotation, setRotation] = useState({ x: 0, y: 0, z: 0 });
    const [modelData, setModelData] = useState<AnalyzedModelData | null>(null);

    useEffect(() => {
        if (!viewer || !modelId) return;

        const rawData = viewer.getModelData(modelId);
        if (rawData && rawData.objectList) {
            const simplifiedList = rawData.objectList.map((obj: AnalyzedObject) => ({
                id: obj.id,
                name: obj.name,
                transform: {
                    position: [...(obj.transform?.position || [0, 0, 0])],
                    rotation: [...(obj.transform?.rotation || [0, 0, 0])],
                }
            }));
            setModelData({ objectList: simplifiedList } as AnalyzedModelData);
        } else {
            setModelData(null);
        }

        setSelectedObjectName('');
    }, [viewer, modelId]);

    const objectList = useMemo(() => modelData?.objectList || [], [modelData]);

    const selectedObject = useMemo(() => 
        objectList.find((obj: AnalyzedObject) => obj.name === selectedObjectName) || null
    , [objectList, selectedObjectName]);

    useEffect(() => {
        if (selectedObject) {
            setPosition({
                x: selectedObject.transform.position[0],
                y: selectedObject.transform.position[1],
                z: selectedObject.transform.position[2],
            });
            setRotation({
                x: selectedObject.transform.rotation[0],
                y: selectedObject.transform.rotation[1],
                z: selectedObject.transform.rotation[2],
            });
        }
    }, [selectedObject]);

    const handleApplyPosition = () => {
        onUpdate('objectPosition', {
            objectName: selectedObjectName,
            value: position
        });
    };

    const handleApplyRotation = () => {
        onUpdate('objectRotation', {
            objectName: selectedObjectName,
            value: rotation
        });
    };

    return (
        <div className="control-section">
            <div className="section-title" onClick={() => setIsCollapsed(!isCollapsed)}>
                {t('panels.model_object.title')}
                <span className="collapse-icon">{isCollapsed ? '▼' : '▲'}</span>
            </div>

            {!isCollapsed && (
                <div className="section-content">
                    {objectList.length === 0 ? (
                        <div className="placeholder-message" style={{ fontSize: '11px', textAlign: 'center', padding: '10px' }}>
                            {t('panels.model_object.no_objects')}
                        </div>
                    ) : (
                        <div className="control-item">
                            <label className="control-label">{t('panels.model_object.select')}</label>
                            <select
                                className="dt-select"
                                value={selectedObjectName}
                                onChange={(e) => setSelectedObjectName(e.target.value)}
                                style={{ marginBottom: '12px' }}
                            >
                                <option value="" disabled>{t('panels.model_object.placeholder')}</option>
                                {objectList.map((obj: AnalyzedObject) => (
                                    <option key={obj.id} value={obj.name}>
                                        {obj.name || obj.id}
                                    </option>
                                ))}
                            </select>

                            {selectedObject && (
                                <div className="object-specific-controls">
                                    <div className="control-item">
                                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '6px' }}>
                                            <span style={{ fontSize: '11px', fontWeight: 'bold' }}>{t('panels.model_object.pos_setting')}</span>
                                            <button className="joy-btn" style={{ padding: '2px 8px', fontSize: '10px' }} onClick={handleApplyPosition}>{t('panels.model_object.apply')}</button>
                                        </div>
                                        <div className="control-row-grid" style={{ marginTop: 0 }}>
                                            <div className="control-item-inline">
                                                <label>X</label>
                                                <input type="number" step="0.1" value={position.x} onChange={e => setPosition({...position, x: parseFloat(e.target.value) || 0})} className="dt-input" style={{ width: '50px' }} />
                                            </div>
                                            <div className="control-item-inline">
                                                <label>Y</label>
                                                <input type="number" step="0.1" value={position.y} onChange={e => setPosition({...position, y: parseFloat(e.target.value) || 0})} className="dt-input" style={{ width: '50px' }} />
                                            </div>
                                            <div className="control-item-inline">
                                                <label>Z</label>
                                                <input type="number" step="0.1" value={position.z} onChange={e => setPosition({...position, z: parseFloat(e.target.value) || 0})} className="dt-input" style={{ width: '50px' }} />
                                            </div>
                                        </div>
                                    </div>

                                    <div className="control-item" style={{ marginTop: '12px' }}>
                                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '6px' }}>
                                            <span style={{ fontSize: '11px', fontWeight: 'bold' }}>{t('panels.model_object.rot_setting')}</span>
                                            <button className="joy-btn" style={{ padding: '2px 8px', fontSize: '10px' }} onClick={handleApplyRotation}>{t('panels.model_object.apply')}</button>
                                        </div>
                                        <div className="control-row-grid" style={{ marginTop: 0 }}>
                                            <div className="control-item-inline">
                                                <label>X</label>
                                                <input type="number" step="1" value={rotation.x} onChange={e => setRotation({...rotation, x: parseFloat(e.target.value) || 0})} className="dt-input" style={{ width: '50px' }} />
                                            </div>
                                            <div className="control-item-inline">
                                                <label>Y</label>
                                                <input type="number" step="1" value={rotation.y} onChange={e => setRotation({...rotation, y: parseFloat(e.target.value) || 0})} className="dt-input" style={{ width: '50px' }} />
                                            </div>
                                            <div className="control-item-inline">
                                                <label>Z</label>
                                                <input type="number" step="1" value={rotation.z} onChange={e => setRotation({...rotation, z: parseFloat(e.target.value) || 0})} className="dt-input" style={{ width: '50px' }} />
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            )}
                        </div>
                    )}
                </div>
            )}
            {isCollapsed && <div className="status-info">{t('panels.model_object.description')}</div>}
        </div>
    );
};

export default ModelObjectControlPanel;
