import * as THREE from 'three'
import CameraController from './CameraController'

/**
 * MinimapManager 클래스
 * 메인 씬의 실시간 미니맵 뷰어를 관리합니다.
 * PCDManager와 동일한 전용 패널 시스템(드래그, 리사이즈)을 공유합니다.
 */
export default class MinimapManager {
  constructor(mainScene, mainRenderer, mainCamera, rootContainer, panelContainer, options = {}) {
    this.mainScene = mainScene
    this.mainCamera = mainCamera
    this.rootContainer = rootContainer
    this.panelContainer = panelContainer // Legacy compatibility

    // 상태 변수
    this.modelList = null
    this.isHidden = true
    this.trackObjInfo = { object: null, forward: null, offset: null, isTracking: false }

    // 옵션 초기화
    this.options = {
      enabled: options.enabled ?? true,
      backgroundColor: options.backgroundColor ?? 0x111111,
      cameraDistance: options.cameraDistance ?? 10,
      ...options
    }

    // 1. 패널 메인 컨테이너 생성 (PCD 사양 일치)
    this.container = document.createElement('div')
    this.container.id = 'minimap-panel-container'
    Object.assign(this.container.style, {
      position: 'absolute',
      bottom: '20px',
      right: '20px', // 초기 위치 동일하게
      width: '450px',
      height: '400px',
      display: 'none', // 초기 은닉
      flexDirection: 'column',
      pointerEvents: 'auto',
      zIndex: '1000',
      backgroundColor: 'rgba(20, 20, 20, 0.95)',
      borderRadius: '12px',
      border: '1px solid rgba(255, 255, 255, 0.15)',
      boxShadow: '0 8px 32px rgba(0, 0, 0, 0.5)',
      overflow: 'hidden',
      resize: 'both',
      minWidth: '300px',
      minHeight: '250px'
    })
    this.rootContainer.appendChild(this.container)

    // 2. 드래그용 헤더 생성
    this._setupHeader()

    // 3. 렌더링 구역 (Canvas)
    this.canvasContainer = document.createElement('div')
    Object.assign(this.canvasContainer.style, {
      flex: '1',
      position: 'relative',
      overflow: 'hidden'
    })
    this.container.appendChild(this.canvasContainer)

    // 4. 미니맵 전용 렌더러 초기화
    this.renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true })
    this.renderer.setPixelRatio(window.devicePixelRatio)
    this.renderer.setClearColor(this.options.backgroundColor, 1)
    this.canvasContainer.appendChild(this.renderer.domElement)

    // 5. 미니맵 전용 카메라 및 컨트롤러
    this.camCtrl = new CameraController(this.canvasContainer, this.mainScene, this.renderer, {
      minPolarAngle: -Math.PI,
      maxPolarAngle: Math.PI
    })

    // 6. 우측 조향 버튼 패널
    this._setupButtonPanel()

    // 7. 리사이즈 옵저버
    this._setupResizeObserver()

    // 8. 드래그 이벤트 등록
    this._setupDragging()

    // 9. 토글 버튼 (대시보드 상단용)
    this._setupToggleButton()
  }

  _setupHeader() {
    this.header = document.createElement('div')
    this.header.innerHTML = `
      <span style="display:flex; align-items:center; gap:8px;">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polygon points="1 6 1 22 8 18 16 22 23 18 23 2 16 6 8 2 1 6"></polygon><line x1="8" y1="2" x2="8" y2="18"></line><line x1="16" y1="6" x2="16" y2="22"></line></svg>
        <span id="minimap-header-title">MINIMAP VIEWER</span>
      </span>
    `
    Object.assign(this.header.style, {
      padding: '0 15px',
      height: '32px',
      background: 'rgba(40, 40, 40, 0.9)',
      color: '#eee',
      display: 'flex',
      alignItems: 'center',
      fontSize: '12px',
      fontWeight: '600',
      letterSpacing: '0.5px',
      textTransform: 'uppercase',
      borderBottom: '1px solid rgba(255, 255, 255, 0.1)',
      zIndex: '10',
      cursor: 'move',
      userSelect: 'none'
    })
    this.container.appendChild(this.header)
  }

  _setupButtonPanel() {
    this.rightButtonPanel = document.createElement('div')
    Object.assign(this.rightButtonPanel.style, {
      position: 'absolute',
      top: '45px',
      right: '12px',
      display: 'flex',
      flexDirection: 'column',
      gap: '8px',
      zIndex: '2002'
    })
    this.container.appendChild(this.rightButtonPanel)

    const presets = [
      { icon: '○', label: 'Default', action: () => this._setCamPosDef() },
      { icon: '↘', label: 'View 2', action: () => this._setCamPosFromModel({ modelId: 'ABB#2', objectName: 'Axis3', forward: new THREE.Vector3(0.7, 0.5, -0.4), offset: 2.7 }) },
      { icon: '↓', label: 'View 3', action: () => this._setCamPosFromModel({ modelId: 'ABB#2', objectName: 'Axis3', forward: new THREE.Vector3(0.1, 0.9, 0.3), offset: 2.6, rot: new THREE.Euler(-1.57, 0, -3.14) }) },
      { icon: '↙', label: 'View 4', action: () => this._setCamPosFromModel({ modelId: 'ABB#2', objectName: 'Axis3', forward: new THREE.Vector3(-0.5, 0.8, -0.2), offset: 2.7, rot: new THREE.Euler(-1.9, -0.4, -2.3) }) },
      { icon: '←', label: 'View 5', action: () => this._setCamPosFromModel({ modelId: 'ABB#2', objectName: 'Axis3', forward: new THREE.Vector3(-1, 0, 0), offset: 3.8, rot: new THREE.Euler(-1.6, -1.4, -1.6) }) },
      { icon: '↯', label: 'Tracking', action: () => this._setCamPosFromModel({ modelId: 'ABB#2', objectName: 'Spark', forward: new THREE.Vector3(0.3, 0.7, -0.6), offset: 0.56, isTracking: true }) }
    ]

    presets.forEach(p => {
      const btn = document.createElement('button')
      btn.innerHTML = p.icon
      btn.title = p.label
      Object.assign(btn.style, {
        width: '36px',
        height: '36px',
        backgroundColor: 'rgba(30, 30, 30, 0.9)',
        color: '#fff',
        border: '1px solid rgba(255, 255, 255, 0.2)',
        borderRadius: '6px',
        cursor: 'pointer',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        transition: 'all 0.2s'
      })
      btn.onmouseenter = () => btn.style.backgroundColor = '#1677ff'
      btn.onmouseleave = () => btn.style.backgroundColor = 'rgba(30, 30, 30, 0.9)'
      btn.onclick = p.action
      this.rightButtonPanel.appendChild(btn)
    })
  }

  _setupResizeObserver() {
    const resizeObserver = new ResizeObserver(() => {
      if (!this.isHidden) this._onResize()
    })
    resizeObserver.observe(this.container)
  }

  _onResize() {
    if (this.renderer && this.canvasContainer) {
      const width = this.canvasContainer.clientWidth
      const height = this.canvasContainer.clientHeight
      if (width > 0 && height > 0) {
        this.renderer.setSize(width, height)
        this.camCtrl?._onResize()
      }
    }
  }

  _setupDragging() {
    let isDragging = false
    let startX, startY, initialX, initialY

    this.header.addEventListener('mousedown', (e) => {
      isDragging = true
      startX = e.clientX
      startY = e.clientY
      initialX = this.container.offsetLeft
      initialY = this.container.offsetTop
      e.preventDefault()
    })

    window.addEventListener('mousemove', (e) => {
      if (!isDragging) return
      const dx = e.clientX - startX
      const dy = e.clientY - startY

      let nextX = initialX + dx
      let nextY = initialY + dy

      // Boundary clamping
      nextX = Math.max(0, Math.min(nextX, window.innerWidth - this.container.offsetWidth))
      nextY = Math.max(0, Math.min(nextY, window.innerHeight - this.container.offsetHeight))

      this.container.style.left = `${nextX}px`
      this.container.style.top = `${nextY}px`
      this.container.style.right = 'auto'
      this.container.style.bottom = 'auto'
    })

    window.addEventListener('mouseup', () => isDragging = false)
  }

  _setupToggleButton() {
    this.toggleButton = document.createElement('button')
    this.toggleButton.title = '미니맵 뷰어'
    Object.assign(this.toggleButton.style, {
      position: 'absolute',
      top: '20px',
      right: '170px',
      width: '40px',
      height: '40px',
      background: 'rgba(30, 30, 30, 0.85)',
      color: '#fff',
      border: '1px solid rgba(255, 255, 255, 0.2)',
      borderRadius: '8px',
      cursor: 'pointer',
      zIndex: '1500', // 패널(1000)보단 높고 헤더(2000)보단 낮게
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      transition: 'all 0.2s'
    })
    this.toggleButton.innerHTML = `<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polygon points="1 6 1 22 8 18 16 22 23 18 23 2 16 6 8 2 1 6"></polygon><line x1="8" y1="2" x2="8" y2="18"></line><line x1="16" y1="6" x2="16" y2="22"></line></svg>`
    this.rootContainer.appendChild(this.toggleButton)
    this.toggleButton.onclick = () => this._setToggleState()
  }

  _setToggleState(forceVisible) {
    const isVisible = forceVisible !== undefined ? forceVisible : (this.container.style.display === 'none' || this.container.style.display === '')

    if (isVisible) {
      this.container.style.display = 'flex'
      this.toggleButton.style.backgroundColor = '#1677ff'
      this.isHidden = false
      setTimeout(() => this._onResize(), 50)
      this._setCamPosDef()
    } else {
      this.container.style.display = 'none'
      this.toggleButton.style.backgroundColor = 'rgba(30, 30, 30, 0.85)'
      this.isHidden = true
    }
  }

  _setCamPosDef() {
    this._setCamPosFromModel({
      modelId: 'ABB#2',
      objectName: 'Axis3',
      forward: new THREE.Vector3(1, 0.5, 0.5),
      offset: 5,
      isTracking: false
    })
  }

  _setCamPosFromModel({ modelId, objectName, forward, offset, rot, isTracking }) {
    if (!this.modelList) return

    // 모델 검색 로직 (Map 기반 최적화 및 Array 하위 호환)
    let model = null
    if (this.modelList instanceof Map) {
      model = this.modelList.get(modelId)
    } else if (Array.isArray(this.modelList)) {
      model = this.modelList.find(m => (m.userData && m.userData.id === modelId) || m.name === modelId)
    }

    if (!model) {
      console.warn(`MinimapManager: 모델을 찾을 수 없습니다. (${modelId})`)
      return
    }
    const object = objectName ? model.getObjectByName(objectName) : model
    if (!object) return

    // 카메라 위치 갱신
    this.trackObjInfo = { object, forward, offset, isTracking }

    // 비추적 모드일 경우 즉시 카메라 포지션 고정
    if (!isTracking && this.camCtrl) {
      const worldPos = new THREE.Vector3()
      object.getWorldPosition(worldPos)
      const camPos = worldPos.clone().add(forward.clone().normalize().multiplyScalar(offset))

      this.camCtrl.setCameraPose(camPos, rot, worldPos)
    }
  }

  renderMinimap(renderer, scene) {
    if (this.isHidden || !this.renderer) return

    if (this.trackObjInfo.isTracking && this.trackObjInfo.object) {
      const { object, forward, offset } = this.trackObjInfo
      const worldPos = new THREE.Vector3()
      object.getWorldPosition(worldPos)

      const camPos = worldPos.clone().add(forward.clone().normalize().multiplyScalar(offset))
      this.camCtrl.camera.position.set(camPos.x, camPos.y, camPos.z)
      this.camCtrl.controls.target.set(worldPos.x, worldPos.y, worldPos.z)
      this.camCtrl.camera.lookAt(worldPos)
    }

    if (this.camCtrl && this.camCtrl.camera) {
      this.renderer.render(scene, this.camCtrl.camera)
    }
  }

  setVisibility(visible) {
    this._setToggleState(visible)
  }

  updateLabels(labels = {}) {
    const titleEl = document.getElementById('minimap-header-title');
    if (titleEl && labels.minimapTitle) {
      titleEl.innerText = labels.minimapTitle;
    }
  }

  dispose() {
    this.isHidden = true

    // 렌더러 해제
    if (this.renderer) {
      this.renderer.dispose()
      if (this.renderer.domElement && this.renderer.domElement.parentNode) {
        this.renderer.domElement.parentNode.removeChild(this.renderer.domElement)
      }
      this.renderer = null
    }

    // 카메라 컨트롤 해제
    if (this.camCtrl) {
      this.camCtrl.dispose()
      this.camCtrl = null
    }

    // 토글 버튼 제거
    if (this.toggleButton && this.toggleButton.parentNode) {
      this.toggleButton.parentNode.removeChild(this.toggleButton)
    }

    // 메인 컨테이너 제거
    if (this.container && this.container.parentNode) {
      this.container.parentNode.removeChild(this.container)
    }
  }

  setModelList(list) {
    this.modelList = list
    this._setCamPosDef()
  }
}
