import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import type EnhancedThreeViewer from '@/platforms/dt-robot/lib/EnhancedThreeViewer';

interface Props {
    viewer: EnhancedThreeViewer | null;
    modelId: string | null;
}

const ModelRenderPanel: React.FC<Props> = ({ viewer, modelId }) => {
    const { t } = useTranslation('dt-robot');
    const [isCollapsed, setIsCollapsed] = useState(true);
    const [options, setOptions] = useState({
        wireframe: false,
        texture: true
    });

    const toggleOption = (option: 'wireframe' | 'texture') => {
        if (!viewer || !modelId) return;
        
        const newValue = !options[option];
        setOptions(prev => ({ ...prev, [option]: newValue }));
        viewer.setModelRenderingOption?.(modelId, option, newValue);
    };

    return (
        <div className="control-section">
            <div className="section-title" onClick={() => setIsCollapsed(!isCollapsed)}>
                <span>{t('panels.model_render.title')}</span>
                <span>{isCollapsed ? '▼' : '▲'}</span>
            </div>

            {!isCollapsed && (
                <div className="control-body">
                    <div className="control-item">
                        <div className="control-row">
                            <label className="control-label" style={{ flex: 1, marginBottom: 0 }}>{t('panels.model_render.texture')}</label>
                            <input
                                type="checkbox"
                                checked={options.texture}
                                onChange={() => toggleOption('texture')}
                                className="dt-switch"
                            />
                        </div>
                    </div>

                    <div className="control-item">
                        <div className="control-row">
                            <label className="control-label" style={{ flex: 1, marginBottom: 0 }}>{t('panels.model_render.wireframe')}</label>
                            <input
                                type="checkbox"
                                checked={options.wireframe}
                                onChange={() => toggleOption('wireframe')}
                                className="dt-switch"
                            />
                        </div>
                    </div>
                </div>
            )}

            {isCollapsed && <div className="status-info">{t('panels.model_render.description')}</div>}
        </div>
    );
};

export default ModelRenderPanel;
