import React from 'react';
import { useTranslation } from 'react-i18next';
import type EnhancedThreeViewer from '@/platforms/dt-robot/lib/EnhancedThreeViewer';
import LightControlPanel from './LightControlPanel';
import CameraControlPanel from './CameraControlPanel';

interface Props {
    viewer: EnhancedThreeViewer | null;
    initialSettings?: any;
}

const EnvironmentPanel: React.FC<Props> = ({ viewer, initialSettings }) => {
    const { t } = useTranslation('dt-robot');
    const [isCollapsed, setIsCollapsed] = React.useState(true);

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
            <LightControlPanel
                viewer={viewer}
                initialOptions={initialSettings?.light}
            />
            <CameraControlPanel
                viewer={viewer}
                initialSettings={initialSettings?.camera}
            />

            <div className="control-section">
                <div className="section-title" onClick={() => setIsCollapsed(!isCollapsed)}>
                    <span>{t('panels.environment.title')}</span>
                    <span>{isCollapsed ? '▼' : '▲'}</span>
                </div>
                {!isCollapsed && (
                    <div className="control-body">
                        <div className="control-item">
                            <div className="control-row">
                                <label className="control-label" style={{ flex: 1, marginBottom: 0 }}>{t('panels.environment.axes_toggle')}</label>
                                <input
                                    type="checkbox"
                                    onChange={(e) => (viewer as any)?.toggleAxesHelper()}
                                    className="dt-switch"
                                />
                            </div>
                        </div>

                        <button
                            className="delete-btn"
                            onClick={() => {
                                if (window.confirm(t('panels.environment.delete_confirm'))) {
                                    (viewer as any)?.loadModelsFromJson([]);
                                }
                            }}
                        >
                            {t('panels.environment.delete_all')}
                        </button>
                    </div>
                )}
                {isCollapsed && <div className="status-info">{t('panels.environment.description')}</div>}
            </div>
        </div>
    );
};

export default EnvironmentPanel;
