// src/strategies/GLTFLoadingStrategy.js
import * as THREE from 'three'
import { GLTFLoader } from 'three/examples/jsm/loaders/GLTFLoader.js'
import { DRACOLoader } from 'three/examples/jsm/loaders/DRACOLoader.js'
import ModelLoadingStrategy from './ModelLoadingStrategy.js'

// 전역 선언
let loader = null
let dracoLoader = null

export default class GLTFLoadingStrategy extends ModelLoadingStrategy {
  constructor() {
    super()
    this.supportedExtensions = ['gltf', 'glb']

    // 전역 loader, dracoLoader 할당
    if (!dracoLoader) {
      dracoLoader = new DRACOLoader()
      dracoLoader.setDecoderPath(`${import.meta.env.BASE_URL}draco/`)
      dracoLoader.setDecoderConfig({ type: 'js' })
    }
    if (!loader) {
      loader = new GLTFLoader()
      loader.setDRACOLoader(dracoLoader)
    }
  }

  async loadModelInstance(viewer, modelData) {
    const modelPath = `${viewer.options.modelFolder}${modelData.path}`

    return new Promise((resolve, reject) => {
      loader.load(
        modelPath,
        (gltf) => {
          const model = gltf.scene
          viewer.scene.add(model)
          const animations = gltf.animations
          const mixer = animations && animations.length > 0 ? new THREE.AnimationMixer(model) : null
          resolve({ model, mixer, animations, controls: null })
        },
        undefined,
        (error) => {
          console.error(`Failed to load GLTF model ${modelPath}:`, error)
          reject(error)
        },
      )
    })
  }

  disposeModel({ model, mixer }) {
    // 1. 모델 전체 순회
    model.traverse((child) => {
      if (child.isMesh) {
        // geometry 해제
        if (child.geometry) {
          child.geometry.dispose()
          child.geometry = null
        }
        // material 및 텍스처 해제
        if (child.material) {
          this.disposeMaterial(child.material)
          child.material = null
        }
        // skinned mesh의 boneTexture 해제
        if (child.skeleton?.boneTexture) {
          child.skeleton.boneTexture.dispose()
          child.skeleton.boneTexture = null
        }
      }
    })

    // 2. 씬에서 제거
    if (model.parent) {
      model.parent.remove(model)
    }

    // 3. 애니메이션 리소스 해제
    if (mixer) {
      mixer.stopAllAction()
      mixer.uncacheRoot(model)
    }

    // 4. 참조 제거
    model.children = []
    model = null

    // 5. 필요 시 dracoLoader 해제 (여러 모델을 계속 로드할 경우 생략 가능)
    if (dracoLoader) {
      dracoLoader.dispose()
      dracoLoader = null
    }

    // 6. 필요 시 loader 해제 (일반적으로 생략 가능)
    loader = null

    // 7. WebGL 컨텍스트 플러시 (optional)
    // requestAnimationFrame(() => { viewer.renderer.context.flush() })
  }

  disposeMaterial(material) {
    if (Array.isArray(material)) {
      material.forEach((m) => this.disposeSingleMaterial(m))
    } else {
      this.disposeSingleMaterial(material)
    }
  }

  disposeSingleMaterial(material) {
    for (const key in material) {
      const value = material[key]
      if (value && value.isTexture) {
        value.dispose()
        material[key] = null
      }
    }
    material.dispose()
  }
}
