import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import type EnhancedThreeViewer from '@/platforms/dt-robot/lib/EnhancedThreeViewer';

interface Props {
    viewer: EnhancedThreeViewer | null;
    initialSettings?: any;
}

const CameraControlPanel: React.FC<Props> = ({ viewer, initialSettings }) => {
    const { t } = useTranslation('dt-robot');
    const [isCollapsed, setIsCollapsed] = useState(true);
    const [camera, setCamera] = useState({
        position: { x: -13.38, y: 5.44, z: -0.17 },
        controlEnabled: true,
        showPositionInfo: true,
        fov: 60
    });

    useEffect(() => {
        if (initialSettings) {
            setCamera(prev => ({
                ...prev,
                ...initialSettings,
                position: initialSettings.position ? { ...initialSettings.position } : prev.position
            }));
        }
    }, [initialSettings]);

    const handleUpdate = (updates: any) => {
        const next = { ...camera, ...updates };
        setCamera(next);

        if (viewer) {
            if (updates.controlEnabled !== undefined) {
                viewer.setCameraControlEnabled(updates.controlEnabled);
            }
            if (updates.position !== undefined) {
                viewer.setCameraPosition([next.position.x, next.position.y, next.position.z]);
            }
            if (updates.fov !== undefined && viewer.cameraController?.camera) {
                viewer.cameraController.camera.fov = updates.fov;
                viewer.cameraController.camera.updateProjectionMatrix();
            }
        }
    };

    const reset = () => {
        const defaultCam = {
            position: { x: -13.38, y: 5.44, z: -0.17 },
            controlEnabled: true,
            showPositionInfo: true,
            fov: 60
        };
        handleUpdate(defaultCam);
        if (viewer) {
            viewer.cameraController.resetCameraPosition();
        }
    };

    return (
        <div className="control-section">
            <div className="section-title" onClick={() => setIsCollapsed(!isCollapsed)}>
                <span>{t('panels.camera.title')}</span>
                <span>{isCollapsed ? '▼' : '▲'}</span>
            </div>

            {!isCollapsed && (
                <div className="control-body">
                    <div className="control-item">
                        <div className="control-row">
                            <label className="control-label" style={{ flex: 1, marginBottom: 0 }}>{t('panels.camera.enable_control')}</label>
                            <input
                                type="checkbox"
                                checked={camera.controlEnabled}
                                onChange={(e) => handleUpdate({ controlEnabled: e.target.checked })}
                                className="dt-switch"
                            />
                        </div>
                    </div>

                    <div className="control-item">
                        <label className="control-label">{t('panels.camera.position')}</label>
                        <div className="control-row">
                            <input
                                type="number"
                                value={camera.position.x}
                                onChange={(e) => handleUpdate({ position: { ...camera.position, x: parseFloat(e.target.value) || 0 } })}
                                className="dt-input"
                                disabled={!camera.controlEnabled}
                            />
                            <input
                                type="number"
                                value={camera.position.y}
                                onChange={(e) => handleUpdate({ position: { ...camera.position, y: parseFloat(e.target.value) || 0 } })}
                                className="dt-input"
                                disabled={!camera.controlEnabled}
                            />
                            <input
                                type="number"
                                value={camera.position.z}
                                onChange={(e) => handleUpdate({ position: { ...camera.position, z: parseFloat(e.target.value) || 0 } })}
                                className="dt-input"
                                disabled={!camera.controlEnabled}
                            />
                        </div>
                    </div>

                    <div className="control-item" style={{ marginTop: 10 }}>
                        <div className="control-row">
                            <label className="control-label" style={{ flex: 1, marginBottom: 0 }}>{t('panels.camera.show_info')}</label>
                            <input
                                type="checkbox"
                                checked={camera.showPositionInfo}
                                onChange={(e) => handleUpdate({ showPositionInfo: e.target.checked })}
                                className="dt-switch"
                                disabled={!camera.controlEnabled}
                            />
                        </div>
                    </div>

                    <div className="control-item">
                        <label className="control-label">{t('panels.camera.fov')}: {camera.fov || 60}</label>
                        <input
                            type="range"
                            min="30" max="100" step="1"
                            value={camera.fov || 60}
                            onChange={(e) => handleUpdate({ fov: parseFloat(e.target.value) })}
                            className="dt-slider"
                            disabled={!camera.controlEnabled}
                        />
                    </div>

                    <button onClick={reset} className="reset-btn" disabled={!camera.controlEnabled}>{t('panels.camera.reset')}</button>

                </div>
            )}

            {isCollapsed && <div className="status-info">{t('panels.camera.description')}</div>}
        </div>
    );
};

export default CameraControlPanel;
