import * as THREE from 'three'

export default class LightManager {
  constructor(scene, options = {}) {
    this.scene = scene
    this.lights = [] // { light: THREE.Light, type: string, enabled: boolean, prevIntensity: number }
    this.modelSpotlights = new Map() // modelUUID: { light: THREE.SpotLight, enabled: boolean, prevIntensity: number }

    // 초기 조명 추가
    this._addAmbientLight(options?.ambient)
    this._addHemisphereLight(options?.hemisphere)
    this._addDirectionalLight1(options?.directional1)
    this._addDirectionalLight2(options?.directional2)
  }

  // === 조명 타입별 아이콘 Mesh 생성 함수 ===
  _createLightIcon(position, options = {}) {
    const group = new THREE.Group()

    // 1. 태양 원(본체)
    const geometry = new THREE.CircleGeometry(options.radius || 5, options.segments || 16)
    const material = new THREE.MeshBasicMaterial({ color: options.color || 0xffe066 })
    const sunBody = new THREE.Mesh(geometry, material)
    group.add(sunBody)

    // 2. 빛살(Rays) 선 추가
    const rayCount = options.rayCount || 12
    const rayLength = options.rayLength || 9
    const rayColor = options.rayColor || 0xffe066

    for (let i = 0; i < rayCount; i++) {
      const angle = (i / rayCount) * Math.PI * 2
      const inner = new THREE.Vector3(
        Math.cos(angle) * (options.radius || 5),
        Math.sin(angle) * (options.radius || 5),
        0.1, // 살짝 앞으로 빼서 겹침 방지
      )
      const outer = new THREE.Vector3(Math.cos(angle) * rayLength, Math.sin(angle) * rayLength, 0.1)
      const points = [inner, outer]
      const rayGeometry = new THREE.BufferGeometry().setFromPoints(points)
      const rayMaterial = new THREE.LineBasicMaterial({ color: rayColor, linewidth: 2 })
      const line = new THREE.Line(rayGeometry, rayMaterial)
      group.add(line)
    }

    group.position.copy(position)
    return group
  }

  // === 조명 아이콘 구 생성 함수 ===
  _createIconSphere(position, options = {}) {
    let mesh = null
    // 구(점광원, 앰비언트, 헤미스피어)
    const geometry = new THREE.SphereGeometry(1, 16, 16)
    const material = new THREE.MeshBasicMaterial({
      color: options.color || 0xffffff,
      wireframe: true,
    })
    mesh = new THREE.Mesh(geometry, material)

    if (mesh) {
      mesh.position.copy(position)
      mesh.renderOrder = 999 // 항상 위에 그리기
      mesh.visible = options?.visible
      mesh.frustumCulled = false
      //mesh.visible = false
    }
    return mesh
  }

  _addAmbientLight(opt) {
    const light = new THREE.AmbientLight(opt?.color || 0xffffff, opt?.intensity || 0.4)
    this.scene.add(light)

    const iconMesh = this._createIconSphere(new THREE.Vector3(0, 0, 0), { visible: false })
    this.scene.add(iconMesh)
    this.lights.push({
      light: light,
      type: 'AmbientLight',
      enabled: opt?.enabled ?? true,
      prevIntensity: opt?.intensity || 0.4,
      iconMesh,
    })
  }

  _addHemisphereLight(opt) {
    const light = new THREE.HemisphereLight(
      opt?.color || 0xffffff,
      opt?.groundColor || 0x444444,
      opt?.intensity || 0.4,
    )
    light.position.set(opt?.position[0] || 0, opt?.position[1] || 200, opt?.position[2] || 0)
    this.scene.add(light)
    const iconMesh = this._createIconSphere(light.position, { visible: false })
    this.scene.add(iconMesh)
    this.lights.push({
      light: light,
      type: 'HemisphereLight',
      enabled: opt?.enabled ?? true,
      prevIntensity: opt?.intensity || 0.4,
      iconMesh,
    })
  }

  _addDirectionalLight1(opt) {
    const light = new THREE.DirectionalLight(opt?.color || 0xffffff, opt?.intensity || 1.0)
    light.position.set(opt?.position[0] || 100, opt?.position[1] || 100, opt?.position[2] || 100)
    light.castShadow = true
    light.shadow.mapSize.width = 2048
    light.shadow.mapSize.height = 2048
    light.shadow.camera.near = 0.5
    light.shadow.camera.far = 500
    light.shadow.camera.left = -50
    light.shadow.camera.right = 50
    light.shadow.camera.top = 50
    light.shadow.camera.bottom = -50
    this.scene.add(light)
    const iconMesh = this._createLightIcon(light.position)
    this.scene.add(iconMesh)
    this.lights.push({
      light: light,
      type: 'DirectionalLight1',
      enabled: opt?.enabled ?? true,
      prevIntensity: opt?.intensity || 1.0,
      //iconMesh,
    })
  }

  _addDirectionalLight2(opt) {
    const light = new THREE.DirectionalLight(opt?.color || 0xffffff, opt?.intensity || 0.5)
    light.position.set(opt?.position[0] || -100, opt?.position[1] || 100, opt?.position[2] || -100)
    this.scene.add(light)
    const iconMesh = this._createLightIcon(light.position)
    this.scene.add(iconMesh)
    this.lights.push({
      light: light,
      type: 'DirectionalLight2',
      enabled: opt?.enabled ?? true,
      prevIntensity: opt?.intensity || 0.5,
      //iconMesh,
    })
  }

  // === 개별 조명 On/Off ===
  setLightEnabled(index, enabled) {
    const entry = this.lights[index]
    if (!entry) return
    if (entry.enabled === enabled) return
    if (enabled) {
      entry.light.intensity = entry.prevIntensity
      entry.enabled = true
    } else {
      entry.prevIntensity = entry.light.intensity
      entry.light.intensity = 0
      entry.enabled = false
    }
  }

  isLightEnabled(index) {
    const entry = this.lights[index]
    return entry ? entry.enabled : undefined
  }

  // === 전체 조명 일괄 On/Off ===
  setAllLightsEnabled(enabled) {
    this.lights.forEach((_, i) => this.setLightEnabled(i, enabled))
  }

  // === 모델별 스포트라이트 추가 및 On/Off ===
  addModelSpotlight(model, options = {}) {
    const config = {
      color: options?.color || 0xffffff,
      intensity: options?.intensity || 0.8,
      distance: options?.distance || 100,
      angle: options?.angle || Math.PI / 4,
      penumbra: options?.penumbra || 0.5,
      decay: options?.decay || 1,
      ...options,
    }
    const spotlight = new THREE.SpotLight(
      config.color,
      config.intensity,
      config.distance,
      config.angle,
      config.penumbra,
      config.decay,
    )
    // 모델 바운딩 박스 기준 위치
    const box = new THREE.Box3().setFromObject(model)
    const center = box.getCenter(new THREE.Vector3())
    spotlight.position.copy(center).add(new THREE.Vector3(0, 50, 0))
    spotlight.target.position.copy(center)
    this.scene.add(spotlight)
    this.scene.add(spotlight.target)
    spotlight.castShadow = true
    this.modelSpotlights.set(model.uuid, {
      light: spotlight,
      enabled: true,
      prevIntensity: config.intensity,
    })
  }

  setModelSpotlightEnabled(modelUUID, enabled) {
    const entry = this.modelSpotlights.get(modelUUID)
    if (!entry) return
    if (entry.enabled === enabled) return
    if (enabled) {
      entry.light.intensity = entry.prevIntensity
      entry.enabled = true
    } else {
      entry.prevIntensity = entry.light.intensity
      entry.light.intensity = 0
      entry.enabled = false
    }
  }

  isModelSpotlightEnabled(modelUUID) {
    const entry = this.modelSpotlights.get(modelUUID)
    return entry ? entry.enabled : undefined
  }

  setAllModelSpotlightsEnabled(enabled) {
    for (const uuid of this.modelSpotlights.keys()) {
      this.setModelSpotlightEnabled(uuid, enabled)
    }
  }

  // === 조명 세기 속성 변경 === type('AmbientLight','HemisphereLight','DirectionalLight' )
  setIntensity(type, intensitys) {
    let find = 0
    this.lights.forEach((entry) => {
      if (entry.type === type) {
        find++
        entry.light.intensity = intensitys.intensity
        if (entry.enabled) entry.prevIntensity = intensitys.intensity
      }
    })
    if (find === 0) console.warn(`set Inensity is warn ${type} is  not Exist`)
  }

  // === 조명 컬러 속성 변경 === type('AmbientLight','HemisphereLight','DirectionalLight' )
  setColor(type, colors) {
    let find = 0
    this.lights.forEach((entry) => {
      if (entry.type === type) {
        find++
        if (colors?.color) entry.light.color.set(colors?.color)
        if (colors?.groundColor) entry.light.groundColor.set(colors?.groundColor)
      }
    })
    if (find === 0) console.warn(`set Color is warn ${type} is not Exist`)
  }

  // === 조명 위치 속성 변경 === type('AmbientLight','HemisphereLight','DirectionalLight' )
  setPosition(type, position) {
    let find = 0
    this.lights.forEach((entry) => {
      if (entry.type === type) {
        find++
        if (position && entry.light.position) {
          entry.light.position.x = position.x
          entry.light.position.y = position.y
          entry.light.position.z = position.z
          // entry.light.position.set(position)
          if (entry.iconMesh) {
            entry.iconMesh.position.copy(entry.light.position)
          }
        }
      }
    })
    if (find === 0) console.warn(`set Position is warn ${type} is not Exist`)
  }

  setAllIntensity(intensity) {
    this.lights.forEach((entry) => {
      entry.light.intensity = intensity
      if (entry.enabled) entry.prevIntensity = intensity
    })
  }
  setAllColor(color) {
    this.lights.forEach((entry) => {
      if (entry.light.color) entry.light.color = color
      if (entry.light.groundColor) entry.light.groundColor = color
    })
  }

  // === 모델별 스포트라이트 정보 조회 ===
  getModelSpotlightInfo() {
    const spotlightInfo = []
    this.modelSpotlights.forEach((entry, modelUUID) => {
      const light = entry.light
      spotlightInfo.push({
        modelUUID: modelUUID,
        type: 'SpotLight',
        color: light.color.getHex(),
        intensity: light.intensity,
        distance: light.distance,
        angle: light.angle,
        penumbra: light.penumbra,
        decay: light.decay,
        position: light.position.clone(),
        targetPosition: light.target.position.clone(),
        shadowEnabled: light.castShadow,
        enabled: entry.enabled,
      })
    })
    return spotlightInfo
  }

  // === 메모리 해제 ===
  dispose() {
    // 기본 조명 제거
    this.lights.forEach((entry) => {
      this.scene.remove(entry.iconMesh) // 아이콘 제거 추가
      if (entry.iconMesh?.dispose) entry.iconMesh.dispose()
      this.scene.remove(entry.light)
      if (entry.light.dispose) entry.light.dispose()
      if (entry.light.target) this.scene.remove(entry.light.target)
    })
    // 모델별 스포트라이트 제거
    this.modelSpotlights.forEach((entry) => {
      this.scene.remove(entry.light)
      if (entry.light.dispose) entry.light.dispose()
      if (entry.light.target) this.scene.remove(entry.light.target)
    })
    this.lights = []
    this.modelSpotlights.clear()
  }
}
