// src/core/CameraController.js
import * as THREE from 'three'
import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls.js'
import * as TWEEN from '@tweenjs/tween.js' // TWEEN 임포트 추가

/**
 * Three.js 씬의 카메라와 OrbitControls를 관리하는 클래스입니다.
 * 카메라 위치, 타겟, 줌 및 부드러운 이동 애니메이션을 제어합니다.
 */
export default class CameraController {
  /**
   * 카메라 위치, 각도, 타겟을 한 번에 설정합니다.
   * @param {THREE.Vector3} position - 카메라 위치
   * @param {THREE.Euler} rotation - 카메라 각도 (Euler)
   * @param {THREE.Vector3} target - 카메라 타겟 위치
   */
  setCameraPose(position, rotation, target) {
    if (position) this.camera.position.copy(position)
    if (rotation) this.camera.rotation.copy(rotation)
    if (target) this.controls.target.copy(target)
    this.camera.lookAt(this.controls.target)
    this.controls.update()
  }

  /**
   * x, y, z 값만 받아 카메라 위치, 각도, 타겟을 한 번에 설정합니다.
   * @param {{x:number, y:number, z:number}} pos - 카메라 위치
   * @param {{x:number, y:number, z:number}} rot - 카메라 각도
   * @param {{x:number, y:number, z:number}} target - 타겟 위치
   */
  setCameraPoseSimple(pos, rot, target) {
    const position = new THREE.Vector3(pos.x, pos.y, pos.z)
    const rotation = new THREE.Euler(rot.x, rot.y, rot.z)
    const targetVec = new THREE.Vector3(target.x, target.y, target.z)
    this.setCameraPose(position, rotation, targetVec)
  }

  /**
   * CameraController의 인스턴스를 생성합니다.
   * @param {HTMLElement} container 뷰어가 렌더링될 DOM 요소 (카메라 종횡비 계산에 사용)
   * @param {THREE.Scene} scene (선택 사항) 카메라가 연결될 씬
   * @param {THREE.WebGLRenderer} renderer 카메라 컨트롤이 상호작용할 렌더러
   */
  constructor(container, scene, renderer, options = {}) {
    this.container = container
    this.scene = scene // 현재는 사용되지 않지만, 나중에 카메라가 씬의 특정 객체를 추적하는 등의 기능에 활용될 수 있습니다.

    // 카메라 설정
    this.camera = new THREE.PerspectiveCamera(
      60, // 시야각 (FOV)
      container.clientWidth / container.clientHeight, // 종횡비
      options?.minDistance ?? 0.1, // Near 클리핑 평면
      options?.maxDistance ?? 1000, // Far 클리핑 평면 (모델이 멀리 있어도 잘 보이도록 충분히 크게 설정)
    )
    // **카메라의 초기 위치와 타겟을 속성으로 저장**
    this.initialCameraPosition = new THREE.Vector3(0, 5, 10)
    this.initialTargetPosition = new THREE.Vector3(0, 0, 0)

    this.camera.position.copy(this.initialCameraPosition) // 카메라 초기 위치
    this.camera.lookAt(this.initialTargetPosition) // 카메라 초기 타겟

    // OrbitControls 설정
    this.controls = new OrbitControls(this.camera, renderer.domElement)
    this.controls.enableDamping = true // 부드러운 움직임 활성화
    this.controls.dampingFactor = 0.05 // 감쇠 계수
    this.controls.zoomSpeed = 0.5 // 줌 속도

    this.controls.minPolarAngle = options?.minPolarAngle ?? 0 // 최소 수직 각도 (0 = 정면)
    this.controls.maxPolarAngle = options?.maxPolarAngle ?? Math.PI / 2 // 최대 수직 각도 (π/2 = 위에서 내려다봄)
    options?.minAzimuthAngle ??
      (this.controls.minAzimuthAngle = options?.minAzimuthAngle ?? -Math.PI) // 최소 수평 각도 (-π = 왼쪽)
    options?.maxAzimuthAngle ??
      (this.controls.maxAzimuthAngle = options?.maxAzimuthAngle ?? Math.PI) // 최대 수평 각도 (π = 오른쪽)
    this.controls.minDistance = options?.minDistance ?? 0 // 최소 줌 거리
    this.controls.maxDistance = options?.maxDistance ?? 1000 // 최대 줌 거리

    this.controls.target.copy(this.initialTargetPosition) // 컨트롤 타겟도 초기 타겟으로 설정
    this.controls.enabled = options?.enableControl ?? true // 기본적으로 컨트롤 활성화

    // 줌/카메라 변경 시 호출될 콜백 함수
    this.onZoom = null // 사용되지 않는 onZoom 대신 onCameraChange로 통일하는 것이 좋습니다.
    this.onCameraChange = null // EnhancedThreeViewer에서 사용하는 콜백

    this.controls.addEventListener('change', () => {
      // 카메라 위치나 타겟이 변경될 때마다 콜백 호출
      if (this.onCameraChange) {
        // onZoom 대신 onCameraChange 사용 권장
        this.onCameraChange(
          this.camera.position.clone(),
          this.camera.rotation.clone(),
          this.controls.target.clone(),
        )
      }
    })

    // 리사이즈 이벤트 핸들러 바인딩
    this._resizeHandler = this._onResize.bind(this)
    window.addEventListener('resize', this._resizeHandler, { passive: true })

    // 슬로우 무빙(Smooth Camera Movement) 관련 변수
    this.moving = false // 카메라 이동 중 여부
    this.startPosition = new THREE.Vector3() // 이동 시작 시 카메라 위치
    this.startTarget = new THREE.Vector3() // 이동 시작 시 컨트롤 타겟
    this.targetPosition = new THREE.Vector3() // 이동 목표 카메라 위치
    this.targetLookAt = new THREE.Vector3() // 이동 목표 컨트롤 타겟
    this.moveProgress = 0 // 이동 진행도 (0.0 ~ 1.0)
    this.moveDuration = 1.5 // 이동 애니메이션 지속 시간 (초)

    // 메모리 캐시: 불필요한 Vector3 인스턴스 생성을 피하기 위해 재사용할 Vector3 객체들
    this._tempDir = new THREE.Vector3()
    this._tempNewPos = new THREE.Vector3()
    this._tempNewTarget = new THREE.Vector3()

    this.trackingEnabled = false
    this.isOriginTracking = false
    this.currentTrackTarget = null
    this.trackingLerpAlpha = 0.2
    this.originTrackingSpeed = 0.1
    this.fixedDistance = 10
    this.pos = { origin: new THREE.Vector3(0, 0, 0), world: new THREE.Vector3() }
  }

  /**
   * 카메라와 타겟 간의 거리를 설정하여 줌 레벨을 조절합니다.
   * @param {number} distance 설정할 거리
   */
  setDistance(distance) {
    this._tempDir.subVectors(this.camera.position, this.controls.target).normalize()
    this.camera.position.copy(
      this.controls.target.clone().add(this._tempDir.multiplyScalar(distance)),
    )

    this.camera.far = distance * 10
    this.camera.updateProjectionMatrix()
    this.controls.update()
  }

  /**
   * 카메라가 바라볼 타겟 지점을 설정합니다.
   * @param {THREE.Vector3} vec3 새로운 타겟 위치
   */
  setTarget(vec3) {
    this.controls.target.copy(vec3) // 컨트롤 타겟 업데이트
    this.controls.update() // 컨트롤 업데이트
  }

  /**
   * 현재 카메라의 타겟 위치를 반환합니다.
   * @returns {THREE.Vector3} 카메라 타겟의 복사본
   */
  get target() {
    return this.controls.target.clone()
  }

  /**
   * 현재 카메라의 위치를 반환합니다.
   * @returns {THREE.Vector3} 카메라 위치의 복사본
   */
  get position() {
    return this.camera.position.clone()
  }

  /**
   * 카메라를 지정된 위치와 타겟으로 부드럽게 이동시킵니다.
   * @param {THREE.Vector3} position 카메라의 목표 위치
   * @param {THREE.Vector3} target 카메라가 바라볼 목표 지점
   * @param {number} duration 애니메이션 지속 시간 (밀리초)
   */
  moveTo(position, target, duration = 1000, onComplete = null) {
    new TWEEN.Tween(this.camera.position)
      .to(position, duration)
      .easing(TWEEN.Easing.Quadratic.Out)
      .start()

    new TWEEN.Tween(this.controls.target)
      .to(target, duration)
      .easing(TWEEN.Easing.Quadratic.Out)
      .onUpdate(() => {
        this.camera.lookAt(this.controls.target)
        this.controls.update()
      })
      .onComplete(() => {
        if (onComplete) onComplete()
      })
      .start()
  }

  /**
   * 카메라를 초기 위치와 타겟으로 재설정합니다.
   * OrbitControls의 `.reset()` 메서드를 활용하거나, 초기 위치로 `.moveTo()`를 호출합니다.
   */
  resetCameraPosition() {
    // 가장 간단하고 권장되는 방법은 OrbitControls의 reset() 메서드를 사용하는 것입니다.
    // 이는 컨트롤러의 초기 상태로 카메라와 타겟을 되돌립니다.
    this.controls.reset()

    // 만약 애니메이션과 함께 초기 위치로 돌아가고 싶다면 moveTo를 사용할 수 있습니다.
    // this.moveTo(this.initialCameraPosition, this.initialTargetPosition);
  }

  /**
   * OrbitControls의 활성화/비활성화 상태를 설정합니다.
   * @param {boolean} enabled 컨트롤 활성화 여부
   */
  setControlsEnabled(enabled) {
    this.controls.enabled = enabled
  }

  /**
   * 특정 객체 추적 시작
   * @param {THREE.Object3D} targetObj - 추적할 3D 객체
   */
  startTracking(targetObj) {
    this.trackingEnabled = true
    this.currentTrackTarget = targetObj
    this.setCameraDistance(this.fixedDistance) // 현재 거리 사용
    this.isOriginTracking = false // 원점 추적 활성화
  }

  /**
   * 객체 추적 정지
   */
  stopTracking() {
    if (this.trackingEnabled === true) {
      this.trackingEnabled = false
      this.currentTrackTarget = null
      this.setCameraDistance(this.fixedDistance) // 현재 거리 사용
      this.isOriginTracking = true // 원점 추적 활성화
    }
  }

  clearTrackingTarget() {
    this.trackingEnabled = false
    this.currentTrackTarget = null
    this.setCameraDistance(this.fixedDistance) // 현재 거리 사용
  }

  /**
   * 원점 추적 모드 설정/해제
   * @param {boolean} enable - 추적 활성화 여부
   * @param {boolean} smooth - 부드러운 전환 여부
   */
  setOriginTracking(enable, smooth = true) {
    this.isOriginTracking = enable
    if (enable) {
      if (smooth) {
        this.moveTo(this.camera.position, new THREE.Vector3(0, 0, 0), 1000) // 부드럽게 원점으로 이동
      } else {
        this.controls.target.set(0, 0, 0)
        this.controls.update()
      }
    }
  }

  /**
   * 현재 카메라-타겟 거리 계산
   * @returns {number} 현재 거리
   */
  getCurrentDistance() {
    return 10 //this.camera.position.distanceTo(this.controls.target)
  }

  /**
   * 지정된 거리로 카메라 위치 조정
   * @param {number} distance
   */
  setCameraDistance(distance, polarAngle = 45, azimuthAngle = 45) {
    // 1. 현재 타겟 위치 가져오기
    const targetPos = this.currentTrackTarget
      ? this.currentTrackTarget.position
      : this.controls.target.clone()

    // 2. 구면 좌표계 설정
    const spherical = new THREE.Spherical().setFromVector3(
      new THREE.Vector3().subVectors(this.camera.position, targetPos),
    )

    // 3. 각도 및 거리 업데이트
    spherical.radius = distance
    spherical.theta = THREE.MathUtils.degToRad(polarAngle) // 수직각 (0 = 정면, π/2 = 위에서 내려봄)
    spherical.phi = THREE.MathUtils.degToRad(azimuthAngle) // 수평각 (0 = 정면, π/2 = 오른쪽 측면)

    // 4. 새 카메라 위치 계산
    const newPosition = new THREE.Vector3().setFromSpherical(spherical).add(targetPos)

    // 5. 카메라 위치 업데이트
    this.camera.position.copy(newPosition)
    this.camera.lookAt(targetPos) // 각도 강제 설정
    this.controls.update() // 컨트롤 동기화
  }

  //
  getCamPos(object, pos, rot, target) {
    //console.debug('trackObjInfo', this.trackObjInfo)
    if (object) {
      const worldPos = new THREE.Vector3()
      object.getWorldPosition(worldPos)

      // 현재 카메라 위치
      const cameraPos = this.camera.position.clone()

      // 카메라 위치와 오브젝트 위치 차이 벡터
      const diff = cameraPos.clone().sub(worldPos)

      // forward 벡터: diff를 정규화
      const forward = diff.clone().normalize()

      // offset: diff의 길이, 부호는 diff와 forward의 내적(dot)로 결정
      const offset = diff.length() * Math.sign(diff.dot(forward))

      // 디버깅 출력
      console.log('카메라 forward:', forward)
      console.log('카메라 offset:', offset)
      console.log('카메라 회전:', rot)
    }
  }

  setCamPos(object, forward, offset, rot) {
    // 오브젝트의 월드 위치
    const worldPos = new THREE.Vector3()
    object.getWorldPosition(worldPos)

    // forward는 이미 월드 방향이므로 쿼터니언을 적용하지 않음
    const normForward = forward.clone().normalize()

    // 오브젝트의 forward 방향 (Three.js에서 -Z가 forward)
    // forward.applyQuaternion(object.getWorldQuaternion(new THREE.Quaternion()))

    // 카메라를 오브젝트 뒤쪽에서 바라보게 배치 (뒤쪽으로 3만큼 떨어뜨림, 필요시 조정)
    const cameraPos = worldPos.clone().add(normForward.clone().multiplyScalar(offset))

    // 카메라 위치와 target이 다르게 설정되어야 객체를 바라봄
    this.camera.position.set(cameraPos.x, cameraPos.y, cameraPos.z)
    this.controls.target.set(worldPos.x, worldPos.y, worldPos.z)
    this.camera.lookAt(worldPos)

    // Euler 값이 있으면 카메라 회전 적용
    if (rot) this.camera.rotation.copy(rot) // 또는 쿼터니언으로 적용: this.camera.quaternion.setFromEuler(rot)

    return normForward
  }

  /**
   * 카메라 컨트롤러의 상태를 업데이트합니다.
   * 애니메이션 루프에서 매 프레임 호출되어야 합니다.
   * @param {number} [delta=0.016] 마지막 업데이트 이후 경과 시간 (초). 기본값은 약 60fps에 해당.
   */
  update(delta = 0.016) {
    if (this.trackingEnabled && this.currentTrackTarget) {
      // 객체 추적 로직
      this.currentTrackTarget.getWorldPosition(this.pos.world)
      this.controls.target.lerp(this.pos.world, this.trackingLerpAlpha)
      this.camera.lookAt(this.controls.target)
      //this.setCameraDistance(this.fixedDistance)
    } else if (this.isOriginTracking) {
      this.controls.target.lerp(this.pos.origin, this.originTrackingSpeed)
      this.camera.lookAt(this.controls.target)
      if (this.controls.target.distanceTo(origin) < 0.01) this.isOriginTracking = false // 목표에 도달하면 추적 중지
    }

    this.controls.update() // OrbitControls 업데이트 (감쇠 및 기타 상호작용 처리)
    TWEEN.update() // TWEEN 애니메이션 업데이트

    // moveTo 함수에서 TWEEN을 사용하므로, 이 부분이 불필요할 수 있습니다.
    // TWEEN이 이미 카메라 위치와 타겟을 직접 업데이트하고 OrbitControls.update()가 이를 처리하기 때문입니다.
    // 따라서, 이 `if (this.moving)` 블록은 TWEEN을 사용하지 않는 수동 보간 시에만 유효합니다.
    // 현재 TWEEN을 사용하므로, 이 코드는 제거하거나 주석 처리해도 무방합니다.
    //if (this.moving) {
    //  this.moveProgress += delta / this.moveDuration
    //  const t = Math.min(this.moveProgress, 1) // 진행도를 1.0으로 클램프
    //  const ease = t * t * (3 - 2 * t) // easeInOut 큐빅 함수 (부드러운 시작 및 끝)
    //
    //  this._tempNewPos.lerpVectors(this.startPosition, this.targetPosition, ease)
    //  this._tempNewTarget.lerpVectors(this.startTarget, this.targetLookAt, ease)
    //
    //  this.camera.position.copy(this._tempNewPos)
    //  this.controls.target.copy(this._tempNewTarget)
    //  this.controls.update() // 카메라가 직접 이동했으므로 컨트롤 업데이트 필요
    //
    //  if (t >= 1) {
    //    this.moving = false
    //  }
    //}
  }

  /**
   * 창 크기 변경 시 카메라의 종횡비와 투영 행렬을 업데이트합니다.
   * @private
   */
  _onResize() {
    this.camera.aspect = this.container.clientWidth / this.container.clientHeight
    this.camera.updateProjectionMatrix()
    this.controls.update() // 컨트롤도 업데이트하여 렌더링 영역에 맞게 조정
  }

  /**
   * CameraController의 모든 리소스를 해제합니다.
   * 뷰어가 종료될 때 호출되어야 합니다.
   */
  dispose() {
    // Dispose OrbitControls
    this.controls.dispose()

    // Remove resize event listener
    window.removeEventListener('resize', this._resizeHandler)

    // Clear temporary variables
    this._tempDir = null
    this._tempNewPos = null
    this._tempNewTarget = null

    // Clear tracking-related references
    this.currentTrackTarget = null
    this.trackingEnabled = false
    this.isOriginTracking = false

    // Log disposal for debugging
    console.log('CameraController: 모든 리소스를 해제했습니다.')
  }
}
