// src/strategies/DefaultInteractionStrategy.js
import * as THREE from 'three'
import ModelInteractionStrategy from './ModelInteractionStrategy.js'

/**
 * 기본 모델 상호작용 전략입니다.
 * - 클릭 시 모델 선택 및 해제
 * - 선택된 모델 외의 객체 투명도 조절
 * - 선택된 모델 색상 변경 및 카메라 이동
 * - 선택된 모델 자동 회전
 */
export default class DefaultInteractionStrategy extends ModelInteractionStrategy {
  /**
   * @param {number} [nonSelectedOpacity=0.3] 선택되지 않은 모델의 투명도
   */
  constructor(nonSelectedOpacity = 0.3) {
    super()
    this.nonSelectedOpacity = nonSelectedOpacity
    this.originalMaterials = new Map() // 각 메쉬의 원본 재질 설정을 저장 (투명도 복원용)
    this.originalColors = new Map() // 각 메쉬의 원본 색상을 저장 (색상 변경 복원용)
    this.isSelectEffect = false
  }

  /**
   * 클릭 이벤트를 처리하여 모델 선택/해제 로직을 수행합니다.
   * @param {EnhancedThreeViewer} viewer 뷰어 인스턴스
   * @param {Array<THREE.Intersection>} intersects Raycaster가 감지한 교차 객체 배열
   */
  handleModelClick(viewer, intersects) {
    let newSelectedModel = null
    if (intersects.length > 0) {
      newSelectedModel = this._getRootModel(viewer, intersects[0].object)
      if (newSelectedModel && newSelectedModel.userData.selectable === false) {
        // console.debug(`Model ${newSelectedModel.userData.id} is not selectable. Ignoring click.`)
        return // 선택 불가능한 모델은 클릭 이벤트를 무시합니다.
      }
    }

    if (!newSelectedModel) {
      //this.unselectModel(viewer) // 배경 클릭 시 선택 해제
      return
    }

    if (viewer.selectedModel && viewer.selectedModel === newSelectedModel) {
      this.unselectModel(viewer) // 이미 선택된 모델을 다시 클릭한 경우 => 선택 해제
      return
    }

    if (viewer.selectedModel) {
      this.unselectModel(viewer) // 이전에 선택된 모델이 있다면 해제
    }
    // 선택된 모델이 없을 경우 (즉, 처음 선택되거나 모든 선택 해제 후 첫 선택) 현재 카메라 위치와 타겟을 원본으로 저장
    if (!viewer.originalCameraPosition || !viewer.originalCameraTarget) {
      viewer.originalCameraPosition = viewer.cameraController.position.clone() // 현재 위치를 복제하여 저장
      viewer.originalCameraTarget = viewer.cameraController.target.clone() // 현재 타겟을 복제하여 저장
    }
    this.selectModel(viewer, newSelectedModel)
  }

  /**
   * Raycaster에 의해 교차된 Three.js 객체로부터 최상위 모델 객체를 찾습니다.
   * (여기서 최상위 모델은 `viewer.instances` 맵에 저장된 객체를 의미합니다.)
   * @param {EnhancedThreeViewer} viewer 뷰어 인스턴스
   * @param {THREE.Object3D} obj 교차된 객체
   * @returns {THREE.Object3D|null} 최상위 모델 객체 또는 null
   */
  _getRootModel(viewer, obj) {
    let currentObject = obj
    while (currentObject) {
      if (currentObject.userData && currentObject.userData.id) {
        return viewer.instances.get(currentObject.userData.id) //  viewer.instances.find((e) => e.id === currentObject.userData.id)
      }
      currentObject = currentObject.parent
    }
    return null
  }

  /**
   * 모델을 선택하고 시각적/기능적 효과를 적용합니다.
   * @param {EnhancedThreeViewer} viewer 뷰어 인스턴스
   * @param {THREE.Object3D} obj 선택된 모델 객체
   */
  selectModel(viewer, obj) {
    // console.debug('deault__selectModel', obj)

    // 선택된 모델 외의 모든 모델 투명하게 처리
    viewer.instances.forEach((value, key) => {
      const instance = value
      if (instance === obj) {
        this._setObjectOpacity(instance, 1.0)
      } else if (instance.userData.transparentable !== false) {
        this._setObjectOpacity(instance, this.nonSelectedOpacity)
      } else {
        this._restoreObjectOpacity(instance)
      }
    })
    // 선택된 모델 자식 Mesh 각각에 대해 원래 색상 저장 & 선택 색상 변경
    if (this.isSelectEffect) {
      obj.traverse((child) => {
        if (child.isMesh && child.material) {
          const materials = Array.isArray(child.material) ? child.material : [child.material]
          materials.forEach((mat) => {
            if (!this.originalColors.has(mat)) this.originalColors.set(mat, mat.color.clone()) // 재질별 원본 색상 저장
            mat.color.setHex(0xff0000) // 선택 시 색상 빨강
            mat.needsUpdate = true
          })
        }
      })
    }

    // 카메라 이동
    //const box = new THREE.Box3().setFromObject(obj)
    //const center = box.getCenter(new THREE.Vector3())
    //const size = box.getSize(new THREE.Vector3()).length()
    //const offset = new THREE.Vector3(0, size * 0.8, size * 1.2)
    //const newPos = center.clone().add(offset)
    //viewer.cameraController.moveTo(newPos, center)

    // 회전 활성화
    this._enableRotation(obj)
    //console.log('obj?.userData?.id', obj?.userData?.id)
    viewer.options.onObjectSelect(obj?.userData?.id) // 콜백 호출
  }

  /**
   * 모델의 선택을 해제하고 시각적/기능적 효과를 복원합니다.
   * @param {EnhancedThreeViewer} viewer 뷰어 인스턴스
   */
  unselectModel(viewer) {
    if (!viewer.selectedModel) return
    viewer.instances.forEach((value, key) => this._restoreObjectOpacity(value))

    // 선택 해제 시 색상 복원
    viewer.selectedModel.traverse((child) => {
      if (child.isMesh && child.material) {
        const materials = Array.isArray(child.material) ? child.material : [child.material]
        materials.forEach((mat) => {
          if (this.originalColors.has(mat)) {
            mat.color.copy(this.originalColors.get(mat))
            this.originalColors.delete(mat) // 사용된 원본 색상 정보 삭제
            mat.needsUpdate = true
          }
        })
      }
    })

    // 선택 해제 시 원래 회전 값으로 복귀
    if (viewer.selectedModel.userData.originalRotation) {
      viewer.selectedModel.rotation.copy(viewer.selectedModel.userData.originalRotation)
      delete viewer.selectedModel.userData.originalRotation
    }

    this._disableRotation(viewer.selectedModel) // 회전 비활성화

    // 카메라 원래 위치로 부드럽게 복귀
    if (viewer.originalCameraPosition && viewer.originalCameraTarget) {
      viewer.cameraController.moveTo(viewer.originalCameraPosition, viewer.originalCameraTarget)
      // 원본 카메라 위치 및 타겟 정보는 한 번 사용 후 초기화하여 다음 선택 시 새롭게 저장되도록 합니다.
      viewer.originalCameraPosition = null
      viewer.originalCameraTarget = null
    }

    viewer.options.onObjectSelect(null) // 콜백 호출
    viewer.selectedModel = null
  }

  /**
   * 객체의 투명도를 설정하고 원래 재질 설정을 저장합니다.
   * @private
   * @param {THREE.Object3D} obj 투명도를 설정할 객체
   * @param {number} alpha 설정할 투명도 값 (0.0 ~ 1.0)
   */
  _setObjectOpacity(obj, alpha) {
    obj.traverse((child) => {
      if (child.isMesh) {
        const materials = Array.isArray(child.material) ? child.material : [child.material]
        materials.forEach((mat) => {
          if (!this.originalMaterials.has(mat)) {
            // 재질별 원본 설정 저장
            const originalSettings = {
              transparent: mat.transparent,
              opacity: mat.opacity,
              depthWrite: mat.depthWrite,
              renderOrder: mat.renderOrder,
            }
            this.originalMaterials.set(mat, originalSettings)
          }

          mat.transparent = true
          mat.opacity = alpha
          // 완전히 불투명할 때만 depthWrite를 활성화하여 투명 객체 렌더링 순서 문제 완화
          mat.depthWrite = alpha === 1.0
          mat.needsUpdate = true
        })
      }
    })
  }

  /**
   * 객체의 투명도를 원래 설정으로 복원합니다.
   * @private
   * @param {THREE.Object3D} obj 투명도를 복원할 객체
   */
  _restoreObjectOpacity(obj) {
    obj.traverse((child) => {
      if (child.isMesh) {
        const materials = Array.isArray(child.material) ? child.material : [child.material]
        materials.forEach((mat) => {
          if (this.originalMaterials.has(mat)) {
            const originalSettings = this.originalMaterials.get(mat)
            mat.transparent = originalSettings.transparent
            mat.opacity = originalSettings.opacity
            mat.depthWrite = originalSettings.depthWrite
            mat.renderOrder = originalSettings.renderOrder
            mat.needsUpdate = true
            this.originalMaterials.delete(mat) // 사용된 원본 설정 정보 삭제
          }
        })
      }
    })
  }

  /**
   * 모델의 회전 애니메이션을 활성화합니다.
   * @private
   * @param {THREE.Object3D} obj 회전을 활성화할 모델
   */
  _enableRotation(obj) {
    if (!obj.userData.originalRotation) {
      obj.userData.originalRotation = obj.rotation.clone() // 현재 회전 값 저장
    }
    obj.userData.isRotating = true // 애니메이션 루프에서 확인할 플래그
  }

  /**
   * 모델의 회전 애니메이션을 비활성화합니다.
   * @private
   * @param {THREE.Object3D} obj 회전을 비활성화할 모델
   */
  _disableRotation(obj) {
    obj.userData.isRotating = false
  }

  /**
   * 매 프레임마다 상호작용 로직을 업데이트합니다. (주로 선택된 모델의 자동 회전)
   * @param {EnhancedThreeViewer} viewer 뷰어 인스턴스
   * @param {number} delta 마지막 업데이트 이후 경과 시간 (초)
   */
  update(viewer, delta) {
    // 선택된 모델이 있고, 회전 플래그가 활성화되어 있으며, movable이 false가 아니면 회전
    if (
      viewer.selectedModel &&
      viewer.selectedModel.userData.isRotating &&
      viewer.selectedModel.userData.movable !== false
    ) {
      viewer.selectedModel.rotation.y += delta * 0.5 // Y축으로 초당 0.5 라디안 회전
    }
  }

  /**
   * DefaultInteractionStrategy의 모든 리소스를 해제합니다.
   */
  dispose() {
    this.originalMaterials.clear()
    this.originalColors.clear()
    // console.log('DefaultInteractionStrategy: 모든 리소스를 해제했습니다.')
  }
}
