import React, { useRef, useEffect, useState } from "react";
import { useTranslation } from "react-i18next";
import EnhancedThreeViewer from "@/platforms/dt-robot/lib/EnhancedThreeViewer";
import type { RobotState } from "../../../mockup/robotData";
import ControlPanel from "./ControlPanel/ControlPanel";
import FpsHistoryModal from "./Modal/FpsHistoryModal";
import MqttHistoryModal from "./Modal/MqttHistoryModal";

interface Props {
    robot: RobotState;
}

const RobotViewer: React.FC<Props> = ({ robot }) => {
    const { t, i18n } = useTranslation('dt-robot');
    const containerRef = useRef<HTMLDivElement>(null);
    const viewerRef = useRef<EnhancedThreeViewer | null>(null);
    const [isLoaded, setIsLoaded] = useState(false);
    const [selectedModelId, setSelectedModelId] = useState<string | null>(null);

    // 모달 관리 상태
    const [fpsModalVisible, setFpsModalVisible] = useState(false);
    const [fpsHistoryData, setFpsHistoryData] = useState<any[]>([]);
    const [mqttModalVisible, setMqttModalVisible] = useState(false);
    const [mqttHistoryData, setMqttHistoryData] = useState<any[]>([]);

    // Initial models data based on prev source
    const initialModels = [
        {
            id: 'ABB#2',
            path: 'WeldDT_Rigging_Rv0.1_250807.glb',
            position: [0, 0, 0] as [number, number, number],
            label: 'IRB6700 (Welding Robot)',
            selectable: true,
            transparentable: true,
            movable: true,
        }
    ];

    useEffect(() => {
        if (!containerRef.current) return;

        const viewer = new EnhancedThreeViewer(containerRef.current, {
            modelFolder: `${import.meta.env.BASE_URL}models/`,
            enableEffects: true,
            enableMinimap: true,
            minimapOptions: {
                size: { width: 200, height: 200 },
                cameraDistance: 1000,
                position: 'bottom-right',
            },
            onObjectSelect: (selectedId: string | null) => {
                // console.log('Selected model:', selectedId);
                setSelectedModelId(selectedId);
            },
            onModelPositionUpdate: (modelId: string, pos: number[]) => {
                // console.log(`Model ${modelId} moved to`, pos);
            },
            onViewerReady: () => {
                // setIsLoaded(true) 제거: 모델 로드 완료 시점에 한꺼번에 처리
            }
        });

        viewerRef.current = viewer;

        // Load models
        viewer.loadModelsFromJson(initialModels).then(() => {
            // console.log('All models loaded');
            setIsLoaded(true);
        });

        // 팝업 이벤트 리스너 등록
        const handleFpsPopup = () => {
            if (viewerRef.current) {
                setFpsHistoryData(viewerRef.current.getFpsHistoryData());
                setFpsModalVisible(true);
            }
        };

        const handleMqttPopup = () => {
            if (viewerRef.current) {
                setMqttHistoryData(viewerRef.current.getMqttDataTable());
                setMqttModalVisible(true);
            }
        };

        const container = containerRef.current;
        container?.addEventListener('fpsHistoryPopup' as any, handleFpsPopup);
        container?.addEventListener('mqttDataTablePopup' as any, handleMqttPopup);

        return () => {
            container?.removeEventListener('fpsHistoryPopup' as any, handleFpsPopup);
            container?.removeEventListener('mqttDataTablePopup' as any, handleMqttPopup);
            viewer.dispose();
            viewerRef.current = null;
        };
    }, []);

    // Update robot position when prop changes
    useEffect(() => {
        if (viewerRef.current && isLoaded) {
            viewerRef.current.moveModelTo('ABB#2', [robot.position.x, robot.position.y, robot.position.z]);
        }
    }, [robot.position, isLoaded]);

    // HUD 다국어 연동
    useEffect(() => {
        if (viewerRef.current && isLoaded) {
            viewerRef.current.updateHudLabels({
                fpsPrefix: 'FPS',
                historyLabel: `📑${t('panels.model_pattern.history')}`,
                axisHistory: `📑 ${t('panels.model_pattern.history')}`,
                axisPlaceholder: t('hud.axis_placeholder'),
                axisMonitoringTitle: t('hud.axis_monitoring'),
                voltageTitle: t('hud.voltage_monitoring'),
                voltagePlaceholder: t('hud.voltage_placeholder'),
                voltageChartTitle: t('hud.voltage_chart_title'),
                voltageLabel: t('hud.voltage'),
                currentLabel: t('hud.current')
            });
        }
    }, [i18n.language, isLoaded, t]);

    return (
        <div ref={containerRef} style={{ width: '100%', height: '100%', position: 'relative' }}>
            {!isLoaded && (
                <div style={{ position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)', color: '#fff', zIndex: 10 }}>
                    Loading 3D Digital Twin...
                </div>
            )}
            {isLoaded && (
                <>
                    <ControlPanel
                        viewer={viewerRef.current}
                        models={initialModels}
                        selectedModelId={selectedModelId}
                        onModelSelect={(id) => {
                            setSelectedModelId(id);
                            if (viewerRef.current) viewerRef.current.selectModel(id);
                        }}
                    />
                    {/* 성능 및 데이터 이력 모달군 */}
                    <FpsHistoryModal
                        visible={fpsModalVisible}
                        onClose={() => setFpsModalVisible(false)}
                        data={fpsHistoryData}
                    />
                    <MqttHistoryModal
                        visible={mqttModalVisible}
                        onClose={() => setMqttModalVisible(false)}
                        data={mqttHistoryData}
                    />
                </>
            )}
        </div>
    );
};

export default RobotViewer;
