export default function getData(axis) {
  return {
    title: {
      text: axis,
      show: true,
      left: 'center',
      bottom: '10%',
      textStyle: {
        color: '#ccc',
        fontSize: 12,
        fontWeight: 'normal'
      }
    },
    series: [
      {
        type: 'gauge',
        startAngle: 210,
        endAngle: -30,
        min: -180,
        max: 180,
        radius: '85%',
        center: ['50%', '50%'],
        itemStyle: {
          color: '#1677ff',
          shadowColor: 'rgba(0, 123, 255, 0.5)',
          shadowBlur: 10
        },
        progress: {
          show: true,
          width: 12,
          roundCap: true
        },
        pointer: {
          show: false
        },
        axisLine: {
          roundCap: true,
          lineStyle: {
            width: 12,
            color: [[1, 'rgba(255, 255, 255, 0.1)']]
          }
        },
        axisTick: {
          show: false
        },
        splitLine: {
          show: false
        },
        axisLabel: {
          show: false
        },
        detail: {
          valueAnimation: true,
          offsetCenter: [0, '0%'], // 중앙에 배치
          fontSize: 18,
          fontWeight: 'bold',
          formatter: '{value}°',
          color: '#fff'
        },
        title: {
          show: false // 값과 겹치는 내부 타이틀 숨김
        },
        data: [
          {
            value: 0
          }
        ]
      }
    ]
  }
}
