import React from 'react';
import { Modal, Table, Tag } from 'antd';
import type { ColumnsType } from 'antd/es/table';
import { useTranslation } from 'react-i18next';

interface MqttData {
    timestamp: number;
    topic: string;
    data: any;
}

interface Props {
    visible: boolean;
    onClose: () => void;
    data: MqttData[];
}

const MqttHistoryModal: React.FC<Props> = ({ visible, onClose, data }) => {
    const { t } = useTranslation('dt-robot');
    
    // 모든 유니크한 데이터 키(컬럼) 추출
    const allKeys = Array.from(new Set(data.flatMap(item => Object.keys(item.data))));

    // Ant Design Table 컬럼 설정
    const columns: ColumnsType<MqttData> = [
        {
            title: t('modals.mqtt_history.col_time'),
            dataIndex: 'timestamp',
            key: 'timestamp',
            render: (ts: number) => new Date(ts).toLocaleTimeString(),
            fixed: 'left',
            width: 120,
        },
        {
            title: t('modals.mqtt_history.col_status'),
            key: 'run',
            render: (_: any, record: MqttData) => {
                const run = record.data.run;
                return run ? (
                    <Tag color={run === 'on' ? 'green' : 'red'}>{run.toUpperCase()}</Tag>
                ) : '-';
            },
            width: 90,
        },
        // 주요 축 데이터 컬럼 동적 생성
        ...allKeys.filter(k => k !== 'run' && k !== 'datetime' && k !== 'robot_id').map(key => ({
            title: key,
            dataIndex: ['data', key],
            key,
            width: 90,
            render: (val: any) => (typeof val === 'number' ? val.toFixed(2) : val),
        })),
        {
            title: t('modals.mqtt_history.col_raw'),
            key: 'raw',
            render: (_: any, record: MqttData) => (
                <div style={{ fontSize: '10px', color: '#888', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', maxWidth: '200px' }}>
                    {JSON.stringify(record.data)}
                </div>
            )
        }
    ];

    return (
        <Modal
            title={<span style={{ color: '#fff' }}>{t('modals.mqtt_history.title')}</span>}
            open={visible}
            onCancel={onClose}
            footer={null}
            width={1000}
            centered
            style={{
                backgroundColor: 'var(--ms-color-bg-container, #1f1f1f)',
                borderRadius: '12px',
                border: '1px solid var(--ms-border-color, rgba(255, 255, 255, 0.1))',
                boxShadow: '0 8px 32px rgba(0, 0, 0, 0.5)'
            }}
            styles={{
                mask: { backdropFilter: 'blur(4px)' },
                body: {
                    backgroundColor: 'var(--ms-color-bg-container, #1f1f1f)',
                    padding: '20px',
                    borderRadius: '0 0 12px 12px'
                }
            }}
        >
            <Table
                size="small"
                dataSource={data.slice().reverse()}
                columns={columns}
                pagination={{ pageSize: 10, showSizeChanger: true }}
                rowKey="timestamp"
                scroll={{ x: 800, y: 500 }}
                rowClassName={() => 'dark-row'}
                style={{ backgroundColor: 'transparent' }}
            />
        </Modal>
    );
};

export default MqttHistoryModal;
