import * as echarts from 'echarts'

export default class VoltageChartManager {
  constructor(rootContainer, panelContainer, styles = {}, options = {}) {
    this.rootContainer = rootContainer
    this.panelContainer = panelContainer
    
    this.categories = []
    this.voltageData = []
    this.currentData = []
    this._lastPushedSecond = ''
    this.chart = null
    this.options = null

    this._setupUI()
    this._initDragAndResize()
    
    // 초기에는 숨김 상태로 시작
    this._setToggleState(false)
  }

  _setupUI() {
    this.container = document.createElement('div')
    Object.assign(this.container.style, {
      position: 'relative',
      width: '100%',
      height: '100%',
      display: 'flex',
      flexDirection: 'column',
      overflow: 'hidden',
    })
    this.panelContainer.appendChild(this.container)

    // 1. 헤더 바 생성
    this.header = document.createElement('div')
    this.header.innerHTML = `
      <span style="display:flex; align-items:center; gap:8px;">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z"></path></svg>
        <span id="voltage-header-title">PROCESS VOLTAGE INFO</span>
      </span>
    `
    Object.assign(this.header.style, {
      padding: '0 15px',
      height: '32px',
      display: 'flex',
      alignItems: 'center',
      backgroundColor: 'rgba(40, 40, 40, 0.9)',
      color: '#ffcc00',
      fontSize: '12px',
      fontWeight: '600',
      letterSpacing: '0.5px',
      textTransform: 'uppercase',
      borderBottom: '1px solid rgba(255, 255, 255, 0.1)',
      zIndex: '10',
      cursor: 'move',
      userSelect: 'none'
    })
    this.container.appendChild(this.header)

    // 2. 차트 영역 (Chart Area)
    this.chartArea = document.createElement('div')
    Object.assign(this.chartArea.style, {
      flex: '1',
      width: '100%',
      height: '100%',
      padding: '10px'
    })
    this.container.appendChild(this.chartArea)

    // 3. 토글 버튼 (메인 화면)
    this.toggleButton = document.createElement('button')
    this.toggleButton.title = '공정 전압 정보'
    Object.assign(this.toggleButton.style, {
      position: 'absolute',
      top: '20px',
      right: '120px',
      width: '40px',
      height: '40px',
      background: 'rgba(30, 30, 30, 0.85)',
      color: '#fff',
      border: '1px solid rgba(255, 255, 255, 0.2)',
      borderRadius: '8px',
      cursor: 'pointer',
      zIndex: '1001',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      boxShadow: '0 2px 8px rgba(0, 0, 0, 0.3)',
      transition: 'all 0.2s',
    })
    this.rootContainer.appendChild(this.toggleButton)
    this.toggleButton.addEventListener('click', () => this._setToggleState())

    // 4. Placeholder (기능 안내)
    this.placeholderText = document.createElement('div')
    this.placeholderText.textContent = '공정 정보 제공'
    Object.assign(this.placeholderText.style, {
      position: 'absolute',
      top: '50%',
      left: '50%',
      transform: 'translate(-50%, -50%)',
      color: '#666',
      fontSize: '14px',
      display: 'none',
    })
    this.container.appendChild(this.placeholderText)
  }

  _ensureChartInit() {
    if (this.chart) return true
    if (!this.chartArea || this.chartArea.clientWidth === 0) return false

    this.chart = echarts.init(this.chartArea)

    const defaultOptions = {
      animation: false,
      title: {
        text: 'Voltage/Current',
        left: 'center',
        top: '10px',
        textStyle: { color: '#fff', fontSize: 13 },
      },
      tooltip: {
        trigger: 'axis',
        axisPointer: { type: 'shadow' }
      },
      legend: {
        data: ['Voltage', 'Current'],
        textStyle: { color: '#fff' },
        top: '40px'
      },
      grid: {
        left: '3%',
        right: '4%',
        bottom: '3%',
        top: '80px',
        containLabel: true
      },
      xAxis: {
        type: 'category',
        data: [],
        axisLabel: { color: '#bbb' },
        axisLine: { lineStyle: { color: 'rgba(255,255,255,0.2)' } }
      },
      yAxis: [
        {
          type: 'value',
          name: 'V',
          axisLabel: { color: '#bbb' },
          splitLine: { lineStyle: { color: 'rgba(255,255,255,0.1)' } },
          min: 0,
          max: 300,
        },
        {
          type: 'value',
          name: 'A',
          axisLabel: { color: '#bbb' },
          splitLine: { show: false },
          min: 0,
          max: 15,
        }
      ],
      series: [
        {
          name: 'Voltage',
          type: 'line',
          yAxisIndex: 0,
          smooth: true,
          data: [],
          itemStyle: { color: '#ffcc00' }
        },
        {
          name: 'Current',
          type: 'bar',
          yAxisIndex: 1,
          data: [],
          itemStyle: { color: '#1677ff' }
        },
      ],
    }

    this.options = { ...defaultOptions }
    this.chart.setOption(this.options)
    return true
  }

  _initDragAndResize() {
    this._setupDragging()
    this._setupResizeObserver()
  }

  _setupDragging() {
    let isDragging = false
    let startX, startY, startLeft, startTop

    this.header.addEventListener('mousedown', (e) => {
      if (e.button !== 0) return
      e.preventDefault()
      isDragging = true

      const rect = this.panelContainer.getBoundingClientRect()
      const parentRect = this.panelContainer.offsetParent ?
        this.panelContainer.offsetParent.getBoundingClientRect() : { left: 0, top: 0 }

      startLeft = rect.left - parentRect.left
      startTop = rect.top - parentRect.top
      startX = e.clientX
      startY = e.clientY

      this.panelContainer.style.bottom = 'auto'
      this.panelContainer.style.right = 'auto'
      this.panelContainer.style.left = `${startLeft}px`
      this.panelContainer.style.top = `${startTop}px`
      this.panelContainer.style.transition = 'none'

      const onMouseMove = (ev) => {
        if (!isDragging) return
        let nextLeft = startLeft + (ev.clientX - startX)
        let nextTop = startTop + (ev.clientY - startY)

        const pRect = this.panelContainer.offsetParent ?
          this.panelContainer.offsetParent.getBoundingClientRect() :
          { width: window.innerWidth, height: window.innerHeight }

        nextLeft = Math.max(0, Math.min(nextLeft, pRect.width - this.panelContainer.offsetWidth))
        nextTop = Math.max(0, Math.min(nextTop, pRect.height - this.panelContainer.offsetHeight))

        this.panelContainer.style.left = `${nextLeft}px`
        this.panelContainer.style.top = `${nextTop}px`
      }

      const onMouseUp = () => {
        isDragging = false
        this.panelContainer.style.transition = 'opacity 0.3s ease-out'
        document.removeEventListener('mousemove', onMouseMove)
        document.removeEventListener('mouseup', onMouseUp)
      }

      document.addEventListener('mousemove', onMouseMove)
      document.addEventListener('mouseup', onMouseUp)
    })
  }

  _setupResizeObserver() {
    const resizeObserver = new ResizeObserver(() => {
      if (this.chart) this.chart.resize()
    })
    resizeObserver.observe(this.panelContainer)
  }

  _setToggleState(forceVisible) {
    const isVisible = forceVisible !== undefined ? forceVisible : this.panelContainer.style.display === 'none'
    const voltIcon = `<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z"></path></svg>`

    if (isVisible) {
      this.panelContainer.style.display = 'flex'
      this.panelContainer.style.opacity = '1'
      this.toggleButton.style.backgroundColor = '#1677ff'
      this.toggleButton.style.borderColor = '#1677ff'
      
      if (this._ensureChartInit()) {
        this.chart.resize()
      }
    } else {
      this.panelContainer.style.display = 'none'
      this.panelContainer.style.opacity = '0'
      this.toggleButton.style.backgroundColor = 'rgba(30, 30, 30, 0.85)'
      this.toggleButton.style.borderColor = 'rgba(255, 255, 255, 0.2)'
    }
    this.toggleButton.innerHTML = voltIcon
  }

  updateData(newCategory, newVoltage, newCurrent) {
    if (this._lastPushedSecond === newCategory) return

    if (this.categories.length >= 60) {
      this.categories.shift()
      this.voltageData.shift()
      this.currentData.shift()
    }
    
    this.categories.push(newCategory)
    this.voltageData.push(newVoltage)
    this.currentData.push(newCurrent)
    this._lastPushedSecond = newCategory

    if (this._ensureChartInit()) {
      const voltLabel = (this.chart.getOption().series[0]).name || 'Voltage'
      const currLabel = (this.chart.getOption().series[1]).name || 'Current'
      
      this.chart.setOption({
        animation: false,
        xAxis: { 
          data: this.categories,
          axisLabel: { interval: 'auto' }
        },
        series: [
          { 
            name: voltLabel, 
            data: this.voltageData, 
            yAxisIndex: 0,
            type: 'line',
            smooth: true,
            symbol: 'none',
            itemStyle: { color: '#ffcc00' }
          },
          { 
            name: currLabel, 
            data: this.currentData, 
            yAxisIndex: 1, 
            type: 'bar',
            barWidth: '60%',
            itemStyle: { color: 'rgba(22, 119, 255, 0.7)' }
          },
        ],
      })
    }
  }

  updateLabels(labels = {}) {
    const titleEl = document.getElementById('voltage-header-title')
    if (titleEl && labels.voltageTitle) {
      titleEl.innerText = labels.voltageTitle
    }

    if (this.chart) {
      const options = this.chart.getOption()
      const updatedTitles = []
      const updatedSeries = [...options.series]

      if (labels.voltageChartMainTitle) {
        options.title[0].text = labels.voltageChartMainTitle
      }
      
      if (labels.voltageLabel) {
        updatedSeries[0].name = labels.voltageLabel
        updatedTitles.push(labels.voltageLabel)
      } else {
        updatedTitles.push(updatedSeries[0].name)
      }

      if (labels.currentLabel) {
        updatedSeries[1].name = labels.currentLabel
        updatedTitles.push(labels.currentLabel)
      } else {
        updatedTitles.push(updatedSeries[1].name)
      }

      this.chart.setOption({
        title: options.title,
        legend: { data: updatedTitles },
        series: updatedSeries
      })
    }
  }

  dispose() {
    this.chart?.dispose()
    this.panelContainer?.remove()
    this.toggleButton?.remove()
  }
}
