import * as THREE from 'three'
import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls.js'
import PCDLoadingStrategy from '../strategies/PCDLoadingStrategy'

/**
 * PCDManager
 * 독립된 미니 패널 내에서 PCD(Point Cloud Data)를 전문적으로 렌더링하는 매니저 클래스입니다.
 * 메인 씬과 격리된 자체 3D 엔진을 보유합니다.
 */
export default class PCDManager {
  constructor(rootContainer, panelContainer) {
    this.rootContainer = rootContainer
    this.panelContainer = panelContainer

    // 1. 독립 3D 엔진 구성 (격리 렌더링용)
    this.miniScene = new THREE.Scene()
    this.miniScene.background = new THREE.Color(0x050505)

    this.miniCamera = new THREE.PerspectiveCamera(45, 1, 0.1, 2000)
    this.miniCamera.position.set(5, 5, 5)

    this.miniRenderer = new THREE.WebGLRenderer({
      antialias: true,
      alpha: true,
      preserveDrawingBuffer: true
    })
    this.miniRenderer.setPixelRatio(window.devicePixelRatio)

    this.controls = null
    this.pcdPoints = null
    this.isHidden = true
    this.animationId = null
    this.pcdLoader = new PCDLoadingStrategy()

    this._setupUI()
    this._initControls()

    // 초기에는 숨김 상태로 시작
    this._setToggleState(false)
    this._initDragAndResize()
  }

  _initDragAndResize() {
    this._setupDragging()
    this._setupResizeObserver()
  }

  _setupDragging() {
    const header = this.container.firstChild
    let isDragging = false
    let startX, startY, startLeft, startTop

    header.addEventListener('mousedown', (e) => {
      if (e.button !== 0) return
      e.preventDefault()

      isDragging = true

      const rect = this.panelContainer.getBoundingClientRect()
      const parentRect = this.panelContainer.offsetParent ?
        this.panelContainer.offsetParent.getBoundingClientRect() : { left: 0, top: 0 }

      startLeft = rect.left - parentRect.left
      startTop = rect.top - parentRect.top
      startX = e.clientX
      startY = e.clientY

      this.panelContainer.style.bottom = 'auto'
      this.panelContainer.style.right = 'auto'
      this.panelContainer.style.left = `${startLeft}px`
      this.panelContainer.style.top = `${startTop}px`
      this.panelContainer.style.transition = 'none'

      const onMouseMove = (ev) => {
        if (!isDragging) return
        let nextLeft = startLeft + (ev.clientX - startX)
        let nextTop = startTop + (ev.clientY - startY)

        const pRect = this.panelContainer.offsetParent ?
          this.panelContainer.offsetParent.getBoundingClientRect() :
          { width: window.innerWidth, height: window.innerHeight }

        const panelWidth = this.panelContainer.offsetWidth
        const panelHeight = this.panelContainer.offsetHeight

        nextLeft = Math.max(0, Math.min(nextLeft, pRect.width - panelWidth))
        nextTop = Math.max(0, Math.min(nextTop, pRect.height - panelHeight))

        this.panelContainer.style.left = `${nextLeft}px`
        this.panelContainer.style.top = `${nextTop}px`
      }

      const onMouseUp = () => {
        isDragging = false
        this.panelContainer.style.transition = 'opacity 0.3s ease-out'
        document.removeEventListener('mousemove', onMouseMove)
        document.removeEventListener('mouseup', onMouseUp)
      }

      document.addEventListener('mousemove', onMouseMove)
      document.addEventListener('mouseup', onMouseUp)
    })
  }

  _setupResizeObserver() {
    const resizeObserver = new ResizeObserver(() => {
      this._onResize()
    })
    resizeObserver.observe(this.panelContainer)
  }

  _setupUI() {
    this.container = document.createElement('div')
    Object.assign(this.container.style, {
      position: 'relative',
      width: '100%',
      height: '100%',
      display: 'flex',
      flexDirection: 'column',
      overflow: 'hidden',
    })
    this.panelContainer.appendChild(this.container)

    const header = document.createElement('div')
    header.innerHTML = `
      <span style="display:flex; align-items:center; gap:8px;">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M17.5 19a3.5 3.5 0 1 1-5.1-3"></path><path d="M12 16V5a2 2 0 1 1 4 0v11"></path><path d="M17.5 19a3.5 3.5 0 1 1 5.1-3"></path><path d="M12 16a2 2 0 1 0-4 0v-5a2 2 0 1 0-4 0v5a3.5 3.5 0 1 0 5.1 3"></path></svg>
        <span id="pcd-header-title">PCD ANALYSIS</span>
      </span>
    `
    Object.assign(header.style, {
      padding: '0 15px',
      height: '32px',
      background: 'rgba(40, 40, 40, 0.9)',
      color: '#00ff88',
      display: 'flex',
      alignItems: 'center',
      fontSize: '12px',
      fontWeight: '600',
      letterSpacing: '0.5px',
      textTransform: 'uppercase',
      borderBottom: '1px solid rgba(255, 255, 255, 0.1)',
      zIndex: '10',
      cursor: 'move',
      userSelect: 'none'
    })
    this.container.appendChild(header)

    this.renderArea = document.createElement('div')
    this.renderArea.style.flex = '1'
    this.renderArea.style.width = '100%'
    this.renderArea.style.height = '100%'
    this.container.appendChild(this.renderArea)
    this.renderArea.appendChild(this.miniRenderer.domElement)

    this.toggleButton = document.createElement('button')
    this.toggleButton.title = 'PCD 데이터 분석'
    Object.assign(this.toggleButton.style, {
      position: 'absolute',
      top: '20px',
      right: '20px',
      width: '40px',
      height: '40px',
      background: 'rgba(30, 30, 30, 0.85)',
      color: '#fff',
      border: '1px solid rgba(255, 255, 255, 0.2)',
      borderRadius: '8px',
      cursor: 'pointer',
      zIndex: '2000',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      boxShadow: '0 2px 8px rgba(0, 0, 0, 0.3)',
      transition: 'all 0.2s',
    })
    this.rootContainer.appendChild(this.toggleButton)
    this.toggleButton.addEventListener('click', () => this._setToggleState())

    const ambientLight = new THREE.AmbientLight(0xffffff, 1.0)
    this.miniScene.add(ambientLight)
  }

  _initControls() {
    this.controls = new OrbitControls(this.miniCamera, this.miniRenderer.domElement)
    this.controls.enableDamping = true
    this.controls.dampingFactor = 0.05
    this.controls.screenSpacePanning = true
  }

  _setToggleState(forceVisible) {
    const isVisible = forceVisible !== undefined ? forceVisible : this.panelContainer.style.display === 'none'
    const pcdIcon = `<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M17.5 19a3.5 3.5 0 1 1-5.1-3"></path><path d="M12 16V5a2 2 0 1 1 4 0v11"></path><path d="M17.5 19a3.5 3.5 0 1 1 5.1-3"></path><path d="M12 16a2 2 0 1 0-4 0v-5a2 2 0 1 0-4 0v5a3.5 3.5 0 1 0 5.1 3"></path></svg>`

    if (isVisible) {
      this.panelContainer.style.display = 'flex'
      this.panelContainer.style.opacity = '1'
      this.toggleButton.style.backgroundColor = '#1677ff'
      this.toggleButton.style.borderColor = '#1677ff'
      this.isHidden = false
      this._onResize()
      this._startAnimating()
    } else {
      this.panelContainer.style.display = 'none'
      this.panelContainer.style.opacity = '0'
      this.toggleButton.style.backgroundColor = 'rgba(30, 30, 30, 0.85)'
      this.toggleButton.style.borderColor = 'rgba(255, 255, 255, 0.2)'
      this.isHidden = true
      this._stopAnimating()
    }
    this.toggleButton.innerHTML = pcdIcon
  }

  loadPCD(filePath) {
    this.pcdLoader.loadPCD(
      filePath,
      (points) => {
        if (this.pcdPoints) this.miniScene.remove(this.pcdPoints)
        if (points.material) {
          points.material.size = 0.015
          points.material.color.set(0x00ffaa)
        }
        this.pcdPoints = points
        this.miniScene.add(points)

        const box = new THREE.Box3().setFromObject(points)
        const center = box.getCenter(new THREE.Vector3())
        const size = box.getSize(new THREE.Vector3())
        const maxDim = Math.max(size.x, size.y, size.z)

        const fov = this.miniCamera.fov * (Math.PI / 180)
        let cameraZ = Math.abs(maxDim / 2 / Math.tan(fov / 2))
        cameraZ *= 1.5

        this.miniCamera.position.set(center.x + cameraZ, center.y + cameraZ, center.z + cameraZ)
        this.miniCamera.lookAt(center)
        this.controls.target.copy(center)
        this.controls.update()
      },
      (error) => console.error('[PCDManager] Mini Viewer Load Error:', error)
    )
  }

  _onResize() {
    if (!this.renderArea) return
    const width = this.renderArea.clientWidth
    const height = this.renderArea.clientHeight
    if (width === 0 || height === 0) return

    this.miniCamera.aspect = width / height
    this.miniCamera.updateProjectionMatrix()
    this.miniRenderer.setSize(width, height)
  }

  _startAnimating() {
    if (!this.animationId) {
      const animate = () => {
        this.animationId = requestAnimationFrame(animate)
        this.controls.update()
        this.miniRenderer.render(this.miniScene, this.miniCamera)
      }
      animate()
    }
  }

  _stopAnimating() {
    if (this.animationId) {
      cancelAnimationFrame(this.animationId)
      this.animationId = null
    }
  }

  updateLabels(labels = {}) {
    const titleEl = document.getElementById('pcd-header-title');
    if (titleEl && labels.pcdTitle) {
      titleEl.innerText = labels.pcdTitle;
    }
  }

  dispose() {
    this._stopAnimating()
    if (this.pcdPoints) {
      this.pcdLoader.disposePCD(this.pcdPoints)
    }
    this.miniRenderer.dispose()
    this.controls.dispose()
    this.container.remove()
    this.toggleButton.remove()
  }
}
