import * as THREE from 'three'

export default class AnimationManager {
  constructor(viewer, onAnimationStateChange = () => {}) {
    // viewer 인스턴스에 대한 참조를 유지하여 필요할 때 접근
    this.viewer = viewer
    this.onAnimationStateChange = onAnimationStateChange
    this.mixers = new Map() // { modelId: THREE.AnimationMixer }
    this.animationClips = new Map() // { modelId: THREE.AnimationClip[] }
    this.currentAnimations = new Map() // { modelId: THREE.AnimationAction }
  }

  /**
   * 모델에 대한 애니메이션 믹서와 클립을 설정합니다.
   * 로딩 전략에 따라 FBX 로더가 모델에 직접 애니메이션을 추가할 수도 있고,
   * GLB 로더가 별도로 클립을 반환할 수도 있습니다.
   * @param {string} modelId - 모델의 고유 ID.
   * @param {THREE.Object3D} model - 애니메이션을 포함하는 Three.js 모델 객체.
   * @param {THREE.AnimationMixer | null} mixer - 해당 모델에 대한 애니메이션 믹서.
   * @param {THREE.AnimationClip[] | null} clips - 로더가 반환한 애니메이션 클립 배열.
   */
  setAnimationsForModel(modelId, model, mixer, clips) {
    let finalClips = []
    let finalMixer = mixer

    // 1. GLB 로더 등이 반환한 clips 우선 처리
    if (clips && clips.length > 0) {
      finalClips = clips
      if (!finalMixer) {
        finalMixer = new THREE.AnimationMixer(model)
        console.warn(
          `[AnimationManager] Mixer was null for model ${modelId} but clips were provided. Creating new mixer.`,
        )
      }
    } else if (model.animations && model.animations.length > 0) {
      // 2. FBX 로더 등이 모델 객체 자체에 추가한 model.animations 처리
      finalClips = model.animations
      if (!finalMixer) finalMixer = new THREE.AnimationMixer(model)
    }

    if (finalMixer && finalClips.length > 0) {
      this.mixers.set(modelId, finalMixer)
      this.animationClips.set(modelId, finalClips)
    } else {
      this.mixers.delete(modelId)
      this.animationClips.set(modelId, [])
      // console.log(`[AnimationManager] Model ${modelId} has no animations to set or mixer.`)
    }

    this.currentAnimations.delete(modelId) // 현재 재생 중인 애니메이션 초기화
  }

  /**
   * 모든 모델 믹서를 업데이트합니다. 메인 애니메이션 루프에서 호출됩니다.
   * @param {number} delta - 이전 프레임으로부터 경과된 시간 (초).
   */
  update(delta) {
    this.mixers.forEach((mixer) => mixer.update(delta))
  }

  /**
   * 모델의 애니메이션 클립을 재생합니다.
   * @param {string} modelId - 모델의 고유 ID.
   * @param {string} clipName - 재생할 애니메이션 클립의 이름.
   * @param {number} [crossFadeDuration=0.5] - 현재 애니메이션에서 새 애니메이션으로 전환하는 데 걸리는 시간.
   */
  playAnimation(modelId, clipName, crossFadeDuration = 0.5) {
    const mixer = this.mixers.get(modelId)
    const clips = this.animationClips.get(modelId)

    if (!mixer || !clips || clips.length === 0) {
      console.warn(`[AnimationManager] No animations or mixer found for model ${modelId}.`)
      return
    }

    const newClip = clips.find((clip) => clip.name === clipName)
    if (!newClip) {
      console.warn(
        `[AnimationManager] Animation clip '${clipName}' not found for model ${modelId}.`,
      )
      return
    }

    const newAction = mixer.clipAction(newClip)
    newAction.loop = THREE.LoopRepeat // 기본적으로 반복
    newAction.clampWhenFinished = false // 끝났을 때 정지하지 않음 (반복이므로)

    const currentAction = this.currentAnimations.get(modelId)
    if (currentAction) {
      if (currentAction === newAction) return
      currentAction.fadeOut(crossFadeDuration)
    }

    newAction.reset().fadeIn(crossFadeDuration).play()
    this.currentAnimations.set(modelId, newAction)

    this.onAnimationStateChange(modelId, clipName)
  }

  /**
   * 모델의 현재 재생 중인 애니메이션을 정지합니다.
   * @param {string} modelId - 모델의 고유 ID.
   */
  stopAnimation(modelId) {
    const currentAction = this.currentAnimations.get(modelId)

    if (currentAction) {
      currentAction.stop()
      this.currentAnimations.delete(modelId)
      this.onAnimationStateChange(modelId, null) // 애니메이션 정지 알림
    }
  }

  /**
   * 모델의 모든 애니메이션을 정지합니다.
   * @param {string} modelId - 모델의 고유 ID.
   */
  stopAllAnimations(modelId) {
    const mixer = this.mixers.get(modelId)
    if (!mixer || mixer === undefined) return
    mixer.stopAllAction()
    this.currentAnimations.delete(modelId)
    this.onAnimationStateChange(modelId, null) // 애니메이션 정지 알림
  }

  /**
   * 특정 모델의 사용 가능한 모든 애니메이션 클립 이름을 가져옵니다.
   * @param {string} modelId - 모델의 고유 ID.
   * @returns {string[]} - 애니메이션 클립 이름 배열.
   */
  getAnimationList(modelId) {
    const clips = this.animationClips.get(modelId)
    return clips ? clips.map((clip) => clip.name) : []
  }

  /**
   * 특정 모델에서 현재 재생 중인 애니메이션 클립의 이름을 가져옵니다.
   * @param {string} modelId - 모델의 고유 ID.
   * @returns {string | null} - 현재 재생 중인 애니메이션 클립 이름 또는 null.
   */
  getCurrentPlayingClipName(modelId) {
    const action = this.currentAnimations.get(modelId)
    return action ? action.getClip().name : null
  }

  /**
   * 모델이 삭제될 때 해당 모델과 관련된 모든 애니메이션 리소스를 정리합니다.
   * @param {string} modelId - 삭제될 모델의 고유 ID.
   */
  onModelRemoved(modelId) {
    if (!this.mixers.has(modelId)) return
    const mixer = this.mixers.get(modelId)
    mixer.stopAllAction() // 해당 믹서의 모든 애니메이션 정지
    this.mixers.delete(modelId)
    this.animationClips.delete(modelId)
    this.currentAnimations.delete(modelId)
  }

  /**
   * AnimationManager의 모든 리소스를 해제합니다.
   */
  dispose() {
    this.mixers.forEach((mixer) => mixer.stopAllAction())
    this.mixers.clear()
    this.animationClips.clear()
    this.currentAnimations.clear()
    this.viewer = null
  }
}
