// src/strategies/ModelLoadingStrategy.js

/**
 * 모델 로딩 전략의 추상 기본 클래스입니다.
 * 모든 구체적인 로딩 전략은 이 클래스를 상속받아 정의된 메서드를 구현해야 합니다.
 */
export default class ModelLoadingStrategy {
  constructor() {
    if (new.target === ModelLoadingStrategy) {
      throw new TypeError(
        'ModelLoadingStrategy는 직접 인스턴스화할 수 없습니다. 상속받아 사용하세요.',
      )
    }
  }

  /**
   * 모델 데이터를 미리 로드하거나 캐시합니다.
   * 이는 동일한 모델을 여러 번 인스턴스화할 때 로딩 시간을 절약하기 위함입니다.
   * @param {EnhancedThreeViewer} viewer 뷰어 인스턴스 (씬, 모델 폴더 등 접근용)
   * @param {string} modelName 로드할 모델의 파일 이름 (예: 'my_model.gltf')
   * @returns {Promise<any>} 미리 로드된 모델 데이터 (예: GLTF 객체)
   * @abstract
   */
  async preloadModel(viewer, modelName) {
    throw new Error('preloadModel() 메서드를 구현해야 합니다.')
  }

  /**
   * 미리 로드된 모델 데이터를 기반으로 씬에 추가할 수 있는 모델 인스턴스를 생성합니다.
   * 이 메서드는 모델의 위치, 회전, 사용자 데이터 등을 설정합니다.
   * @param {EnhancedThreeViewer} viewer 뷰어 인스턴스
   * @param {Object} item 로드할 모델 인스턴스에 대한 정보 (id, name, position, rotation, label 등)
   * @returns {Promise<THREE.Object3D>} 씬에 추가된 모델 객체 인스턴스
   * @abstract
   */
  async loadModelInstance(viewer, item) {
    throw new Error('loadModelInstance() 메서드를 구현해야 합니다.')
  }

  /**
   * 로딩 전략에 필요한 모든 리소스를 해제합니다.
   * @abstract
   */
  dispose() {
    // 필요한 경우 하위 클래스에서 오버라이드하여 리소스 해제 로직을 추가
  }
}
