import React from "react";
import { useTranslation } from "react-i18next";
import { Typography, Tag } from "antd";
import { useLayout } from "@/framework/layouts/LayoutProvider";
import { mockRobotData } from "../../mockup/robotData";
import RobotViewer from "./components/RobotViewer";

const { Title, Text } = Typography;

export default function DTRobotDashboard() {
    const { t } = useTranslation("dt-robot");
    const { setLayout } = useLayout();

    React.useEffect(() => {
        // setLayout("default");
    }, [setLayout]);

    return (
        <div style={{ padding: '0 24px 24px 24px', minHeight: '100%' }}>
            <header style={{ marginBottom: 16 }}>
                <Title level={2} style={{ marginBottom: 0 }}>{t("title")}</Title>
                <Text type="secondary">
                    {mockRobotData.name} ({mockRobotData.id}) - <Tag color="green">{mockRobotData.status.toUpperCase()}</Tag>
                </Text>
            </header>

            <div style={{
                width: '100%',
                height: 'calc(100vh - 180px)', // 헤더 높이 반영하여 조정
                overflow: 'hidden',
                background: 'var(--ms-color-bg-container, #001529)',
                borderRadius: '8px',
                border: '1px solid var(--ms-border-color, #303030)'
            }}>
                <RobotViewer robot={mockRobotData} />
            </div>
        </div>
    );
}
