// src/core/EffectManager.js
import * as THREE from 'three'
import * as TWEEN from '@tweenjs/tween.js'

/**
 * 모델에 다양한 시각적 효과(화재, 연기, 스파크 등)를 적용하고 관리하는 클래스입니다.
 * 각 효과는 파티클 시스템으로 구현됩니다.
 */
export default class EffectManager {
  constructor(scene) {
    this.scene = scene
    this.activeEffects = new Map() // key: modelId, value: { effectObjects: [], updateFn: function }
    this.particleSystems = new Map() // key: modelId, value: THREE.Points instance
    this.timer = new THREE.Timer() // 파티클 업데이트를 위한 타이머

    // 파티클 텍스처 (기본 원형 점)
    this.particleTexture = this._createParticleTexture()

    // --- 사전에 정의된 효과 설정 (JSON 형식) - 기본 값, 모델 크기에 따라 보정됨 ---
    // 파라미터 설명을 추가하여 이해를 돕습니다.
    this._effectConfigs = {
      fire: {
        baseCount: 200, // 기본 파티클 수
        baseSpreadFactor: 1.0, // 파티클의 XZ 평면 확산 계수 (모델 크기에 비례)
        baseHeightFactor: 2.0, // 파티클의 Y축(높이) 확산 계수 (모델 크기에 비례)
        baseSpeed: 0.1, // 파티클의 기본 상승 속도
        baseLifetime: 1.5, // 파티클의 기본 생명 주기 (초)
        baseSize: 1.0, // 파티클의 초기 기본 크기
        baseSizeEnd: 5.0, // 파티클의 최종 기본 크기 (점점 커짐)
        colorStart: 0xff4500, // Hex 값 (주황)
        colorEnd: 0xffa07a, // Hex 값 (밝은 주황)
        opacityStart: 0.8,
        opacityEnd: 0,
        material: null,
      },
      smoke: {
        baseCount: 100,
        baseSpreadFactor: 1.5,
        baseHeightFactor: 2.5,
        baseSpeed: 0.05,
        baseLifetime: 4,
        baseSize: 1.0,
        baseSizeEnd: 3.0,
        colorStart: 0x808080, // 회색
        colorEnd: 0xc0c0c0, // 밝은 회색
        opacityStart: 0.4,
        opacityEnd: 0,
        material: null,
      },
      spark: {
        baseCount: 400,
        baseSpreadFactor: 1.2,
        baseHeightFactor: 1.5,
        baseSpeed: 0.3,
        baseLifetime: 0.5,
        baseSize: 0.5,
        baseSizeEnd: 2.5,
        colorStart: 0xffff00, // 노랑
        colorEnd: 0xff0000, // 빨강
        opacityStart: 1.0,
        opacityEnd: 0,
        material: null,
      },
      normal: {
        material: null,
      },
    }
    // ------------------------------------------

    this._initializeMaterials()
  }

  /** 파티클 재료 생성 헬퍼 */
  _createParticleMaterial(colorHex, opacity) {
    return new THREE.PointsMaterial({
      color: new THREE.Color(colorHex),
      size: 0.1,
      transparent: true,
      blending: THREE.AdditiveBlending,
      depthWrite: false, // 파티클이 다른 객체의 깊이 버퍼에 쓰지 않도록 하여 투명도 문제 완화
      depthTest: true,
      map: this.particleTexture,
      vertexColors: false,
      opacity: opacity,
    })
  }

  /** 파티클 텍스처 (원형 점) 생성 헬퍼 */
  _createParticleTexture() {
    const canvas = document.createElement('canvas')
    canvas.width = 32 // 텍스처 해상도 증가 (더 부드러운 점)
    canvas.height = 32
    const context = canvas.getContext('2d')
    const gradient = context.createRadialGradient(
      canvas.width / 2,
      canvas.height / 2,
      0,
      canvas.width / 2,
      canvas.height / 2,
      canvas.width / 2,
    )
    gradient.addColorStop(0, 'rgba(255,255,255,1)')
    gradient.addColorStop(0.5, 'rgba(255,255,255,0.7)') // 중간에 약간의 투명도
    gradient.addColorStop(1, 'rgba(0,0,0,0)')
    context.fillStyle = gradient
    context.fillRect(0, 0, canvas.width, canvas.height)
    return new THREE.CanvasTexture(canvas)
  }

  /** _effectConfigs에 정의된 설정을 기반으로 재료를 초기화합니다. */
  _initializeMaterials() {
    for (const type in this._effectConfigs) {
      const config = this._effectConfigs[type]
      if (config.colorStart !== undefined) {
        config.material = this._createParticleMaterial(config.colorStart, config.opacityStart)
      }
    }
  }

  /**
   * 특정 모델에 시각적 효과를 추가합니다.
   * 기존 효과가 있다면 제거하고 새로운 효과를 적용합니다.
   * @param {string} modelId 효과를 적용할 모델의 ID
   * @param {THREE.Object3D} model 효과를 적용할 모델의 THREE.Object3D 인스턴스
   * @param {string} effectType 적용할 효과의 타입 ('fire', 'smoke', 'spark' 등)
   * @param {THREE.Vector3} modelSize 해당 모델의 바운딩 박스 크기
   */
  addEffect(modelId, model, effectType, modelSize) {
    this.removeEffect(modelId)

    const baseConfig = this._effectConfigs[effectType]
    if (!baseConfig) {
      console.warn(`정의되지 않은 효과 타입: ${effectType}`)
      return
    }

    if (effectType === 'normal') {
      return
    }

    // === 모델 크기에 따라 효과 파라미터 동적 계산 ===
    const maxModelDim = Math.max(modelSize.x, modelSize.y, modelSize.z)
    const modelHeight = modelSize.y // 모델의 높이

    // 스케일 팩터는 물체의 가장 큰 차원(maxModelDim)을 기반으로 하되, 너무 작거나 크지 않도록 제한합니다.
    // 예를 들어, 모델이 1유닛일 때 1배, 5유닛일 때 2배, 10유닛일 때 3배 정도로 커지도록 조정
    // 최소 0.5 (매우 작은 모델), 최대 5.0 (너무 큰 모델 제한)
    const sizeScaleFactor = Math.max(0.5, Math.min(5.0, maxModelDim * 0.5)) // 모델 크기에 더 민감하게 반응하도록 0.5를 곱함

    // 파티클의 확산 및 높이, 크기를 더욱 강조합니다.
    const config = {
      // 파티클 수는 모델의 부피에 비례하도록 조정 (세제곱근)
      count: Math.floor(baseConfig.baseCount * Math.pow(sizeScaleFactor, 2.0)), // 파티클 수를 더 많이 증가

      // XZ 평면에서의 퍼짐 정도 (모델 크기 및 기본 퍼짐 계수 사용)
      spread: maxModelDim * baseConfig.baseSpreadFactor * 0.8, // 모델을 더 확실하게 감싸도록 조정

      // Y축(높이) 방향으로의 확산 정도를 모델 높이에 비례하여 증가
      heightSpread: modelHeight * baseConfig.baseHeightFactor * 1.5, // 모델 높이보다 훨씬 더 높게 퍼지도록 조정

      speed: baseConfig.baseSpeed * (sizeScaleFactor * 0.8), // 속도도 크기에 비례하여 증가
      lifetime: baseConfig.baseLifetime,

      // 파티클의 시작 및 최종 크기. 모델 크기에 비례하여 더 크게 보이도록 조정
      size: baseConfig.baseSize * sizeScaleFactor * 1.5,
      sizeEnd: baseConfig.baseSizeEnd * sizeScaleFactor * 1.8,

      colorStart: new THREE.Color(baseConfig.colorStart),
      colorEnd: new THREE.Color(baseConfig.colorEnd),
      opacityStart: baseConfig.opacityStart,
      opacityEnd: baseConfig.opacityEnd,
      material: baseConfig.material,
      effectType: effectType,
    }
    // =================================================

    const effectObjects = []
    let updateFn = null

    const particleSystem = this._createParticleSystem(model, config.material, config)

    effectObjects.push(particleSystem.points)
    updateFn = particleSystem.update
    this.scene.add(particleSystem.points)
    this.particleSystems.set(modelId, particleSystem.points)

    this.activeEffects.set(modelId, { effectObjects, updateFn })
  }

  /**
   * 파티클 시스템을 생성하고 업데이트 함수를 반환합니다.
   * @param {THREE.Object3D} targetObject 파티클이 생성될 기준 오브젝트
   * @param {THREE.PointsMaterial} material 파티클 재료
   * @param {Object} options 파티클 속성 설정 (이미 계산된 최종 값)
   * @returns {{points: THREE.Points, update: function}} 생성된 파티클 시스템과 업데이트 함수
   */
  _createParticleSystem(targetObject, material, options) {
    const particlesGeometry = new THREE.BufferGeometry()
    const positions = []
    const sizes = []
    const colors = []
    const initialTimes = []
    const lifetimes = []

    const baseColor = options.colorStart
    const endColor = options.colorEnd

    for (let i = 0; i < options.count; i++) {
      // 초기 위치는 모델 중심 주변의 spread 범위 내
      // Y축 시작점은 물체 바닥 근처에서 시작하도록 조정 가능 (예: -options.heightSpread / 2)
      positions.push(
        (Math.random() - 0.5) * options.spread,
        (Math.random() - 0.5) * options.heightSpread * 0.2, // Y축 시작 위치를 바닥 가까이로 집중
        (Math.random() - 0.5) * options.spread,
      )
      sizes.push(options.size)
      colors.push(baseColor.r, baseColor.g, baseColor.b)
      initialTimes.push(Math.random() * options.lifetime)
      lifetimes.push(options.lifetime + (Math.random() - 0.5) * options.lifetime * 0.2) // 생명 주기 변화폭 증가
    }

    particlesGeometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3))
    particlesGeometry.setAttribute('size', new THREE.Float32BufferAttribute(sizes, 1))
    particlesGeometry.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3))
    particlesGeometry.setAttribute('initialTime', new THREE.Float32BufferAttribute(initialTimes, 1))
    particlesGeometry.setAttribute('lifetime', new THREE.Float32BufferAttribute(lifetimes, 1))

    const points = new THREE.Points(particlesGeometry, material)
    points.position.copy(targetObject.position)
    points.name = `particleEffect_${targetObject.userData.id}_${options.effectType || ''}`

    // 파티클 업데이트 함수
    const update = (deltaTime) => {
      if (!points.geometry || !points.geometry.attributes.position) return

      const positions = points.geometry.attributes.position.array
      const sizes = points.geometry.attributes.size.array
      const colors = points.geometry.attributes.color.array
      const initialTimes = points.geometry.attributes.initialTime.array
      const lifetimes = points.geometry.attributes.lifetime.array
      const currentTime = this.timer.getElapsed()

      for (let i = 0; i < options.count; i++) {
        const i3 = i * 3
        const i1 = i

        let elapsed = (currentTime - initialTimes[i1]) % lifetimes[i1]
        if (elapsed < 0) elapsed += lifetimes[i1]

        const progress = elapsed / lifetimes[i1]

        // 파티클이 사라지면 재시작 (더욱 유기적인 흐름을 위해)
        if (progress >= 1.0) {
          initialTimes[i1] = currentTime // 현재 시간을 새로운 시작 시간으로 설정
          elapsed = 0 // 경과 시간 리셋
        }

        // 위치 업데이트:
        // Y축은 상승합니다.
        // X, Z축은 중앙에서 퍼져나가다가 다시 수렴하거나, 특정 범위 내에서 무작위로 움직입니다.
        // 이펙트 높이를 `options.heightSpread`까지 확장합니다.
        positions[i3 + 1] =
          options.speed * elapsed +
          (Math.random() - 0.5) * 0.1 * options.heightSpread * (1 - progress) // Y축 상승 및 약간의 무작위 수직 이동
        positions[i3 + 0] = (Math.random() - 0.5) * options.spread * (1 - progress * 0.5) // X 퍼짐 (수렴하는 경향)
        positions[i3 + 2] = (Math.random() - 0.5) * options.spread * (1 - progress * 0.5) // Z 퍼짐 (수렴하는 경향)

        // 크기 업데이트 (점점 커짐)
        sizes[i1] = THREE.MathUtils.lerp(options.size, options.sizeEnd, progress)

        // 색상 및 투명도 업데이트 (시간에 따라 색상 변화 및 투명해짐)
        const lerpedColor = new THREE.Color().copy(baseColor).lerp(endColor, progress)
        colors[i3 + 0] = lerpedColor.r
        colors[i3 + 1] = lerpedColor.g
        colors[i3 + 2] = lerpedColor.b

        // 재료의 투명도를 직접 조절하는 대신, 파티클 자체의 투명도를 `material.opacity`에서
        // `vertexColors`를 사용한 색상 변화로 구현할 수도 있습니다.
        // 현재는 `material.opacity`가 고정되어 있으므로,
        // 파티클 생성 시의 `opacityStart`와 `opacityEnd`를 고려하여 색상의 알파 값을 조정해야 합니다.
        // 여기서는 material의 opacity를 재활용하여 간단히 구현합니다.
        points.material.opacity = THREE.MathUtils.lerp(
          options.opacityStart,
          options.opacityEnd,
          progress,
        )
      }

      points.geometry.attributes.position.needsUpdate = true
      points.geometry.attributes.size.needsUpdate = true
      points.geometry.attributes.color.needsUpdate = true

      // 모델 위치에 파티클 시스템 동기화
      if (targetObject && targetObject.parent) {
        points.position.copy(targetObject.position)
      }
    }

    return { points, update }
  }

  /**
   * 특정 모델의 효과를 제거합니다.
   * @param {string} modelId 효과를 제거할 모델의 ID
   */
  removeEffect(modelId) {
    if (this.activeEffects.has(modelId)) {
      const { effectObjects } = this.activeEffects.get(modelId)
      effectObjects.forEach((obj) => {
        if (obj instanceof THREE.Points) {
          obj.geometry.dispose()
        }
        this.scene.remove(obj)
      })
      this.activeEffects.delete(modelId)
      this.particleSystems.delete(modelId)
    }
  }

  /**
   * 모든 활성 효과를 업데이트합니다. 애니메이션 루프에서 호출되어야 합니다.
   * @param {number} deltaTime 이전 프레임으로부터 경과된 시간
   */
  update(deltaTime) {
    this.timer.update()
    TWEEN.update()

    this.activeEffects.forEach(({ updateFn }) => {
      if (updateFn) {
        updateFn(deltaTime)
      }
    })
  }

  /** 모든 효과를 제거하고 리소스를 해제합니다. */
  dispose() {
    this.activeEffects.forEach((_, modelId) => this.removeEffect(modelId))
    this.activeEffects.clear()
    this.particleSystems.clear()

    if (this.particleTexture) {
      this.particleTexture.dispose()
      this.particleTexture = null
    }
    for (const type in this._effectConfigs) {
      const config = this._effectConfigs[type]
      if (config.material) {
        config.material.dispose()
        config.material = null
      }
    }
  }
}
