import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';

interface Props {
    clips: string[];
    playingName: string;
    onUpdate: (property: string, value: any) => void;
}

const AnimationControlPanel: React.FC<Props> = ({ clips, playingName, onUpdate }) => {
    const { t } = useTranslation('dt-robot');
    const [isCollapsed, setIsCollapsed] = useState(true);

    return (
        <div className="control-section">
            <div className="section-title" onClick={() => setIsCollapsed(!isCollapsed)}>
                <span>{t('panels.animation.title')}</span>
                <span>{isCollapsed ? '▼' : '▲'}</span>
            </div>

            {!isCollapsed && (
                <div className="control-body">
                    {clips.length > 0 ? (
                        <div className="animation-list" style={{ display: 'flex', flexDirection: 'column', gap: 5 }}>
                            {clips.map(clip => (
                                <button
                                    key={clip}
                                    onClick={() => onUpdate('playAnimation', clip)}
                                    className={`reset-btn ${playingName === clip ? 'active' : ''}`}
                                    style={{
                                        textAlign: 'left',
                                        padding: '5px 10px',
                                        background: playingName === clip ? 'var(--ms-color-primary, #1677ff)' : 'rgba(255, 255, 255, 0.05)',
                                        color: playingName === clip ? '#fff' : 'var(--panel-font-secondary)'
                                    }}
                                >
                                    ▶ {clip}
                                </button>
                            ))}
                            <button
                                onClick={() => onUpdate('stopAnimation', '')}
                                className="reset-btn"
                                style={{ marginTop: 10, background: 'var(--ms-color-error, #cf1322)', color: '#fff' }}
                            >
                                ■ {t('panels.animation.stop_all')}
                            </button>
                        </div>
                    ) : (
                        <div className="placeholder-message">{t('panels.animation.no_animations')}</div>
                    )}
                </div>
            )}

            {isCollapsed && <div className="status-info">{t('panels.animation.description')}</div>}
        </div>
    );
};

export default AnimationControlPanel;
