import React, { useState, useEffect, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import { Button, Slider, Space, Typography, Badge, Tag } from 'antd';
import { PlayCircleOutlined, PauseCircleOutlined, RedoOutlined, StepForwardOutlined, FileSearchOutlined } from '@ant-design/icons';
import EnhancedThreeViewer from '@/platforms/dt-robot/lib/EnhancedThreeViewer';
import { MOCK_ROBOT_PATTERN_DATA } from '@/platforms/dt-robot/mockup/patternData';

const { Text, Title } = Typography;

interface ModelPatternPanelProps {
    viewer: EnhancedThreeViewer | null;
    selectedModelId: string | null;
}

const ModelPatternPanel: React.FC<ModelPatternPanelProps> = ({ viewer, selectedModelId }) => {
    const { t } = useTranslation('dt-robot');
    const [isPlaying, setIsPlaying] = useState(false);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [intervalMs, setIntervalMs] = useState(30);
    const timerRef = useRef<any>(null);

    const fullData = MOCK_ROBOT_PATTERN_DATA;

    const startPlayback = () => {
        if (!viewer || !selectedModelId) return;
        setIsPlaying(true);
    };

    const stopPlayback = () => {
        setIsPlaying(false);
    };

    const resetPlayback = () => {
        setIsPlaying(false);
        setCurrentIndex(0);
        if (viewer && selectedModelId) {
            viewer.sendSimulatedMqtt(fullData[0]);
        }
    };

    const openHistory = () => {
        if (viewer && viewer.container) {
            const event = new CustomEvent('mqttDataTablePopup');
            viewer.container.dispatchEvent(event);
        }
    };

    useEffect(() => {
        if (isPlaying) {
            timerRef.current = setInterval(() => {
                setCurrentIndex((prev) => {
                    const next = (prev + 1) % fullData.length;
                    if (viewer && selectedModelId) {
                        viewer.sendSimulatedMqtt(fullData[next]);
                    }
                    return next;
                });
            }, intervalMs);
        } else {
            if (timerRef.current) clearInterval(timerRef.current);
        }

        return () => {
            if (timerRef.current) clearInterval(timerRef.current);
        };
    }, [isPlaying, intervalMs, viewer, selectedModelId]);

    return (
        <div className="pattern-panel-content" style={{ background: 'var(--ms-color-bg-layout, rgba(0,0,0,0.2))', padding: '12px', borderRadius: '4px' }}>
            <Space direction="vertical" style={{ width: '100%' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <Title level={5} style={{ color: 'var(--ms-color-text)', margin: 0 }}>{t('panels.model_pattern.title')}</Title>
                    <Badge status={isPlaying ? 'processing' : 'default'} text={<Text style={{ color: 'var(--ms-color-text-secondary, #aaa)', fontSize: '12px' }}>{isPlaying ? t('panels.model_pattern.running') : t('panels.model_pattern.stopped')}</Text>} />
                </div>

                <div style={{ background: 'rgba(255,255,255,0.05)', padding: '10px', borderRadius: '4px', border: '1px solid var(--ms-border-color, rgba(255,255,255,0.1))' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px' }}>
                        <Text style={{ color: 'var(--ms-color-text-secondary, #888)' }}>{t('panels.model_pattern.status')}</Text>
                        <Text style={{ color: 'var(--ms-color-primary, #1890ff)' }}>{currentIndex + 1} / {fullData.length}</Text>
                    </div>
                    <Slider
                        value={currentIndex}
                        max={fullData.length - 1}
                        tooltip={{ open: false }}
                        onChange={(val) => setCurrentIndex(val)}
                        disabled={isPlaying}
                        style={{ margin: '4px 0' }}
                    />
                </div>

                <div style={{ background: 'rgba(255,255,255,0.05)', padding: '10px', borderRadius: '4px', border: '1px solid var(--ms-border-color, rgba(255,255,255,0.1))' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '4px' }}>
                        <Text style={{ color: 'var(--ms-color-text-secondary, #888)' }}>{t('panels.model_pattern.interval')}</Text>
                        <Tag color="blue">{intervalMs}ms</Tag>
                    </div>
                    <Slider
                        min={10}
                        max={500}
                        value={intervalMs}
                        onChange={(val) => setIntervalMs(val)}
                        step={10}
                        style={{ margin: '4px 0' }}
                    />
                </div>

                <Space style={{ width: '100%', justifyContent: 'center', marginTop: '10px' }}>
                    <Button
                        type={isPlaying ? 'default' : 'primary'}
                        danger={isPlaying}
                        icon={isPlaying ? <PauseCircleOutlined /> : <PlayCircleOutlined />}
                        onClick={isPlaying ? stopPlayback : startPlayback}
                        style={{ flex: 1 }}
                    >
                        {isPlaying ? t('panels.model_pattern.stop') : t('panels.model_pattern.start')}
                    </Button>
                    <Button icon={<RedoOutlined />} onClick={resetPlayback} title={t('panels.model_pattern.history')} />
                    <Button icon={<FileSearchOutlined />} onClick={openHistory}>
                        {t('panels.model_pattern.history')}
                    </Button>
                    <Button
                        icon={<StepForwardOutlined />}
                        onClick={() => {
                            const next = (currentIndex + 1) % fullData.length;
                            setCurrentIndex(next);
                            if (viewer && selectedModelId) viewer.sendSimulatedMqtt(fullData[next]);
                        }}
                        disabled={isPlaying}
                    />
                </Space>
            </Space>
        </div>
    );
};

export default ModelPatternPanel;
