import * as THREE from 'three'

export default class ModelManager {
  constructor() {}

  // 모델 데이터 설정
  setModelData(model) {
    // 콘솔에 구조 정보 출력
    // this._logModelStructure(model)

    const nodeTree = this._analyzeNodeTree(model)
    const meshList = this._extractMeshes(model)
    const objectList = this._extractObjects(model)
    const modelData = { nodeTree, meshList, objectList }
    //console.log('modelData :', modelData)

    return modelData
  }

  // 모델 구조를 콘솔에 출력
  _logModelStructure(object, depth = 0) {
    const indent = '  '.repeat(depth)
    const type = object.type
    const name = object.name || 'unnamed'

    //console.log(`${indent}${type}: "${name}" (${object.uuid})`)

    if (object.isMesh) {
      //console.log(`${indent}  - Material: ${object.material?.type || 'none'}`)
      //console.log(`${indent}  - Geometry: ${object.geometry?.type || 'none'}`)
      //console.log(`${indent}  - Vertices: ${object.geometry?.attributes?.position?.count || 0}`)
    }

    if (object.children && object.children.length > 0) {
      object.children.forEach((child) => this._logModelStructure(child, depth + 1))
    }
  }

  // 모델의 노드 트리를 계층적으로 분석
  _analyzeNodeTree(object, depth = 0) {
    const node = {
      id: object.uuid,
      name: object.name || 'unnamed',
      type: object.type,
      position: object.position.toArray(),
      rotation: object.rotation.toArray(),
      scale: object.scale.toArray(),
      visible: object.visible,
      depth: depth,
      children: [],
    }

    // 메쉬 관련 정보 추가
    if (object.isMesh) {
      node.meshInfo = {
        geometry: object.geometry?.type || 'none',
        material: object.material?.type || 'none',
        vertices: object.geometry?.attributes?.position?.count || 0,
        triangles: object.geometry?.index ? object.geometry.index.count / 3 : 0,
        boundingBox: this.getBoundingBox(object),
      }
    }

    // 본/스켈레톤 정보 추가 (FBX 캐릭터용)
    if (object.skeleton) {
      node.skeletonInfo = {
        boneCount: object.skeleton.bones.length,
        bones: object.skeleton.bones.map((bone) => ({ name: bone.name, id: bone.uuid })),
      }
    }

    // 자식 노드들 재귀적으로 분석
    object.children.forEach((child) => node.children.push(this._analyzeNodeTree(child, depth + 1)))

    return node
  }

  // 모든 메쉬 추출 및 분석
  _extractMeshes(model) {
    const meshes = []

    model.traverse((child) => {
      if (child.isMesh) {
        meshes.push({
          id: child.uuid,
          name: child.name || 'unnamed',
          geometry: {
            type: child.geometry?.type || 'none',
            vertices: child.geometry?.attributes?.position?.count || 0,
            triangles: child.geometry?.index ? child.geometry.index.count / 3 : 0,
          },
          material: {
            type: child.material?.type || 'none',
            name: child.material?.name || 'unnamed',
            color: child.material?.color?.getHex() || 0xffffff,
          },
          transform: {
            position: child.position.toArray().map((val) => this._formatValue('position', val)),
            rotation: child.rotation.toArray().map((val) => this._formatValue('rotation', val)),
            scale: child.scale.toArray().map((val) => this._formatValue('scale', val)),
          },
          boundingBox: this.getBoundingBox(child),
          visible: child.visible,
          parent: child.parent?.name || 'root',
        })
      }
    })

    return meshes
  }

  // 모든 오브젝트 추출 및 분석
  _extractObjects(model) {
    const objects = []

    model.traverse((child) => {
      objects.push({
        id: child.uuid,
        name: child.name || 'unnamed',
        type: child.type,
        transform: {
          position: child.position.toArray().map((val) => this._formatValue('position', val)),
          rotation: child.rotation.toArray().map((val) => this._formatValue('rotation', val)),
          scale: child.scale.toArray().map((val) => this._formatValue('scale', val)),
        },
        visible: child.visible,
        parent: child.parent?.name || 'root',
        childrenCount: child.children.length,
        isMesh: child.isMesh,
        isGroup: child.isGroup,
        isObject3D: child.isObject3D,
      })
    })

    return objects
  }

  // 바운딩 박스 계산
  getBoundingBox(object) {
    try {
      const box = new THREE.Box3().setFromObject(object)
      const size = box.getSize(new THREE.Vector3())
      const center = box.getCenter(new THREE.Vector3())

      return {
        min: box.min.toArray(),
        max: box.max.toArray(),
        size: size.toArray(),
        center: center.toArray(),
      }
    } catch (error) {
      console.error('Bounding box calculation failed:', error)
      return null
    }
  }

  // 오브젝트 위치 변경 (instance는 실제 THREE.Object3D)
  setObjectPosition(model, modelData, objectName, x, y, z) {
    const obj = model.getObjectByName(objectName)
    if (!obj) return false
    
    obj.position.set(x, y, z)
    
    // modelData의 메타데이터도 함께 업데이트 (UI 연동용)
    const meta = modelData.objectList.find((o) => o.name === objectName)
    if (meta) meta.transform.position = [x, y, z]
    
    return true
  }

  // 오브젝트 회전 변경 (instance는 실제 THREE.Object3D)
  setObjectRotation(model, modelData, objectName, x, y, z) {
    const obj = model.getObjectByName(objectName)
    if (!obj) return false
    
    obj.rotation.set(x, y, z)

    // modelData의 메타데이터도 함께 업데이트 (UI 연동용)
    const meta = modelData.objectList.find((o) => o.name === objectName)
    if (meta) meta.transform.rotation = [x, y, z]

    if (objectName === 'Axis2') {
      this.relateObj(modelData, model, obj, [x, y, z], 'Bone', 'piston1')
    }

    return true
  }

  relateObj(modelData, model, targetObj, [x, y, z], bObjName, cObjName) {
    // bObjName과 cObjName에 해당하는 오브젝트 찾기
    const b = model.getObjectByName(bObjName)
    const c = model.getObjectByName(cObjName)

    if (!b || !c) {
      // console.error(`relateObj: Unable to find objects with names "${bObjName}" or "${cObjName}".`)
      return
    }

    // b와 c의 논리적 연결 구현
    const updateCTransform = () => {
      // 거리 기반 보정 값 계산
      let offset = 0.0
      const threshold = 0.1 // 거리 임계값

      if (targetObj.rotation.z < 0.03) offset = 0.0
      else if (targetObj.rotation.z < 0.5) offset = -0.3
      else if (targetObj.rotation.z < 1.0) offset = -0.35
      else if (targetObj.rotation.z < 1.4) offset = -0.25

      // c의 위치 및 회전 설정
      const theta_cylinder = 0.2105 * (z + 1.15) - 0.28
      const theta_axis = 1.218 * (z + 1.15) - 3 - offset

      c.rotation.set(c.rotation.x, c.rotation.y, theta_cylinder)
      b.rotation.set(theta_axis, b.rotation.y, b.rotation.z)
    }

    // b의 변환이 변경될 때마다 c를 업데이트
    // b.onAfterRender = updateCTransform

    // 초기 변환 동기화
    updateCTransform()
  }

  // 유틸리티 함수: 값 포맷팅
  _formatValue(key, value, precision = 3, threshold = 1e-6) {
    if (typeof value !== 'number') {
      // console.warn('Invalid value passed to _formatValue:', key, value)
      return 0 // 기본값 반환
    }
    if (Math.abs(value) < threshold) {
      return 0 // 임계값보다 작으면 0으로 처리
    }
    return parseFloat(value.toFixed(precision)) // 소수점 이하 자리수 제한
  }

  // 오브젝트 위치 가져오기
  getObjectPosition(modelData, objectName) {
    const obj = modelData.objectList.find((o) => o.name === objectName)
    if (!obj) return null
    return obj.transform.position.map((val) => this._formatValue('position', val))
  }

  // 오브젝트 회전 가져오기
  getObjectRotation(modelData, objectName) {
    const obj = modelData.objectList.find((o) => o.name === objectName)
    if (!obj) return null
    return obj.transform.rotation.map((val) => this._formatValue('rotation', val))
  }

  // 특정 오브젝트의 정보를 다시 읽어오기
  refreshObjectInfo(modelData, objectName) {
    const obj = modelData.objectList.find((o) => o.name === objectName)
    if (!obj) return null
    obj.transform.position = obj.object.position
      .toArray()
      .map((val) => this._formatValue('position', val))
    obj.transform.rotation = obj.object.rotation
      .toArray()
      .map((val) => this._formatValue('rotation', val))
    obj.transform.scale = obj.object.scale.toArray().map((val) => this._formatValue('scale', val))
    return obj
  }

  // 이름으로 메쉬 찾기
  findMeshByName(modelData, name) {
    return modelData.meshList.find((mesh) => mesh.name === name)
  }

  // ID로 오브젝트 찾기
  findObjectById(modelData, id) {
    return modelData.objectList.find((obj) => obj.id === id)
  }

  // 메쉬 가시성 제어
  setMeshVisibility(modelData, meshName, visible) {
    const mesh = modelData.meshList.find((m) => m.name === meshName)
    if (!mesh) return false
    mesh.object.visible = visible
    return true
  }

  // 메쉬 색상 변경
  setMeshColor(modelData, meshName, color) {
    const mesh = modelData.meshList.find((m) => m.name === meshName)
    if (!mesh?.object?.material) return false
    mesh.object.material.color.setHex(color)
    return true
  }
}
