import { PCDLoader } from 'three/examples/jsm/loaders/PCDLoader.js'

export default class PCDLoadingStrategy {
  constructor() {
    this.loader = new PCDLoader()
  }

  loadPCD(filePath, onLoad, onError) {
    this.loader.load(
      filePath,
      (points) => {
        //console.log('PCD file loaded:', points)

        //points.geometry.center() // Center the point cloud
        onLoad(points)
      },
      undefined,
      (error) => {
        console.error('Error loading PCD file:', error)
        if (onError) onError(error)
      },
    )
  }

  disposePCD(points) {
    if (points) {
      points.geometry?.dispose()
      points.geometry = null

      points.material?.dispose()
      points.material = null
    }
    console.log('PCD resources have been disposed.')
  }
}
