import * as THREE from 'three'

export default class AxesHelperManager {
  constructor(scene, camera, labelManager, size = 5, visible = true) {
    this.scene = scene
    this.labelManager = labelManager
    this.camera = camera
    this.initialSize = size
    this.currentSize = size
    this.initVisible = visible

    this.axesHelper = null
    this.arrowHeads = new THREE.Group()
    this.scene.add(this.arrowHeads)

    this._createAxesHelperAndElements(size, visible)

    // Ensure axes are visible by default
    this.show()
  }

  _createAxesHelperAndElements(size, visible) {
    if (!this.scene) {
      console.warn('[AxesHelperManager] Scene is null. Skipping creation.')
      return
    }
    this._disposeExistingElements()

    this.axesHelper = new THREE.AxesHelper(size)
    this.axesHelper.visible = visible
    this.scene.add(this.axesHelper)
    this.currentSize = size

    this._createArrowHeadsAndLabels(size)

    this.arrowHeads.visible = this.axesHelper.visible
    this._toggleLabelsVisibility(this.axesHelper.visible)
  }

  _disposeExistingElements() {
    if (this.axesHelper) {
      this.scene.remove(this.axesHelper)
      this.axesHelper = null
    }

    if (this.arrowHeads) {
      this.arrowHeads.children.forEach((child) => {
        if (child.geometry) child.geometry.dispose()
        if (child.material) {
          if (Array.isArray(child.material)) {
            child.material.forEach((mat) => mat.dispose())
          } else {
            child.material.dispose()
          }
        }
      })
      this.arrowHeads.clear()
    }

    this._removeAxesLabels()
  }

  show() {
    if (this.axesHelper) this.axesHelper.visible = true
    this.arrowHeads.visible = true
    this._toggleLabelsVisibility(true)
  }

  hide() {
    if (this.axesHelper) this.axesHelper.visible = false
    this.arrowHeads.visible = false
    this._toggleLabelsVisibility(false)
  }

  toggleVisibility() {
    const newState = !this.axesHelper.visible
    if (this.axesHelper) this.axesHelper.visible = newState
    this.arrowHeads.visible = newState
    this._toggleLabelsVisibility(newState)
    this.initVisible = newState
    return newState
  }

  setSize(size) {
    if (size === this.currentSize) return

    this._createAxesHelperAndElements(
      size,
      this.axesHelper ? this.axesHelper.visible : this.initVisible,
    )
  }

  _createArrowHeadsAndLabels(size) {
    this.arrowHeads.children.forEach((child) => {
      if (child.geometry) child.geometry.dispose()
      if (child.material) child.material.dispose()
    })
    this.arrowHeads.clear()

    this._removeAxesLabels()

    const coneRadius = size * 0.02
    const coneHeight = size * 0.04
    const labelOffset = size * 1.1

    console.debug(
      `[AxesHelperManager] Cone Size: R=${coneRadius.toFixed(4)}, H=${coneHeight.toFixed(4)}, Label Offset=${labelOffset.toFixed(4)} (based on axes size=${size})`,
    )

    const coneGeometry = new THREE.ConeGeometry(coneRadius, coneHeight, 32)

    // 공통 라벨 스타일 정의 (흰색 배경에서 잘 보이도록)
    const baseLabelStyle = {
      color: '#333', // 어두운 글자색
      backgroundColor: 'rgba(255, 255, 255, 0.7)', // 반투명 흰색 배경
      // textShadow: '1px 1px 2px rgba(0, 0, 0, 0.6)', // 글자 그림자
      padding: '3px 6px',
      borderRadius: '4px',
      border: '1px solid rgba(0, 0, 0, 0.2)',
      fontWeight: 'bold',
      whiteSpace: 'nowrap',
    }

    // X축 (빨간색)
    const coneX = new THREE.Mesh(coneGeometry, new THREE.MeshBasicMaterial({ color: 0xff0000 }))
    coneX.position.set(size, 0, 0)
    coneX.rotation.z = -Math.PI / 2
    this.arrowHeads.add(coneX)
    this.labelManager.addLabel(
      'axisXLabel',
      new THREE.Vector3(labelOffset, 0, 0),
      'X',
      {
        isBillboard: true,
        style: { ...baseLabelStyle, color: '#ff4444' }, // X축 라벨 색상
      },
      null,
    )

    // Y축 (초록색)
    const coneY = new THREE.Mesh(coneGeometry, new THREE.MeshBasicMaterial({ color: 0x00ff00 }))
    coneY.position.set(0, size, 0)
    this.arrowHeads.add(coneY)
    this.labelManager.addLabel(
      'axisYLabel',
      new THREE.Vector3(0, labelOffset, 0),
      'Y',
      {
        isBillboard: true,
        style: { ...baseLabelStyle, color: '#44ff44' }, // Y축 라벨 색상
      },
      null,
    )

    // Z축 (파란색)
    const coneZ = new THREE.Mesh(coneGeometry, new THREE.MeshBasicMaterial({ color: 0x0000ff }))
    coneZ.position.set(0, 0, size)
    coneZ.rotation.x = Math.PI / 2
    this.arrowHeads.add(coneZ)
    this.labelManager.addLabel(
      'axisZLabel',
      new THREE.Vector3(0, 0, labelOffset),
      'Z',
      {
        isBillboard: true,
        style: { ...baseLabelStyle, color: '#4444ff' }, // Z축 라벨 색상
      },
      null,
    )

    this.arrowHeads.visible = this.axesHelper.visible
    this._toggleLabelsVisibility(this.axesHelper.visible)
  }

  _toggleLabelsVisibility(visible) {
    this.labelManager?.setLabelVisibility('axisXLabel', visible)
    this.labelManager?.setLabelVisibility('axisYLabel', visible)
    this.labelManager?.setLabelVisibility('axisZLabel', visible)
  }

  _removeAxesLabels() {
    this.labelManager?.removeLabel('axisXLabel')
    this.labelManager?.removeLabel('axisYLabel')
    this.labelManager?.removeLabel('axisZLabel')
  }

  _isVector3Finite(v) {
    return Number.isFinite(v.x) && Number.isFinite(v.y) && Number.isFinite(v.z)
  }

  updateSizeBasedOnScene(instances) {
    const boundingBox = new THREE.Box3()
    let foundValidGeometry = false

    instances.forEach((model) => {
      if (model && model.isObject3D) {
        model.traverse((child) => {
          if (child.isMesh && child.geometry && child.geometry.attributes.position) {
            const meshBBox = new THREE.Box3().setFromObject(child)

            if (
              this._isVector3Finite(meshBBox.min) &&
              this._isVector3Finite(meshBBox.max) &&
              !meshBBox.isEmpty()
            ) {
              boundingBox.union(meshBBox)
              foundValidGeometry = true
            } else {
              console.warn('Invalid bounding box found for mesh:', child.name, meshBBox)
            }
          }
        })
      }
    })

    if (!this.scene || !foundValidGeometry || boundingBox.isEmpty()) {
      this.setSize(this.initialSize)
    } else {
      const size = new THREE.Vector3()
      boundingBox.getSize(size)

      const maxDim = Math.max(size.x, size.y, size.z)
      const newAxesSize = Math.max(this.initialSize, maxDim * 1.2)
      this.setSize(newAxesSize)
    }
  }

  dispose() {
    this._disposeExistingElements()

    if (this.arrowHeads) {
      this.scene.remove(this.arrowHeads)
      this.arrowHeads = null
    }

    this.scene = null
    this.labelManager = null
    this.camera = null
  }
}
