import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';

interface Props {
    model: any;
    onUpdate: (property: string, value: any) => void;
}

const ModelPropsPanel: React.FC<Props> = ({ model, onUpdate }) => {
    const { t } = useTranslation('dt-robot');
    const [isCollapsed, setIsCollapsed] = useState(true);
    const [moveSpeed, setMoveSpeed] = useState(0.1);

    const startMoving = (axis: 'x' | 'y' | 'z', dir: number) => {
        let direction = '';
        if (axis === 'x') direction = dir > 0 ? 'right' : 'left';
        else if (axis === 'y') direction = dir > 0 ? 'up' : 'down';
        else if (axis === 'z') direction = dir > 0 ? 'backward' : 'forward';

        onUpdate('startContinuousMove', { direction, speed: moveSpeed });
    };

    const stopMoving = () => {
        onUpdate('stopContinuousMove', null);
    };

    useEffect(() => {
        return () => {
            onUpdate('stopContinuousMove', null);
        };
    }, []);

    const handleRotationChange = (axis: 'x' | 'y' | 'z', value: number) => {
        const newRot = [...(model.rotation || [0, 0, 0])];
        const idx = axis === 'x' ? 0 : axis === 'y' ? 1 : 2;
        newRot[idx] = value;
        onUpdate('rotation', newRot);
    };

    return (
        <div className="control-section">
            <div className="section-title" onClick={() => setIsCollapsed(!isCollapsed)}>
                <span>{t('panels.model_props.title')}</span>
                <span>{isCollapsed ? '▼' : '▲'}</span>
            </div>

            {!isCollapsed && (
                <div className="control-body">
                    <div className="control-item">
                        <label className="control-label">{t('panels.model_props.naming')}</label>
                        <div className="control-row">
                            <input
                                type="text"
                                placeholder={t('panels.model_props.label')}
                                value={model.label || ''}
                                onChange={(e) => onUpdate('label', e.target.value)}
                                className="dt-input"
                            />
                            <input
                                type="text"
                                placeholder={t('panels.model_props.name')}
                                value={model.name || ''}
                                onChange={(e) => onUpdate('name', e.target.value)}
                                className="dt-input"
                            />
                        </div>
                    </div>

                    <div className="control-row-grid">
                        <div className="control-item-inline">
                            <label>{t('panels.model_props.selectable')}</label>
                            <input type="checkbox" checked={model.selectable !== false} onChange={(e) => onUpdate('selectable', e.target.checked)} className="dt-switch" />
                        </div>
                        <div className="control-item-inline">
                            <label>{t('panels.model_props.transparentable')}</label>
                            <input type="checkbox" checked={model.transparentable !== false} onChange={(e) => onUpdate('transparentable', e.target.checked)} className="dt-switch" />
                        </div>
                        <div className="control-item-inline">
                            <label>{t('panels.model_props.movable')}</label>
                            <input type="checkbox" checked={model.movable !== false} onChange={(e) => onUpdate('movable', e.target.checked)} className="dt-switch" />
                        </div>
                    </div>

                    <div className="control-item divider-top">
                        <label className="control-label">{t('panels.model_props.precision_pos')}</label>
                        {['x', 'y', 'z'].map((axis, i) => (
                            <div key={axis} className="control-row">
                                <span className="axis-label">{axis.toUpperCase()}</span>
                                <input
                                    type="range"
                                    min="-50" max="50" step="0.1"
                                    value={model.position?.[i] || 0}
                                    onChange={(e) => {
                                        const nextPos = [...(model.position || [0, 0, 0])];
                                        nextPos[i] = parseFloat(e.target.value);
                                        onUpdate('position', nextPos);
                                    }}
                                    className="dt-slider"
                                />
                                <span className="axis-value">{(model.position?.[i] || 0).toFixed(1)}</span>
                            </div>
                        ))}
                    </div>

                    <div className="control-item divider-top">
                        <label className="control-label">{t('panels.model_props.precision_rot')}</label>
                        {['x', 'y', 'z'].map((axis, i) => (
                            <div key={`rot-${axis}`} className="control-row">
                                <span className="axis-label" style={{ color: '#52c41a' }}>{axis.toUpperCase()}</span>
                                <input
                                    type="range"
                                    min="-360" max="360" step="1"
                                    value={model.rotation?.[i] || 0}
                                    onChange={(e) => handleRotationChange(axis as any, parseFloat(e.target.value))}
                                    className="dt-slider"
                                />
                                <span className="axis-value">{(model.rotation?.[i] || 0).toFixed(0)}°</span>
                            </div>
                        ))}
                    </div>

                    <div className="control-item divider-top">
                        <label className="control-label">{t('panels.model_props.joystick')}</label>
                        <div className="joystick-grid">
                            {(['x', 'y', 'z'] as const).flatMap(axis => [-1, 1].map(dir => (
                                <button
                                    key={`${axis}-${dir}`}
                                    className="joy-btn"
                                    onMouseDown={() => startMoving(axis, dir)}
                                    onMouseUp={() => stopMoving()}
                                    onMouseLeave={() => stopMoving()}
                                >
                                    {dir > 0 ? '▶' : '◀'} {axis.toUpperCase()}
                                </button>
                            )))}
                        </div>
                    </div>

                    <div className="control-item">
                        <label className="control-label">{t('panels.model_props.move_speed')}: {moveSpeed.toFixed(2)}</label>
                        <input
                            type="range"
                            min="0.01" max="2" step="0.01"
                            value={moveSpeed}
                            onChange={(e) => setMoveSpeed(parseFloat(e.target.value))}
                            className="dt-slider"
                        />
                    </div>

                    <div className="control-actions" style={{ marginTop: 15 }}>
                        <button className="reset-btn" onClick={() => onUpdate('resetPosition', true)}>{t('panels.model_props.reset')}</button>
                        <button className="delete-btn" onClick={() => onUpdate('deleteModel', true)}>{t('panels.model_props.delete')}</button>
                    </div>
                </div>
            )}

            {isCollapsed && <div className="status-info">{t('panels.model_props.description')}</div>}
        </div>
    );
};

export default ModelPropsPanel;
