  /**
   * 모델의 위치를 설정합니다.
   * @param {string} modelId - 모델의 ID
   * @param {string} objectName - 오브젝트의 이름
   * @param {number} x - X 좌표
   * @param {number} y - Y 좌표
   * @param {number} z - Z 좌표
   */
  setModelPosition(modelId, objectName, x, y, z) {
    const model = this.instances.get(modelId);
    if (!model?.userData?.modelData) {
      console.warn(
        `Model with ID ${modelId} not found or modelData is missing.`,
      );
      return false;
    }

    const success = this.modelMgr.setObjectPosition(
      model,
      model.userData.modelData,
      objectName,
      x,
      y,
      z,
    );
    if (success) {
      this.labelManager.updateLabelPosition(modelId, [x, y, z]);
    }
    return success;
  }

