import * as echarts from 'echarts'

export default class AxisChartManager {
  constructor(rootContainer, panelContainer, styles = {}, options = {}) {
    this.rootContainer = rootContainer
    this.panelContainer = panelContainer
    
    // rootContainer.clientHeight가 0일 경우 브라우저 높이 기준 또는 기본값(180) 사용
    const baseHeight = rootContainer.clientHeight || window.innerHeight
    this.height = Math.max(baseHeight / 4, 180)
    this.container = document.createElement('div')
    rootContainer.appendChild(this.container)

    this.container.id = 'bottom-axis-panel'
    Object.assign(this.container.style, {
      position: 'absolute',
      bottom: '0px',
      left: '0px',
      width: '100%',
      height: `${this.height}px`,
      backgroundColor: 'rgba(20, 20, 20, 0.95)',
      padding: '20px',
      zIndex: '999',
      display: 'flex',
      flexDirection: 'row',
      borderTop: '1px solid rgba(255, 255, 255, 0.15)',
      overflow: 'hidden',
      pointerEvents: 'auto',
      transition: 'transform 0.4s cubic-bezier(0.4, 0, 0.2, 1), opacity 0.4s',
      boxShadow: '0 -8px 24px rgba(0, 0, 0, 0.5)',
    })

    // Create a chart area within the container
    this.chartArea = document.createElement('div')
    this.chartArea.style.position = 'relative'
    this.chartArea.style.width = '100%'
    this.chartArea.style.height = '100%'
    this.chartArea.style.display = 'flex'
    this.chartArea.style.flexDirection = 'row'
    this.chartArea.style.justifyContent = 'space-around'
    this.chartArea.style.alignItems = 'center'
    this.container.appendChild(this.chartArea)

    // Add a collapsible button for the chart area
    this.collapseButton = document.createElement('button')
    this.collapseButton.title = '실시간 축 정보 모니터링'
    Object.assign(this.collapseButton.style, {
      position: 'absolute',
      top: '20px',
      right: '70px',
      width: '40px',
      height: '40px',
      background: 'rgba(30, 30, 30, 0.85)',
      color: '#fff',
      border: '1px solid rgba(255, 255, 255, 0.2)',
      borderRadius: '8px',
      cursor: 'pointer',
      zIndex: '1500', // 패널(1000)보단 높고 헤더(2000)보단 낮게
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      boxShadow: '0 2px 8px rgba(0, 0, 0, 0.3)',
      transition: 'all 0.2s',
    })
    rootContainer.appendChild(this.collapseButton)

    // 리스트 버튼 추가 (this.container의 우측 상단)
    this.listButton = document.createElement('button')
    this.listButton.textContent = '📑 이력'
    this.listButton.style.position = 'absolute'
    this.listButton.style.top = '10px'
    this.listButton.style.right = '20px'
    this.listButton.style.width = '100px'
    this.listButton.style.zIndex = '10'
    this.listButton.style.padding = '5px 10px'
    this.listButton.style.backgroundColor = 'rgba(0, 0, 0, 0.7)'
    this.listButton.style.color = '#fff'
    this.listButton.style.border = 'none'
    this.listButton.style.borderRadius = '4px'
    this.listButton.style.cursor = 'pointer'
    this.listButton.style.boxShadow = '0 2px 4px rgba(0,0,0,0.2)'
    this.container.appendChild(this.listButton)

    // 리스트 버튼 클릭 시 커스텀 이벤트 dispatch
    this.listButton.addEventListener('click', () => {
      const event = new CustomEvent('mqttDataTablePopup', {
        detail: {},
        bubbles: true, // 부모 컨테이너(RobotViewer)까지 전파 보장
        composed: true
      })
      this.rootContainer.dispatchEvent(event)
    })

    // Add a placeholder text for when charts are hidden
    this.placeholderText = document.createElement('div')
    this.placeholderText.textContent = '실시간 축 정보 제공'
    this.placeholderText.style.position = 'absolute'
    this.placeholderText.style.top = '0'
    this.placeholderText.style.left = '50%'
    this.placeholderText.style.width = '100%'
    this.placeholderText.style.bottom = '299px'
    this.placeholderText.style.transform = 'translateX(-50%)'
    this.placeholderText.style.color = '#fff'
    this.placeholderText.style.fontSize = '16px'
    this.placeholderText.style.textAlign = 'center'
    this.placeholderText.style.display = 'none' // Initially hidden
    this.container.appendChild(this.placeholderText)

    // Bind the collapse button handler
    this._collapseButtonHandler = (forceState) => {
      // opacity가 0이거나 초기 상태("")일 때 visible로 전환하도록 판단
      const isVisible = forceState !== undefined ? forceState :
        (this.container.style.opacity === '0' || this.container.style.opacity === '')

      const chartIcon = `<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M18 20V10"></path><path d="M12 20V4"></path><path d="M6 20V14"></path></svg>`

      if (isVisible) {
        this.container.style.transform = 'translateY(0)'
        this.container.style.opacity = '1'
        this.container.style.pointerEvents = 'auto'
        this.collapseButton.innerHTML = chartIcon
        this.collapseButton.style.backgroundColor = '#1677ff'
        this.collapseButton.style.borderColor = '#1677ff'
      } else {
        this.container.style.transform = 'translateY(100%)'
        this.container.style.opacity = '0'
        this.container.style.pointerEvents = 'none'
        this.collapseButton.innerHTML = chartIcon
        this.collapseButton.style.backgroundColor = 'rgba(30, 30, 30, 0.85)'
        this.collapseButton.style.borderColor = 'rgba(255, 255, 255, 0.2)'
      }

      const customEvent = new CustomEvent('collapseButtonClick', {
        detail: { isVisible: isVisible },
      })
      this.rootContainer.dispatchEvent(customEvent)
    }

    this.collapseButton.addEventListener('click', () => this._collapseButtonHandler())

    // Initial state: Start collapsed as requested by user
    this._collapseButtonHandler(false)

    // Default options
    const defaultOptions = {
      title: {
        text: 'Default Chart Title',
        left: 'center',
      },
      tooltip: {},
      series: [],
    }

    // Merge provided options with default options
    this.options = { ...defaultOptions, ...options }

    // Store multiple charts
    this.charts = {}
  }

  updateLabels(labels = {}) {
    if (labels.axisHistory) this.listButton.textContent = labels.axisHistory;
    if (labels.axisPlaceholder) this.placeholderText.textContent = labels.axisPlaceholder;
    if (labels.axisMonitoringTitle) this.collapseButton.title = labels.axisMonitoringTitle;
  }

  // Set layout for the chart area
  setLayout(layout = 'flex') {
    this.chartArea.style.display = layout === 'flex' ? 'flex' : 'block'
  }

  // Initialize a chart with a unique key
  initChart(key = 'default', options, positionAndSize = {}) {
    if (!this.chartArea) {
      console.error('Chart area is not defined.')
      return
    }

    if (this.charts[key]) {
      console.warn(
        `Chart with key '${key}' already exists. Use a different key or dispose the existing chart.`,
      )
      return
    }

    // Create a unique container for the chart
    const chartContainer = document.createElement('div')
    chartContainer.style.position = 'relative'
    chartContainer.style.flex = '0 0 auto' // Ensure proper flex behavior
    chartContainer.style.width = positionAndSize.width || '150px'
    chartContainer.style.height = positionAndSize.height || '150px'
    //chartContainer.style.border = '1px solid #ccc'
    this.chartArea.appendChild(chartContainer)

    // Initialize ECharts instance
    const doInit = () => {
      if (this.charts[key]) return; // 이미 초기화됨
      
      if (chartContainer.clientWidth === 0 || chartContainer.clientHeight === 0) {
        // 크기가 아직 0이면 재시도
        setTimeout(doInit, 100);
        return;
      }
      
      const chart = echarts.init(chartContainer);
      const mergedOptions = { ...this.options, ...options };
      chart.setOption(mergedOptions);
      this.charts[key] = chart;
    }

    doInit();
  }

  // Set chart position and size
  setChartPositionAndSize(
    key,
    { top = '0px', left = '0px', width = '100%', height = '400px', position = 'relative' } = {},
  ) {
    const chart = this.charts[key]
    if (chart) {
      const container = chart.getDom()
      container.style.position = position
      container.style.top = top
      container.style.left = left
      container.style.width = width
      container.style.height = height
      chart.resize()
    } else {
      console.warn(`Chart with key '${key}' is not initialized. Call initChart first.`)
    }
  }

  // Update a specific chart with new options
  updateChart(key, options = {}) {
    const chart = this.charts[key]
    if (chart) {
      // Dynamically calculate font size in em based on container height
      const fontSizeEm = (this.container.clientHeight / 250).toFixed(2) + 'em'

      // Merge new options with existing options
      const mergedOptions = {
        ...chart.getOption(),
        ...options,
        series: options.series?.map((series) => ({
          ...series,
          data: series.data.map((dataPoint) => ({
            ...dataPoint,
            title: {
              ...dataPoint.title,
              fontSize: fontSizeEm, // Set title font size dynamically
            },
          })),
          detail: {
            ...series.detail,
            fontSize: fontSizeEm, // Set detail font size dynamically
          },
        })),
      }

      chart.setOption(mergedOptions)
    } else {
      console.warn(`Chart with key '${key}' is not initialized. Call initChart first.`)
    }
  }

  // Set minimum width for the chart container
  setMinWidth(minWidth) {
    if (this.container) {
      this.container.style.minWidth = minWidth
    }
  }

  // Dispose a specific chart
  disposeChart(key = 'default') {
    const chart = this.charts[key]
    if (chart) {
      // Dispose the chart instance
      chart.dispose()

      // Remove the chart container from the DOM
      const container = chart.getDom()
      container?.parentNode?.removeChild(container)

      // Delete the chart reference
      delete this.charts[key]
    } else {
      console.warn(`Chart with key '${key}' does not exist.`)
    }
  }

  // Dispose all charts
  disposeAllCharts() {
    Object.keys(this.charts).forEach((key) => {
      const chart = this.charts[key]
      if (chart) {
        // Dispose the chart instance
        chart.dispose()

        // Remove the chart container from the DOM
        const container = chart.getDom()
        if (container && container.parentNode) {
          container.parentNode.removeChild(container)
        }
      }
    })

    // Clear the charts object
    this.charts = {}
  }

  dispose() {
    // Remove event listeners
    if (this.collapseButton) {
      this.collapseButton.removeEventListener('click', this._collapseButtonHandler)
      this.collapseButton = null
    }

    // Dispose all charts
    this.disposeAllCharts()

    // Remove the container from the DOM
    if (this.container && this.container.parentNode) {
      this.container.parentNode.removeChild(this.container)
    }
    this.container = null // Remove reference to the container
  }
}
