import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import type EnhancedThreeViewer from '@/platforms/dt-robot/lib/EnhancedThreeViewer';
import ModelPropsPanel from './ModelPropsPanel';
import AnimationControlPanel from './AnimationControlPanel';
import ModelEffectPanel from './ModelEffectPanel';
import ModelObjectControlPanel from './ModelObjectControlPanel';
import ModelPatternPanel from './ModelPatternPanel';
import ModelRenderPanel from './ModelRenderPanel';

interface Props {
    viewer: EnhancedThreeViewer | null;
    models: any[];
    selectedModelId: string | null;
    onModelSelect: (id: string | null) => void;
}

const ModelControlPanel: React.FC<Props> = ({ viewer, models, selectedModelId, onModelSelect }) => {
    const { t } = useTranslation('dt-robot');
    const [clips, setClips] = useState<string[]>([]);
    const [playingName, setPlayingName] = useState<string>('');
    const [isPatternCollapsed, setIsPatternCollapsed] = useState(true);

    const selectedModel = models.find(m => m.id === selectedModelId) || null;

    useEffect(() => {
        if (selectedModelId && viewer) {
            const modelClips = viewer.animationManager?.getAnimationList(selectedModelId) || [];
            setClips(modelClips);
        } else {
            setClips([]);
        }
    }, [selectedModelId, viewer]);

    const handleUpdateModelProp = (property: string, value: any) => {
        if (!viewer || !selectedModelId) return;

        switch (property) {
            case 'playAnimation':
                viewer.animationManager?.play(selectedModelId, value);
                setPlayingName(value);
                break;
            case 'stopAnimation':
                viewer.animationManager?.stop(selectedModelId);
                setPlayingName('');
                break;
            case 'resetPosition':
                const initialPos = (viewer as any).modelInitialPositions?.get(selectedModelId) || [0, 0, 0];
                viewer.moveModelTo(selectedModelId, initialPos);
                break;
            case 'deleteModel':
                if (window.confirm(t('panels.model_props.delete_confirm', { id: selectedModelId }))) {
                    viewer.deleteModel(selectedModelId);
                    onModelSelect(null);
                }
                break;
            case 'position':
                viewer.moveModelTo(selectedModelId, value);
                break;
            case 'rotation':
                viewer.rotateModelByEuler?.(selectedModelId, value[0], value[1], value[2], 'XYZ', false);
                break;
            case 'label':
                viewer.updateModelLabel?.(selectedModelId, value);
                break;
            case 'name':
                viewer.updateModelObject3DName?.(selectedModelId, value);
                break;
            case 'torch':
                if (value) {
                    const torchObjects = ['headlight_L', 'headlight_R', 'eye_L', 'eye_R', 'Spark', 'welding_spark'];
                    viewer.addTorchLightsToModel?.(selectedModelId, torchObjects, { intensity: 5, distance: 10 });
                } else {
                    viewer.removeTorchLightsFromModel?.(selectedModelId);
                }
                break;
            case 'modelLights':
                viewer.setModelLightControl?.(selectedModelId, value);
                break;
            case 'addEffect':
                viewer.addModelEffect?.(selectedModelId, value);
                break;
            case 'toggleEffect':
                if (value.isOn) {
                    viewer.addModelEffect?.(selectedModelId, value.type);
                } else {
                    const effectId = viewer.getModelEffectId?.(selectedModelId, value.type);
                    if (effectId) {
                        viewer.removeModelEffect?.(selectedModelId, effectId);
                    }
                }
                break;
            case 'clearEffects':
                viewer.removeAllModelEffects?.(selectedModelId);
                break;
            case 'objectPosition':
                viewer.setModelPosition(selectedModelId, value.objectName, value.value.x, value.value.y, value.value.z);
                break;
            case 'objectRotation':
                viewer.setModelRotation(selectedModelId, value.objectName, value.value.x, value.value.y, value.value.z);
                break;
            case 'startContinuousMove':
                viewer.startModelContinuousMove?.(selectedModelId, value.direction, value.speed);
                break;
            case 'stopContinuousMove':
                viewer.stopModelContinuousMove?.(selectedModelId);
                break;
            default:
                viewer.updateModelProperty(selectedModelId, property, value);
                break;
        }
    };

    return (
        <div className="model-control-panel">
            <div className="control-item">
                <label className="control-label">{t('panels.model_main.select_model')}</label>
                <select
                    className="dt-select"
                    value={selectedModelId || ''}
                    onChange={(e) => onModelSelect(e.target.value || null)}
                >
                    <option value="">{t('panels.model_main.placeholder')}</option>
                    {models.map(m => (
                        <option key={m.id} value={m.id}>{m.label || m.id}</option>
                    ))}
                </select>
            </div>

            {selectedModel ? (
                <>
                    <ModelPropsPanel
                        model={selectedModel}
                        onUpdate={(prop, val) => handleUpdateModelProp(prop, val)}
                    />

                    <ModelEffectPanel
                        modelId={selectedModelId}
                        onUpdate={(prop, val) => handleUpdateModelProp(prop, val)}
                    />

                    <ModelObjectControlPanel
                        viewer={viewer}
                        modelId={selectedModelId!}
                        onUpdate={(prop, val) => handleUpdateModelProp(prop, val)}
                    />

                    <ModelRenderPanel
                        viewer={viewer}
                        modelId={selectedModelId}
                    />

                    <AnimationControlPanel
                        clips={clips}
                        playingName={playingName}
                        onUpdate={(prop, val) => handleUpdateModelProp(prop, val)}
                    />

                    <div className="control-section">
                        <div className="section-title" onClick={() => setIsPatternCollapsed(!isPatternCollapsed)}>
                            <span>{t('panels.model_main.pattern_sim')}</span>
                            <span>{isPatternCollapsed ? '▼' : '▲'}</span>
                        </div>
                        {!isPatternCollapsed && (
                            <ModelPatternPanel
                                viewer={viewer}
                                selectedModelId={selectedModelId}
                            />
                        )}
                        {isPatternCollapsed && <div className="status-info">{t('panels.model_main.pattern_description')}</div>}
                    </div>

                    <div className="status-info" style={{ marginTop: 15 }}>
                        ID: {selectedModel.id}<br />
                        Path: {selectedModel.path}
                    </div>
                </>
            ) : (
                <div className="placeholder-message">
                    {t('panels.model_main.no_selection')}
                </div>
            )}
        </div>
    );
};

export default ModelControlPanel;
