import React, { useState, useRef, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import './ControlPanel.css';
import EnvironmentPanel from './EnvironmentPanel';
import ModelControlPanel from '@/platforms/dt-robot/pages/dashboard/components/ControlPanel/ModelControlPanel';
import type EnhancedThreeViewer from '@/platforms/dt-robot/lib/EnhancedThreeViewer';

interface Props {
    viewer: EnhancedThreeViewer | null;
    models: any[];
    selectedModelId: string | null;
    onModelSelect: (id: string | null) => void;
}

const ControlPanel: React.FC<Props> = ({ viewer, models, selectedModelId, onModelSelect }) => {
    const { t } = useTranslation('dt-robot');
    const [selectedTab, setSelectedTab] = useState(0);
    const [isPanelOpen, setIsPanelOpen] = useState(true);
    const [isPinned, setIsPinned] = useState(false);
    const [position, setPosition] = useState({ x: 20, y: 20 });
    const [isDragging, setIsDragging] = useState(false);
    const dragStart = useRef({ x: 0, y: 0 });
    const initialPos = useRef({ x: 0, y: 0 });

    const tabs = [
        { name: 'environment', label: t('tabs.environment') },
        { name: 'model', label: t('tabs.model') }
    ];

    const startDrag = (e: React.MouseEvent) => {
        if (isPinned) return;
        setIsDragging(true);
        dragStart.current = { x: e.clientX, y: e.clientY };
        initialPos.current = { ...position };

        window.addEventListener('mousemove', handleDrag as any);
        window.addEventListener('mouseup', stopDrag as any);
    };

    const handleDrag = (e: MouseEvent) => {
        const dx = e.clientX - dragStart.current.x;
        const dy = e.clientY - dragStart.current.y;

        let nx = initialPos.current.x + dx;
        let ny = initialPos.current.y + dy;

        // Boundary checks
        nx = Math.max(0, Math.min(window.innerWidth - (isPinned ? 50 : 400), nx));
        ny = Math.max(0, Math.min(window.innerHeight - 50, ny));

        setPosition({ x: nx, y: ny });
    };

    const stopDrag = () => {
        setIsDragging(false);
        window.removeEventListener('mousemove', handleDrag as any);
        window.removeEventListener('mouseup', stopDrag as any);
    };

    const togglePin = () => {
        setIsPinned(!isPinned);
        if (!isPinned) {
            setIsPanelOpen(true);
            setPosition({ x: 10, y: 20 });
        } else {
            setPosition({ x: 20, y: 20 });
        }
    };

    const panelStyle: React.CSSProperties = {
        left: position.x,
        top: position.y,
        width: isPinned ? 50 : 400,
        maxHeight: isPanelOpen ? '80vh' : 40,
    };

    return (
        <div
            className={`dt-control-panel ${!isPanelOpen ? 'is-collapsed' : ''} ${isPinned ? 'is-pinned' : ''}`}
            style={panelStyle}
        >
            <div className="panel-header" onMouseDown={startDrag}>
                {!isPinned && <h3>{t('tabs.digital_twin')}</h3>}
                <div className="header-actions">
                    <button className="action-btn" onClick={togglePin}>
                        {isPinned ? '📌' : '📍'}
                    </button>
                    {!isPinned && (
                        <button className="action-btn" onClick={() => setIsPanelOpen(!isPanelOpen)}>
                            {isPanelOpen ? '⬆' : '⬇'}
                        </button>
                    )}
                </div>
            </div>

            {isPanelOpen && !isPinned && (
                <>
                    <div className="panel-tabs">
                        {tabs.map((tab, idx) => (
                            <div
                                key={tab.name}
                                className={`tab-item ${selectedTab === idx ? 'active' : ''}`}
                                onClick={() => setSelectedTab(idx)}
                            >
                                {tab.label}
                            </div>
                        ))}
                    </div>
                    <div className="panel-content">
                        {selectedTab === 0 ? (
                            <EnvironmentPanel viewer={viewer} />
                        ) : (
                            <ModelControlPanel
                                viewer={viewer}
                                models={models}
                                selectedModelId={selectedModelId}
                                onModelSelect={onModelSelect}
                            />
                        )}
                    </div>
                </>
            )}
        </div>
    );
};

export default ControlPanel;
