// src/strategies/CompositeLoadingStrategy.js

//import FBXLoadingStrategy from './FBXLoadingStrategy'
//import GLTFLoadingStrategy from './GLTFLoadingStrategy'
import ModelLoadingStrategy from './ModelLoadingStrategy'

export default class CompositeLoadingStrategy extends ModelLoadingStrategy {
  constructor(strategies = []) {
    super()
    this.strategies = {}

    for (const strategy of strategies) {
      if (strategy instanceof ModelLoadingStrategy) {
        const extList = strategy.supportedExtensions || []
        for (const ext of extList) this.strategies[ext] = strategy
      }
    }
  }

  getExtension(filePath) {
    const parts = filePath.split('.')
    return parts.pop().toLowerCase()
  }

  async loadModelInstance(viewer, modelData) {
    const ext = this.getExtension(modelData.path)
    const strategy = this.strategies[ext]
    if (!strategy) throw new Error(`지원하지 않는 확장자: ${ext}`)
    return strategy.loadModelInstance(viewer, modelData)
  }

  disposeModel(model) {
    const ext = this.getExtension(model.userData?.path || model.name)
    const strategy = this.strategies[ext]
    if (strategy?.disposeModel) {
      strategy.disposeModel(model)
    } else {
      console.warn(`[CompositeLoadingStrategy] disposeModel 미지원 확장자: ${ext}`)
    }
  }
}
