// src/core/PostProcessingManager.js
import * as THREE from 'three'
import { EffectComposer } from 'three/examples/jsm/postprocessing/EffectComposer.js'
import { RenderPass } from 'three/examples/jsm/postprocessing/RenderPass.js' // 필요 없음 (RenderPass는 Strategy가 관리)
import { OutlinePass } from 'three/examples/jsm/postprocessing/OutlinePass.js'
import { ShaderPass } from 'three/examples/jsm/postprocessing/ShaderPass.js'
import { FXAAShader } from 'three/examples/jsm/shaders/FXAAShader.js'
import { UnrealBloomPass } from 'three/examples/jsm/postprocessing/UnrealBloomPass.js'

/**
 * Three.js 씬에 후처리 효과(아웃라인, 블룸 등)를 적용하고 관리하는 클래스입니다.
 */
export default class PostProcessingManager {
  /**
   * @param {THREE.Scene} scene 씬 객체
   * @param {THREE.Camera} camera 카메라 객체
   * @param {THREE.WebGLRenderer} renderer 렌더러 객체
   * @param {HTMLElement} container 뷰어가 렌더링될 DOM 요소 (크기 조정용)
   * @param {EffectComposer} composer PostProcessingRendererStrategy로부터 전달받은 EffectComposer 인스턴스
   */
  constructor(scene, camera, renderer, container, composer) {
    // composer 인자를 추가
    this.scene = scene
    this.camera = camera
    this.renderer = renderer
    this.container = container
    this.composer = composer // PostProcessingRendererStrategy가 관리하는 composer를 사용

    this.outlinePass = null
    this.bloomPass = null
    this.fxaaPass = null

    this._setupPasses() // 패스 설정 메서드 이름 변경 (컴포저 설정이 아니므로)
    this._setupEventListeners()

    // 선택된 모델을 위한 참조 (OutlinePass에 전달할 객체 배열)
    this.selectedObjects = []
  }

  /**
   * EffectComposer에 추가할 패스들을 설정합니다.
   * 이 메서드는 생성자에서 한 번만 호출됩니다.
   */
  _setupPasses() {
    // _setupComposer에서 _setupPasses로 변경
    // 아웃라인 패스 설정
    this.outlinePass = new OutlinePass(
      new THREE.Vector2(this.container.clientWidth, this.container.clientHeight),
      this.scene,
      this.camera,
    )
    this.outlinePass.edgeStrength = 5.0 // 외곽선 강도 (두께)
    this.outlinePass.edgeGlow = 0.5 // 외곽선 발광 정도
    this.outlinePass.edgeDetectionMode = 2 // NORMAL 모드
    this.outlinePass.visibleEdgeColor.set('#FF8800') // 선택 모델의 외곽선 색상 (밝은 주황)
    this.outlinePass.hiddenEdgeColor.set('#440a00') // 가려진 외곽선 색상
    this.outlinePass.pulsePeriod = 0 // 0으로 설정하면 깜빡임 효과 없음
    this.composer.addPass(this.outlinePass) // composer에 추가

    // 블룸 패스 (발광 효과) 설정
    this.bloomPass = new UnrealBloomPass(
      new THREE.Vector2(this.container.clientWidth, this.container.clientHeight),
      1.5, // strength: 블룸 효과의 강도. 높을수록 밝아짐.
      0.5, // radius: 블룸이 퍼지는 반경. 높을수록 넓게 퍼짐.
      0.8, // threshold: 이 값보다 밝은 픽셀에만 블룸이 적용됨. 낮을수록 더 많은 부분이 블룸됨.
    )
    // 초기에는 블룸 패스를 composer에 추가하지 않습니다. applyEffect에서 제어

    // FXAA (Fast Approximate Anti-aliasing) 패스 설정
    this.fxaaPass = new ShaderPass(FXAAShader)
    this.fxaaPass.material.uniforms['resolution'].value.set(
      1 / this.container.clientWidth,
      1 / this.container.clientHeight,
    )
    this.composer.addPass(this.fxaaPass) // composer에 추가
  }

  /**
   * 리사이즈 이벤트 리스너를 설정합니다. (여전히 필요)
   * @private
   */
  _setupEventListeners() {
    window.addEventListener('resize', this._onResize.bind(this))
  }

  /**
   * 창 크기 변경 시 컴포저 및 패스들을 업데이트합니다. (이제 이 매니저가 패스들을 소유하므로 여기에서 처리)
   * @private
   */
  _onResize() {
    const width = this.container.clientWidth
    const height = this.container.clientHeight

    // PostProcessingManager는 렌더러의 크기를 직접 설정하지 않음. 이는 EnhancedThreeViewer나 Strategy가 해야 할 일.
    // this.renderer.setSize(width, height);
    if (this.composer) {
      this.composer.setSize(width, height)
    }

    if (this.outlinePass) {
      this.outlinePass.resolution.set(width, height)
    }
    if (this.bloomPass) {
      this.bloomPass.resolution.set(width, height)
    }
    if (this.fxaaPass) {
      this.fxaaPass.material.uniforms['resolution'].value.set(1 / width, 1 / height)
    }
  }

  /**
   * 선택된 객체에 아웃라인 효과를 적용합니다.
   * @param {THREE.Object3D|null} object 아웃라인을 적용할 객체 (THREE.Object3D) 또는 null
   */
  selectObject(object) {
    this.selectedObjects.length = 0 // 기존 선택 해제
    if (object) {
      object.traverse((child) => {
        if (child.isMesh) {
          this.selectedObjects.push(child)
        }
      })
    }
    this.outlinePass.selectedObjects = this.selectedObjects
  }

  /**
   * 특정 모델의 상태에 따라 후처리 효과를 적용합니다.
   * @param {string} modelId 상태를 변경할 모델의 ID
   * @param {THREE.Object3D} model 해당 모델의 Three.js 객체
   * @param {string} status 새로운 상태 ('normal', 'fire', 'smoke', 'spark' 등)
   */
  applyEffect(modelId, model, status) {
    // 모든 효과 초기화 (상태 변경 시 이전 효과 제거)
    this.selectObject(null) // 현재 선택된 객체 아웃라인 해제
    this.bloomPass.strength = 0 // 블룸 강도를 0으로 설정하여 비활성화

    // 블룸 패스가 컴포저에 있다면 제거하여 초기 상태로 만듭니다.
    if (this.composer.passes.includes(this.bloomPass)) {
      this.composer.removePass(this.bloomPass)
    }

    // 특정 상태에 따른 효과 적용
    if (status === 'fire' || status === 'spark') {
      this.outlinePass.visibleEdgeColor.set('#FF0000') // 강렬한 빨간색 아웃라인
      this.selectObject(model) // 모델에 아웃라인 적용

      this.bloomPass.strength = 1.8
      this.bloomPass.radius = 0.8
      this.bloomPass.threshold = 0.8

      // 블룸 패스가 아직 컴포저에 추가되지 않았다면 추가합니다.
      // FXAA 이전에 블룸을 추가하여 블룸된 결과에 FXAA가 적용되도록 합니다.
      const fxaaIndex = this.composer.passes.indexOf(this.fxaaPass)
      if (fxaaIndex !== -1 && !this.composer.passes.includes(this.bloomPass)) {
        this.composer.insertPass(this.bloomPass, fxaaIndex)
      } else if (fxaaIndex === -1 && !this.composer.passes.includes(this.bloomPass)) {
        // FXAA가 없는 경우, 마지막에 추가
        this.composer.addPass(this.bloomPass)
      }
    } else if (status === 'smoke') {
      this.outlinePass.visibleEdgeColor.set('#0000FF') // 파란색 아웃라인
      this.selectObject(model) // 모델에 아웃라인 적용
    } else {
      this.outlinePass.visibleEdgeColor.set('#FF8800') // 기본 아웃라인 색상으로 되돌리기
      this.removeEffect(modelId) // 완전히 효과 제거
    }
  }

  /**
   * 모델의 상태 효과를 제거합니다.
   * @param {string} modelId 효과를 제거할 모델의 ID
   */
  removeEffect(modelId) {
    // 선택된 객체 배열에서 해당 모델 제거
    this.selectedObjects = this.selectedObjects.filter((obj) => obj.userData.id !== modelId)
    this.outlinePass.selectedObjects = this.selectedObjects

    // 모든 선택 객체가 없어지면 블룸 효과 비활성화 및 컴포저에서 제거
    if (this.selectedObjects.length === 0) {
      this.bloomPass.strength = 0
      if (this.composer.passes.includes(this.bloomPass)) {
        this.composer.removePass(this.bloomPass)
      }
    }
    // 아웃라인 색상을 기본으로 되돌림 (선택 객체가 없으므로 보이지는 않지만 상태 일관성)
    this.outlinePass.visibleEdgeColor.set('#FF8800')
  }

  /**
   * 후처리 효과를 렌더링합니다. (이 메서드는 이제 PostProcessingRendererStrategy에서만 호출되어야 함)
   * 이 Manager 자체는 렌더링을 직접 트리거하지 않고, 패스를 설정하고 관리하는 역할만 함.
   * 하지만 기존 EnhancedThreeViewer에서 PostProcessingManager의 render를 호출하고 있었으므로,
   * PostProcessingRendererStrategy가 EffectComposer를 소유하고 render를 호출하는 방식으로 수정되었습니다.
   * 따라서 이 render 메서드는 더 이상 외부에서 호출되지 않을 수 있습니다.
   * 하지만 현재의 코딩 스타일을 유지하기 위해 이 메서드를 제거하지 않고, 대신 이 메서드 내부의 로직이
   * PostProcessingRendererStrategy의 render에서 이루어지도록 변경했음을 명시합니다.
   */
  render(delta) {
    // 이 render 메서드는 PostProcessingManager가 패스들을 관리하고 EffectComposer를 직접 호출하던 이전 역할에서
    // PostProcessingRendererStrategy가 EffectComposer를 소유하고 렌더링을 담당하는 역할로 변경됨에 따라
    // 더 이상 외부에서 직접 호출될 필요가 없습니다.
    // 모든 패스는 이미 EffectComposer에 추가되어 있으므로, Composer가 render될 때 함께 처리됩니다.
    // 필요한 경우, PostProcessingManager의 내부 상태에 따라 패스의 enable/disable을 제어할 수 있습니다.
  }

  /** 모든 리소스를 해제합니다. */
  dispose() {
    window.removeEventListener('resize', this._onResize.bind(this))

    // 각 패스들이 리소스를 해제하도록 dispose()를 호출
    if (this.outlinePass) {
      this.outlinePass.dispose()
      // composer에서 패스 제거
      if (this.composer && this.composer.passes.includes(this.outlinePass)) {
        this.composer.removePass(this.outlinePass)
      }
    }
    if (this.bloomPass) {
      // UnrealBloomPass는 명시적인 dispose() 메서드를 보통 제공하지 않습니다.
      if (this.composer && this.composer.passes.includes(this.bloomPass)) {
        this.composer.removePass(this.bloomPass)
      }
    }
    if (this.fxaaPass) {
      // FXAAShaderPass는 명시적인 dispose() 메서드를 보통 제공하지 않습니다.
      if (this.composer && this.composer.passes.includes(this.fxaaPass)) {
        this.composer.removePass(this.fxaaPass)
      }
    }

    console.log('PostProcessingManager: 모든 후처리 패스 리소스를 해제했습니다.')
  }
}
