import React from 'react';
import { Modal, Table } from 'antd';
import ReactECharts from 'echarts-for-react';
import type { EChartsOption } from 'echarts';
import { useTranslation } from 'react-i18next';

interface FpsData {
    time: string;
    fps: number;
}

interface Props {
    visible: boolean;
    onClose: () => void;
    data: FpsData[];
}

const FpsHistoryModal: React.FC<Props> = ({ visible, onClose, data }) => {
    const { t } = useTranslation('dt-robot');

    // 차트 옵션 설정
    const getOption = (): EChartsOption => {
        return {
            backgroundColor: 'transparent',
            title: {
                text: t('modals.fps_history.title'),
                left: 'center',
                textStyle: { color: 'var(--ms-color-text, #ffffff)', fontSize: 16 }
            },
            tooltip: {
                trigger: 'axis',
                backgroundColor: 'rgba(20, 20, 20, 0.9)',
                borderColor: 'var(--ms-color-primary, #1677ff)',
                textStyle: { color: '#ffffff' },
                formatter: (params: any) => {
                    const p = params[0];
                    return `${p.name}<br/><b>FPS: ${p.value}</b>`;
                }
            },
            grid: {
                left: '8%',
                right: '5%',
                top: '20%',
                bottom: '12%',
            },
            xAxis: {
                type: 'category',
                data: data.map(item => item.time.split('T')[1].split('.')[0]),
                axisLine: { lineStyle: { color: 'rgba(255, 255, 255, 0.3)' } },
                axisLabel: { color: 'var(--ms-color-text-secondary, #aaa)', fontSize: 10 }
            },
            yAxis: {
                type: 'value',
                min: 0,
                max: 70,
                axisLine: { lineStyle: { color: 'rgba(255, 255, 255, 0.3)' } },
                splitLine: { lineStyle: { color: 'rgba(255, 255, 255, 0.1)' } },
                axisLabel: { color: 'var(--ms-color-text-secondary, #aaa)' }
            },
            series: [
                {
                    name: 'FPS',
                    type: 'line',
                    smooth: true,
                    showSymbol: false,
                    data: data.map(item => item.fps),
                    itemStyle: { color: 'var(--ms-color-primary, #1677ff)' },
                    areaStyle: {
                        color: {
                            type: 'linear',
                            x: 0, y: 0, x2: 0, y2: 1,
                            colorStops: [
                                { offset: 0, color: 'rgba(22, 119, 255, 0.5)' },
                                { offset: 1, color: 'transparent' }
                            ]
                        }
                    }
                }
            ]
        };
    };

    return (
        <Modal
            title={<span style={{ color: 'var(--ms-color-text, #fff)' }}>{t('modals.fps_history.report_title')}</span>}
            open={visible}
            onCancel={onClose}
            footer={null}
            width={800}
            centered
            style={{
                backgroundColor: 'var(--ms-color-bg-container, #1f1f1f)',
                borderRadius: '12px',
                border: '1px solid var(--ms-border-color, rgba(255, 255, 255, 0.1))',
                boxShadow: '0 8px 32px rgba(0, 0, 0, 0.5)'
            }}
            styles={{
                mask: { backdropFilter: 'blur(4px)' },
                body: {
                    backgroundColor: 'var(--ms-color-bg-container, #1f1f1f)',
                    padding: '20px',
                    borderRadius: '0 0 12px 12px'
                }
            }}
        >
            <div style={{ height: '400px', width: '100%' }}>
                <ReactECharts
                    option={getOption()}
                    style={{ height: '100%', width: '100%' }}
                    notMerge={true}
                    lazyUpdate={true}
                />
            </div>
            <div style={{ marginTop: '20px' }}>
                <Table
                    size="small"
                    dataSource={data.slice().reverse()}
                    pagination={{ pageSize: 5 }}
                    columns={[
                        { title: t('modals.fps_history.col_time'), dataIndex: 'time', key: 'time', render: (t) => t.split('T')[1].split('.')[0] },
                        { title: t('modals.fps_history.col_fps'), dataIndex: 'fps', key: 'fps', render: (f) => <span style={{ color: f < 30 ? '#ff4d4f' : '#52c41a' }}>{f}</span> }
                    ]}
                    rowKey="time"
                />
            </div>
        </Modal>
    );
};

export default FpsHistoryModal;
