import mqtt from 'mqtt'

class MqttManager {
  constructor({ brokerUrl, topics = [], username, password, onMessage }) {
    this.client = null
    this.brokerUrl = brokerUrl || 'ws://localhost:1883' // 기본 브로커 URL
    this.username = username || 'kiot'
    this.password = password || 'kiot!@34'
    this.subscribedTopics = topics
    this.messageCallback = onMessage

    console.log(`MQTT Manager initialized with broker: ${this.brokerUrl}`)

    this.createClient()
  }

  // 클라이언트 생성
  createClient(onMessage) {
    if (this.client) {
      console.warn('MQTT 클라이언트가 이미 생성되었습니다.')
      return
    }

    console.log(`Connecting to MQTT broker at: ${this.brokerUrl}`)
    // HTTPS 환경인 경우 강제로 WSS로 간주하여 브라우저 차단 방지
    const isSecurePage = window.location.protocol === 'https:'
    const useWss = isSecurePage || this.brokerUrl.startsWith('wss://')
    
    // 주소 정규화
    if (isSecurePage && this.brokerUrl.startsWith('ws://')) {
      this.brokerUrl = this.brokerUrl.replace('ws://', 'wss://')
    }

    const options = {
      username: this.username,
      password: this.password,
      reconnectPeriod: 10000, 
      connectTimeout: 10000, 
    }

    // WSS 연결 시 port 8083이 강제되면 라이브러리가 WS로 오해할 수 있으므로 분기 처리
    if (!useWss) {
      options.port = 8083
    }

    // Use WebSocket URL directly if applicable
    const isWebSocket = this.brokerUrl.startsWith('ws://') || this.brokerUrl.startsWith('wss://')
    this.client = isWebSocket
      ? mqtt.connect(this.brokerUrl, options)
      : mqtt.connect({ host: this.brokerUrl, port: useWss ? 8084 : 8083, ...options })

    this.client.on('connect', () => {
      console.log('MQTT 클라이언트 연결 성공', this.brokerUrl)
      this._subscribeToTopics()
    })

    this.client.on('reconnect', () => {
      console.log('MQTT 클라이언트 재접속 시도 중...', this.brokerUrl)
    })

    this.client.on('error', (err) => {
      console.error('MQTT 클라이언트 오류:', err)
    })

    this.client.on('close', () => {
      console.warn('MQTT 클라이언트 연결이 종료되었습니다.', this.brokerUrl)
    })
  }

  // 클라이언트 파괴
  destroyClient() {
    if (this.client) {
      this.client.end(() => {
        console.log('MQTT 클라이언트 연결 종료')
      })
      this.client = null
      this.subscribedTopics = []
      this.messageCallback = null
    } else {
      console.warn('MQTT 클라이언트가 존재하지 않습니다.')
    }
  }

  // 토픽 구독
  _subscribeToTopics() {
    if (!this.client || !this.subscribedTopics.length) return

    this.subscribedTopics.forEach((topic) => {
      this.client.subscribe(topic, (err) => {
        if (!err) {
          console.log(`토픽 "${topic}" 구독 성공`)
        } else {
          console.error(`토픽 "${topic}" 구독 실패:`, err)
        }
      })
    })

    // 메시지 수신 시 부모로 전달
    this.client.on('message', (topic, message) => {
      // console.log(`수신된 메시지 [${topic}]: ${message.toString()}`)
      if (this.messageCallback) this.messageCallback(topic, message.toString())
    })
  }
}

export default MqttManager
