import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';

interface Props {
    modelId: string | null;
    onUpdate: (property: string, value: any) => void;
}

const ModelEffectPanel: React.FC<Props> = ({ modelId, onUpdate }) => {
    const { t } = useTranslation('dt-robot');
    const [isCollapsed, setIsCollapsed] = useState(true);
    const [torchOn, setTorchOn] = useState(false);
    const [modelLightsOn, setModelLightsOn] = useState(true);
    const [activeEffects, setActiveEffects] = useState<Record<string, boolean>>({
        fire: false,
        smoke: false,
        water: false
    });

    const effectTypes = [
        { id: 'fire', label: `🔥 ${t('panels.model_effect.effects.fire')}` },
        { id: 'smoke', label: `💨 ${t('panels.model_effect.effects.smoke')}` },
        { id: 'water', label: `💦 ${t('panels.model_effect.effects.water')}` }
    ];

    const toggleTorch = () => {
        const next = !torchOn;
        setTorchOn(next);
        onUpdate('torch', next);
    };

    const toggleModelLights = () => {
        const next = !modelLightsOn;
        setModelLightsOn(next);
        onUpdate('modelLights', next);
    };

    const toggleEffect = (effectId: string) => {
        const next = !activeEffects[effectId];
        setActiveEffects(prev => ({ ...prev, [effectId]: next }));
        onUpdate('toggleEffect', { type: effectId, isOn: next });
    };

    return (
        <div className="control-section">
            <div className="section-title" onClick={() => setIsCollapsed(!isCollapsed)}>
                <span>{t('panels.model_effect.title')}</span>
                <span>{isCollapsed ? '▼' : '▲'}</span>
            </div>

            {!isCollapsed && (
                <div className="control-body">
                    <div className="control-item">
                        <div className="control-row">
                            <label className="control-label" style={{ flex: 1, marginBottom: 0 }}>{t('panels.model_effect.torch')}</label>
                            <input
                                type="checkbox"
                                checked={torchOn}
                                onChange={toggleTorch}
                                className="dt-switch"
                            />
                        </div>
                    </div>

                    <div className="control-item">
                        <div className="control-row">
                            <label className="control-label" style={{ flex: 1, marginBottom: 0 }}>{t('panels.model_effect.model_lights')}</label>
                            <input
                                type="checkbox"
                                checked={modelLightsOn}
                                onChange={toggleModelLights}
                                className="dt-switch"
                            />
                        </div>
                    </div>

                    <div className="control-item divider-top">
                        <label className="control-label">{t('panels.model_effect.env_effects')}</label>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
                            {effectTypes.map(type => (
                                <div key={type.id} className="control-row">
                                    <label className="control-label" style={{ flex: 1, marginBottom: 0 }}>{type.label}</label>
                                    <input
                                        type="checkbox"
                                        checked={activeEffects[type.id]}
                                        onChange={() => toggleEffect(type.id)}
                                        className="dt-switch"
                                    />
                                </div>
                            ))}
                            <button
                                className="delete-btn"
                                style={{ marginTop: 8, padding: '4px' }}
                                onClick={() => {
                                    setActiveEffects({ fire: false, smoke: false, water: false });
                                    onUpdate('clearEffects', true);
                                }}
                            >
                                {t('panels.model_effect.clear_all')}
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {isCollapsed && <div className="status-info">{t('panels.model_effect.description')}</div>}
        </div>
    );
};

export default ModelEffectPanel;
