import { CSS2DRenderer, CSS2DObject } from 'three/examples/jsm/renderers/CSS2DRenderer.js'
import * as THREE from 'three'

export default class LabelManager {
  constructor(container, scene, camera, renderer) {
    this.container = container
    this.scene = scene
    this.camera = camera
    this.renderer = renderer // WebGLRenderer 인스턴스 (사이즈 참조용)
    this.labels = new Map() // id -> { labelObject, element, parent }
    this.worldPosition = new THREE.Vector3()
    this._setupLabelRenderer()
  }

  _setupLabelRenderer() {
    this.labelRenderer = new CSS2DRenderer()
    this.labelRenderer.setSize(this.container.clientWidth, this.container.clientHeight)
    this.labelRenderer.domElement.style.position = 'absolute'
    this.labelRenderer.domElement.style.top = '0px'
    this.labelRenderer.domElement.style.pointerEvents = 'none' // 마우스 이벤트 무시
    this.container.appendChild(this.labelRenderer.domElement)
  }

  /**
   * 3D 객체 또는 특정 위치에 HTML 라벨을 추가합니다.
   * @param {string} id 라벨의 고유 ID (중복 불가능)
   * @param {THREE.Object3D | THREE.Vector3} target 라벨을 붙일 3D 객체 또는 월드 좌표
   * @param {string} text 라벨에 표시할 텍스트
   * @param {object} options 추가 옵션: { className: string, isBillboard: boolean, offset: THREE.Vector3, style: object }
   * style: { color: 'black', background: 'rgba(255,255,255,0.7)', textShadow: '1px 1px 2px black' }
   * @param {THREE.Object3D} parentObject (선택 사항) 라벨이 자식으로 추가될 부모 Object3D. 지정하면 라벨은 부모의 로컬 좌표계를 따릅니다.
   */
  addLabel(id, target, text, options = {}, parentObject = null) {
    if (this.labels.has(id)) {
      console.warn(`Label with ID '${id}' already exists. Skipping.`)
      return
    }

    const element = document.createElement('div')
    element.className = 'label' // 기본 label 클래스는 유지 (공통 스타일)
    element.textContent = text

    if (options.className) {
      element.className += ` ${options.className}` // 추가 클래스도 유지
    }

    // ⭐⭐⭐ 추가된 부분: options.style 객체를 사용하여 인라인 스타일 적용 ⭐⭐⭐
    if (options.style) {
      for (const key in options.style) {
        if (Object.hasOwn(options.style, key)) {
          element.style[key] = options.style[key]
        }
      }
    }

    const labelObject = new CSS2DObject(element)
    labelObject.isBillboard = options.isBillboard ?? false

    if (target instanceof THREE.Object3D) {
      labelObject.position.copy(target.position)
      if (options.offset) {
        labelObject.position.add(options.offset)
      }
    } else if (target instanceof THREE.Vector3) {
      labelObject.position.copy(target)
      if (options.offset) {
        labelObject.position.add(options.offset)
      }
    } else {
      console.error('Invalid target for label. Must be Object3D or Vector3.')
      return
    }

    if (parentObject) {
      parentObject.add(labelObject)
    } else {
      this.scene.add(labelObject)
    }

    this.labels.set(id, { labelObject, element, parent: parentObject })
  }

  /**
   * 라벨의 텍스트를 업데이트합니다.
   * @param {string} id 라벨 ID
   * @param {string} newText 새 텍스트
   */
  updateLabelText(id, newText) {
    const labelEntry = this.labels.get(id)
    if (labelEntry) {
      labelEntry.element.textContent = newText
    }
  }

  /**
   * 라벨의 위치를 업데이트합니다.
   * @param {string} id 라벨 ID
   * @param {THREE.Vector3} newPosition 새 위치 (부모가 있다면 부모의 로컬, 없다면 월드)
   */
  updateLabelPosition(id, newPosition) {
    const labelEntry = this.labels.get(id)
    if (labelEntry) {
      labelEntry.labelObject.position.set(...newPosition)
    }
  }

  /**
   * 라벨의 가시성을 설정합니다.
   * @param {string} id 라벨 ID
   * @param {boolean} visible 가시성 상태
   */
  setLabelVisibility(id, visible) {
    const labelEntry = this.labels.get(id)
    if (labelEntry) {
      labelEntry.labelObject.visible = visible
    }
  }

  /**
   * 라벨을 제거합니다.
   * @param {string} id 라벨 ID
   */
  removeLabel(id) {
    const labelEntry = this.labels.get(id)
    if (labelEntry) {
      if (labelEntry.parent) {
        labelEntry.parent.remove(labelEntry.labelObject)
      } else {
        this.scene.remove(labelEntry.labelObject)
      }
      labelEntry.element.remove()
      this.labels.delete(id)
    }
  }

  updateSize(width, height) {
    this.labelRenderer.setSize(width, height)
  }

  render() {
    this.labelRenderer.render(this.scene, this.camera)
  }

  dispose() {
    this.labelRenderer.domElement.remove()
    this.labels.forEach((labelEntry) => {
      if (labelEntry.parent) {
        labelEntry.parent.remove(labelEntry.labelObject)
      } else {
        this.scene.remove(labelEntry.labelObject)
      }
      labelEntry.element.remove()
    })
    this.labels.clear()
  }
}
