import * as THREE from 'three'
import { EffectComposer } from 'three/examples/jsm/postprocessing/EffectComposer.js'
import { RenderPass } from 'three/examples/jsm/postprocessing/RenderPass.js'
import { UnrealBloomPass } from 'three/examples/jsm/postprocessing/UnrealBloomPass.js' // 사용되지 않을 수 있으나 기존 코드에 있었으므로 유지

export default class PostProcessingRendererStrategy {
  constructor(scene, camera, renderer, container, options = {}) {
    this.scene = scene
    this.camera = camera
    this.renderer = renderer
    this.container = container
    this.enablePostProcessing = options.enablePostProcessing ?? false

    this.width = container.clientWidth
    this.height = container.clientHeight

    this.composer = null // EffectComposer를 여기에 선언
    this.renderPass = null

    this._initComposer()
  }

  _initComposer() {
    // PostProcessingRendererStrategy가 EffectComposer를 소유하고 관리합니다.
    this.composer = new EffectComposer(this.renderer)
    // RenderPass는 PostProcessingRendererStrategy가 관리합니다.
    this.renderPass = new RenderPass(this.scene, this.camera)
    this.composer.addPass(this.renderPass)
    // 이전 코드에서 RenderTarget이 사용되었으나, EffectComposer는 기본적으로 렌더러의 타겟을 사용합니다.
    // 만약 renderTarget이 명시적으로 필요하다면 다시 추가할 수 있습니다.
  }

  // 외부(PostProcessingManager)에서 패스를 추가할 수 있도록 메서드 제공
  addPass(pass) {
    if (this.composer) {
      this.composer.addPass(pass)
    }
  }

  // 외부(PostProcessingManager)에서 패스를 제거할 수 있도록 메서드 제공
  removePass(pass) {
    if (this.composer) {
      this.composer.removePass(pass)
    }
  }

  // EffectComposer 인스턴스를 반환하여 PostProcessingManager가 접근할 수 있도록 함
  getComposer() {
    return this.composer
  }

  render(delta) {
    if (this.enablePostProcessing && this.composer) {
      this.composer.render(delta)
    } else {
      this.renderer.render(this.scene, this.camera)
    }
  }

  selectObject(object) {}

  _onResize() {
    const width = this.container.clientWidth
    const height = this.container.clientHeight

    this.renderer.setSize(width, height)
    if (this.composer) {
      this.composer.setSize(width, height)
      // 이전에 bloom 패스 해상도 조절 로직이 여기에 있었으나,
      // 이제 bloom 패스는 PostProcessingManager에서 관리하므로 PostProcessingManager에서 처리하도록 합니다.
      // this.passes.bloom && this.passes.bloom.resolution.set(width, height)
    }
    // 카메라 해상도 업데이트는 CameraController에서 담당
    // 카메라 비율 업데이트는 EnhancedThreeViewer의 _onWindowResize에서 CameraController._onResize() 호출로 충분
  }

  dispose() {
    // RenderPass는 dispose 메서드가 없으므로 특별히 할 것이 없음
    // EffectComposer 자체는 dispose 메서드가 없지만, 내부 WebGLRenderTarget 등은 정리해야 할 수 있음
    // 그러나 Three.js 예제 코드에서는 composer 자체를 dispose하는 경우는 드뭅니다.
    // 내부 패스들이 리소스를 정리하는 것이 더 일반적입니다.
    if (this.composer) {
      // composer의 렌더 타겟 등 내부 리소스 정리 (직접 접근하여 제거)
      if (this.composer.renderTarget1) {
        this.composer.renderTarget1.dispose()
      }
      if (this.composer.renderTarget2) {
        this.composer.renderTarget2.dispose()
      }
      // 모든 패스들에 대해 dispose 호출 (PostProcessingManager에 의해 추가된 패스 포함)
      this.composer.passes.forEach((pass) => {
        if (pass.dispose) {
          pass.dispose()
        }
      })
      // composer 객체 참조를 null로
      this.composer = null
    }
    console.log('PostProcessingRendererStrategy: 리소스 해제.')
  }
}
